def _load_local_env_file() -> None:
    """Best-effort .env loader for local runs.

    - Loads BASE_DIR/.env if present.
    - Keeps already-exported env vars untouched.
    - Supports simple KEY=VALUE lines (optional quotes).
    """
    env_path = BASE_DIR / ".env"
    if not env_path.exists():
        return
    try:
        raw_text = env_path.read_text(encoding="utf-8")
    except Exception:
        return
    # For these keys, .env should win over stale shell exports so local behavior is deterministic.
    force_override_keys = {
        "RIKO_AUTO_YIELD_RPC_URL",
        "RIKO_AUTO_YIELD_PRIVATE_KEY",
    }
    for line in raw_text.splitlines():
        s = str(line or "").strip()
        if not s or s.startswith("#") or "=" not in s:
            continue
        key, value = s.split("=", 1)
        k = str(key or "").strip()
        if not k:
            continue
        v = str(value or "").strip()
        if "#" in v:
            hash_idx = v.find("#")
            if hash_idx > 0 and v[hash_idx - 1].isspace():
                v = v[:hash_idx].rstrip()
        if (v.startswith('"') and v.endswith('"')) or (v.startswith("'") and v.endswith("'")):
            v = v[1:-1]
        if k in force_override_keys:
            os.environ[k] = v
        else:
            os.environ.setdefault(k, v)


_load_local_env_file()


def _resolve_catalog_dir() -> Path:
    # Highest priority: explicit path from env.
    explicit = os.environ.get("CATALOG_STORAGE_DIR", "").strip()
    if explicit:
        return Path(explicit).expanduser()

    # Render disk mount can be exposed under different env names.
    for env_name in ("RENDER_DISK_PATH", "RENDER_DISK_MOUNT_PATH", "RENDER_DISK_MOUNT"):
        mount = os.environ.get(env_name, "").strip()
        if mount:
            return Path(mount) / "uni_fee_cache"

    # Common Render persistent disk mount point.
    default_render_mount = Path("/var/data")
    if default_render_mount.exists():
        return default_render_mount / "uni_fee_cache"

    # Local/dev fallback.
    return DATA_DIR


