def _fetch_pool_token_ids(endpoint: str, pool_id: str) -> tuple[str, str]:
    pool_lc = str(pool_id or "").strip().lower()
    if not endpoint or not pool_lc:
        return "", ""
    q = """
    query PoolTokens($pool: String!) {
      pool(id: $pool) {
        token0 { id }
        token1 { id }
      }
    }
    """
    try:
        data = graphql_query(endpoint, q, {"pool": pool_lc}, retries=1)
        p = ((data.get("data") or {}).get("pool") or {})
        t0 = str(((p.get("token0") or {}).get("id") or "")).strip().lower()
        t1 = str(((p.get("token1") or {}).get("id") or "")).strip().lower()
        return (t0 if _is_eth_address(t0) else ""), (t1 if _is_eth_address(t1) else "")
    except Exception:
        return "", ""


def _normalize_chain_key_slug(chain_key: str) -> str:
    """Canonical UI/config slug (legacy token: arbitrum-one → arbitrum)."""
    k = str(chain_key or "").strip().lower()
    if k.startswith("eip155:"):
        k = k.split(":", 2)[-1].strip().lower()
    if k.isdigit() and int(k) in CHAIN_ID_TO_KEY:
        return str(CHAIN_ID_TO_KEY[int(k)]).strip().lower()
    return "arbitrum" if k == "arbitrum-one" else k


def _chain_id_by_chain_key(chain_key: str) -> int:
    key = _normalize_chain_key_slug(chain_key)
    for cid, ck in CHAIN_ID_TO_KEY.items():
        if str(ck).strip().lower() == key:
            return int(cid)
    return 0


def _fetch_position_snapshot_series_exact(
    endpoint: str,
    position_id: str,
    *,
    since_ts: int,
    chain_id: int,
) -> list[tuple[int, float]]:
    pid = str(position_id or "").strip()
    if not pid:
        return []
    cache_key = (str(endpoint or "").strip(), str(pid), int(since_ts), int(chain_id))
    now = time.time()
    with POSITION_SNAPSHOT_SERIES_CACHE_LOCK:
        cached = POSITION_SNAPSHOT_SERIES_CACHE.get(cache_key)
        if cached and (now - float(cached[0])) <= float(FEE_SERIES_CACHE_TTL_SEC):
            return list(cached[1])
    queries = [
        (
            "ID",
            """
            query Snapshots($pid: ID!, $since: Int!) {
              positionSnapshots(
                first: 500,
                orderBy: timestamp,
                orderDirection: asc,
                where: { position: $pid, timestamp_gte: $since }
              ) {
                timestamp
                liquidity
                position { tickLower { tickIdx } tickUpper { tickIdx } }
                pool { sqrtPrice token0Price token0 { id decimals } token1 { id decimals } }
              }
            }
            """,
        ),
        (
            "String",
            """
            query Snapshots($pid: String!, $since: Int!) {
              positionSnapshots(
                first: 500,
                orderBy: timestamp,
                orderDirection: asc,
                where: { position: $pid, timestamp_gte: $since }
              ) {
                timestamp
                liquidity
                position { tickLower { tickIdx } tickUpper { tickIdx } }
                pool { sqrtPrice token0Price token0 { id decimals } token1 { id decimals } }
              }
            }
            """,
        ),
        (
            "ID",
            """
            query Snapshots($pid: ID!, $since: Int!) {
              positionSnapshots(
                first: 500,
                orderBy: timestamp,
                orderDirection: asc,
                where: { position_: { id: $pid }, timestamp_gte: $since }
              ) {
                timestamp
                liquidity
                position { tickLower { tickIdx } tickUpper { tickIdx } }
                pool { sqrtPrice token0Price token0 { id decimals } token1 { id decimals } }
              }
            }
            """,
        ),
    ]
    rows: list[dict[str, Any]] = []
    for _typ, q in queries:
        try:
            data = graphql_query(endpoint, q, {"pid": pid, "since": int(since_ts)}, retries=1)
            rows = ((data.get("data") or {}).get("positionSnapshots") or [])
            if rows:
                break
        except Exception:
            continue
    if not rows:
        with POSITION_SNAPSHOT_SERIES_CACHE_LOCK:
            POSITION_SNAPSHOT_SERIES_CACHE[cache_key] = (now, [])
        return []

    # Keep only the last snapshot per day for this position.
    by_day: dict[int, tuple[int, float]] = {}
    for s in rows:
        try:
            ts = int((s or {}).get("timestamp") or 0)
            if ts <= 0:
                continue
            liq = str((s or {}).get("liquidity") or "").strip()
            pos = (s or {}).get("position") or {}
            pool = (s or {}).get("pool") or {}
            if not liq:
                continue
            p = {
                "liquidity": liq,
                "tickLower": (pos.get("tickLower") or {}),
                "tickUpper": (pos.get("tickUpper") or {}),
            }
            val = _estimate_position_tvl_usd_from_detail_external(p, pool, int(chain_id))
            if val is None or val <= 0:
                continue
            day_ts = (ts // 86400) * 86400
            prev = by_day.get(day_ts)
            if prev is None or ts > prev[0]:
                by_day[day_ts] = (ts, float(val))
        except Exception:
            continue
    out = [(day_ts, val) for day_ts, (_real_ts, val) in by_day.items()]
    out.sort(key=lambda x: x[0])
    with POSITION_SNAPSHOT_SERIES_CACHE_LOCK:
        POSITION_SNAPSHOT_SERIES_CACHE[cache_key] = (now, list(out))
    return out


def _fetch_position_snapshot_amounts_series_exact(
    endpoint: str,
    position_id: str,
    *,
    since_ts: int,
    chain_id: int,
) -> list[tuple[int, float, float, float]]:
    """
    One point per day (latest snapshot in that day):
    (day_ts, amount0, amount1, position_tvl_usd)
    """
    pid = str(position_id or "").strip()
    if not pid:
        return []
    queries = [
        (
            "ID",
            """
            query Snapshots($pid: ID!, $since: Int!) {
              positionSnapshots(
                first: 500,
                orderBy: timestamp,
                orderDirection: asc,
                where: { position: $pid, timestamp_gte: $since }
              ) {
                timestamp
                liquidity
                position { tickLower { tickIdx } tickUpper { tickIdx } }
                pool { sqrtPrice token0Price token0 { id decimals symbol } token1 { id decimals symbol } }
              }
            }
            """,
        ),
        (
            "String",
            """
            query Snapshots($pid: String!, $since: Int!) {
              positionSnapshots(
                first: 500,
                orderBy: timestamp,
                orderDirection: asc,
                where: { position: $pid, timestamp_gte: $since }
              ) {
                timestamp
                liquidity
                position { tickLower { tickIdx } tickUpper { tickIdx } }
                pool { sqrtPrice token0Price token0 { id decimals symbol } token1 { id decimals symbol } }
              }
            }
            """,
        ),
        (
            "ID",
            """
            query Snapshots($pid: ID!, $since: Int!) {
              positionSnapshots(
                first: 500,
                orderBy: timestamp,
                orderDirection: asc,
                where: { position_: { id: $pid }, timestamp_gte: $since }
              ) {
                timestamp
                liquidity
                position { tickLower { tickIdx } tickUpper { tickIdx } }
                pool { sqrtPrice token0Price token0 { id decimals symbol } token1 { id decimals symbol } }
              }
            }
            """,
        ),
    ]
    rows: list[dict[str, Any]] = []
    for _typ, q in queries:
        try:
            data = graphql_query(endpoint, q, {"pid": pid, "since": int(since_ts)}, retries=1)
            rows = ((data.get("data") or {}).get("positionSnapshots") or [])
            if rows:
                break
        except Exception:
            continue
    if not rows:
        return []
    by_day: dict[int, tuple[int, float, float, float]] = {}
    for s in rows:
        try:
            ts = int((s or {}).get("timestamp") or 0)
            if ts <= 0:
                continue
            liq = str((s or {}).get("liquidity") or "").strip()
            pos = (s or {}).get("position") or {}
            pool = (s or {}).get("pool") or {}
            if not liq:
                continue
            p = {
                "liquidity": liq,
                "tickLower": (pos.get("tickLower") or {}),
                "tickUpper": (pos.get("tickUpper") or {}),
            }
            amts = _position_amounts_from_detail(p, pool)
            if not amts:
                continue
            a0 = max(0.0, float(amts[0]))
            a1 = max(0.0, float(amts[1]))
            tvl = _estimate_position_tvl_usd_from_detail_external(p, pool, int(chain_id))
            if tvl is None or float(tvl) <= 0.0:
                continue
            day_ts = (ts // 86400) * 86400
            prev = by_day.get(day_ts)
            if prev is None or ts > prev[0]:
                by_day[day_ts] = (ts, float(a0), float(a1), float(tvl))
        except Exception:
            continue
    out = [(dts, v[1], v[2], v[3]) for dts, v in by_day.items()]
    out.sort(key=lambda x: x[0])
    return out


