def _fetch_v3_collect_series_by_shape(
    endpoint: str,
    *,
    pool_id: str,
    owner: str,
    tick_lower: int,
    tick_upper: int,
    since_ts: int,
    chain_id: int,
) -> list[tuple[int, float]]:
    """
    Best-effort fallback for V3 when positionSnapshots fee fields are empty:
    query Collect events by (pool, owner, tick range) and build cumulative USD series by day.
    """
    pid = str(pool_id or "").strip().lower()
    own = str(owner or "").strip().lower()
    tl = int(tick_lower)
    tu = int(tick_upper)
    if not endpoint or not pid or not _is_eth_address(own) or tl >= tu:
        return []
    queries = [
        (
            "ID/Bytes/BigInt",
            """
            query CollectByShape($pool: ID!, $owner: Bytes!, $tl: BigInt!, $tu: BigInt!, $since: Int!) {
              collects(
                first: 1000,
                orderBy: timestamp,
                orderDirection: asc,
                where: { pool: $pool, owner: $owner, tickLower: $tl, tickUpper: $tu, timestamp_gte: $since }
              ) {
                timestamp
                amountUSD
                amount0
                amount1
                pool { sqrtPrice token0Price token0 { id decimals } token1 { id decimals } }
              }
            }
            """,
        ),
        (
            "pool_/owner String",
            """
            query CollectByShape($pool: String!, $owner: String!, $tl: BigInt!, $tu: BigInt!, $since: Int!) {
              collects(
                first: 1000,
                orderBy: timestamp,
                orderDirection: asc,
                where: { pool_: { id: $pool }, owner: $owner, tickLower: $tl, tickUpper: $tu, timestamp_gte: $since }
              ) {
                timestamp
                amountUSD
                amount0
                amount1
                pool { sqrtPrice token0Price token0 { id decimals } token1 { id decimals } }
              }
            }
            """,
        ),
    ]
    rows: list[dict[str, Any]] = []
    for _kind, q in queries:
        try:
            vars_map = {"pool": pid, "owner": own, "tl": int(tl), "tu": int(tu), "since": int(since_ts)}
            data = graphql_query(endpoint, q, vars_map, retries=1)
            rows = ((data.get("data") or {}).get("collects") or [])
            if rows:
                break
        except Exception:
            continue
    if not rows:
        return []
    by_day: dict[int, tuple[int, float]] = {}
    cum = 0.0
    for r in rows:
        try:
            ts = int((r or {}).get("timestamp") or 0)
            if ts <= 0:
                continue
            inc = max(0.0, _safe_float((r or {}).get("amountUSD")))
            if inc <= 0:
                pool = (r or {}).get("pool") or {}
                a0 = _safe_float((r or {}).get("amount0"))
                a1 = _safe_float((r or {}).get("amount1"))
                val = _value_usd_from_token_amounts(a0, a1, pool, int(chain_id))
                inc = max(0.0, _safe_float(val))
            if inc <= 0:
                continue
            cum += float(inc)
            day_ts = (ts // 86400) * 86400
            prev = by_day.get(day_ts)
            if prev is None or ts > prev[0]:
                by_day[day_ts] = (ts, float(cum))
        except Exception:
            continue
    out = [(int(ts), float(v)) for ts, (_rt, v) in by_day.items()]
    out.sort(key=lambda x: x[0])
    return out


def _v3_pool_flow_topic0_map() -> dict[str, str]:
    out: dict[str, str] = {}
    sigs = {
        "mint": b"Mint(address,address,int24,int24,uint128,uint256,uint256)",
        "burn": b"Burn(address,int24,int24,uint128,uint256,uint256)",
        "collect": b"Collect(address,address,int24,int24,uint128,uint128)",
        "swap": b"Swap(address,address,int256,int256,uint160,uint128,int24)",
    }
    for name, sig in sigs.items():
        h = _keccak256_hex(sig)
        if h:
            out[name] = h
    return out


def _pool_token_addrs_onchain(chain_id: int, pool_id: str) -> tuple[str, str]:
    p = str(pool_id or "").strip().lower()
    if not _is_eth_address(p):
        return "", ""
    try:
        batch = _eth_call_hex_batch(
            int(chain_id),
            [
                {"to": p, "data": "0x0dfe1681"},  # token0()
                {"to": p, "data": "0xd21220a7"},  # token1()
            ],
        )
        t0 = _decode_address_from_word((_hex_words(str(batch[0] or "")) or [""])[0]).lower() if batch and len(batch) > 0 and batch[0] else ""
        t1 = _decode_address_from_word((_hex_words(str(batch[1] or "")) or [""])[0]).lower() if batch and len(batch) > 1 and batch[1] else ""
        return (t0 if _is_eth_address(t0) else ""), (t1 if _is_eth_address(t1) else "")
    except Exception:
        return "", ""


def _decode_v3_pool_flow_log(log_row: dict[str, Any], topic0_by_name: dict[str, str]) -> dict[str, Any] | None:
    if not isinstance(log_row, dict):
        return None
    topics = [str(x or "").strip().lower() for x in (log_row.get("topics") or [])]
    if not topics:
        return None
    topic0 = topics[0]
    inv = {str(v): str(k) for k, v in (topic0_by_name or {}).items()}
    event_name = str(inv.get(topic0) or "").strip().lower()
    if not event_name:
        return None
    words = _hex_words(str(log_row.get("data") or ""))
    owner = ""
    recipient = ""
    tick_lower = 0
    tick_upper = 0
    amount0_raw = 0
    amount1_raw = 0
    liquidity_raw = 0
    try:
        if event_name == "mint":
            # Mint(address sender, address indexed owner, int24 indexed tickLower, int24 indexed tickUpper, uint128 amount, uint256 amount0, uint256 amount1)
            if len(topics) < 4 or len(words) < 4:
                return None
            owner = _decode_address_from_word(topics[1][-64:])
            tick_lower = int(_decode_int_from_word(topics[2][-64:]))
            tick_upper = int(_decode_int_from_word(topics[3][-64:]))
            liquidity_raw = int(_decode_uint_from_word(words[1]))
            amount0_raw = int(_decode_uint_from_word(words[2]))
            amount1_raw = int(_decode_uint_from_word(words[3]))
        elif event_name == "burn":
            # Burn(address indexed owner, int24 indexed tickLower, int24 indexed tickUpper, uint128 amount, uint256 amount0, uint256 amount1)
            if len(topics) < 4 or len(words) < 3:
                return None
            owner = _decode_address_from_word(topics[1][-64:])
            tick_lower = int(_decode_int_from_word(topics[2][-64:]))
            tick_upper = int(_decode_int_from_word(topics[3][-64:]))
            liquidity_raw = int(_decode_uint_from_word(words[0]))
            amount0_raw = int(_decode_uint_from_word(words[1]))
            amount1_raw = int(_decode_uint_from_word(words[2]))
        elif event_name == "collect":
            # Collect(address indexed owner, address recipient, int24 indexed tickLower, int24 indexed tickUpper, uint128 amount0, uint128 amount1)
            if len(topics) < 4 or len(words) < 3:
                return None
            owner = _decode_address_from_word(topics[1][-64:])
            tick_lower = int(_decode_int_from_word(topics[2][-64:]))
            tick_upper = int(_decode_int_from_word(topics[3][-64:]))
            recipient = _decode_address_from_word(words[0])
            amount0_raw = int(_decode_uint_from_word(words[1]))
            amount1_raw = int(_decode_uint_from_word(words[2]))
        elif event_name == "swap":
            # Swap(address indexed sender, address indexed recipient, int256 amount0, int256 amount1, uint160 sqrtPriceX96, uint128 liquidity, int24 tick)
            if len(topics) < 3 or len(words) < 5:
                return None
            owner = _decode_address_from_word(topics[1][-64:])
            recipient = _decode_address_from_word(topics[2][-64:])
            amount0_raw = int(_decode_int_from_word(words[0]))
            amount1_raw = int(_decode_int_from_word(words[1]))
            liquidity_raw = int(_decode_uint_from_word(words[3]))
        else:
            return None
    except Exception:
        return None
    return {
        "event_name": event_name,
        "owner": str(owner or "").strip().lower(),
        "recipient": str(recipient or "").strip().lower(),
        "tick_lower": int(tick_lower),
        "tick_upper": int(tick_upper),
        "amount0_raw": int(amount0_raw),
        "amount1_raw": int(amount1_raw),
        "liquidity_raw": int(liquidity_raw),
    }


def _explorer_logs_templates_for_chain(chain_id: int) -> list[str]:
    cid = int(chain_id)
    out: list[str] = []
    eth_key = os.environ.get("ETHERSCAN_API_KEY", "").strip()
    bsc_key = os.environ.get("BSCSCAN_API_KEY", "").strip() or eth_key
    base_key = os.environ.get("BASESCAN_API_KEY", "").strip() or eth_key
    arb_key = os.environ.get("ARBISCAN_API_KEY", "").strip() or eth_key
    polygon_key = os.environ.get("POLYGONSCAN_API_KEY", "").strip() or eth_key
    optimistic_key = (
        os.environ.get("OPTIMISTIC_ETHERSCAN_API_KEY", "").strip()
        or os.environ.get("OPTIMISM_ETHERSCAN_API_KEY", "").strip()
        or eth_key
    )
    uni_key = os.environ.get("UNISCAN_API_KEY", "").strip() or eth_key
    chainid_for_v2 = _explorer_v2_chainid(cid)
    if eth_key and chainid_for_v2:
        out.append(f"https://api.etherscan.io/v2/api?chainid={chainid_for_v2}&module=logs&action=getLogs&apikey={eth_key}")
    if cid == 1 and eth_key:
        out.append(f"https://api.etherscan.io/api?module=logs&action=getLogs&apikey={eth_key}")
    if cid == 56 and bsc_key:
        out.append(f"https://api.bscscan.com/api?module=logs&action=getLogs&apikey={bsc_key}")
    if cid == 8453 and base_key:
        out.append(f"https://api.basescan.org/api?module=logs&action=getLogs&apikey={base_key}")
    if cid == 42161 and arb_key:
        out.append(f"https://api.arbiscan.io/api?module=logs&action=getLogs&apikey={arb_key}")
    if cid == 137 and polygon_key:
        out.append(f"https://api.polygonscan.com/api?module=logs&action=getLogs&apikey={polygon_key}")
    if cid == 10 and optimistic_key:
        out.append(f"https://api-optimistic.etherscan.io/api?module=logs&action=getLogs&apikey={optimistic_key}")
    if cid in {130, 1301} and uni_key:
        uniscan_api = str(os.environ.get("UNISCAN_API_URL", "https://api.uniscan.xyz/api")).strip()
        out.append(f"{uniscan_api}?module=logs&action=getLogs&apikey={uni_key}")
    dedup: list[str] = []
    seen: set[str] = set()
    for u in out:
        k = str(u or "").strip()
        if not k or k in seen:
            continue
        seen.add(k)
        dedup.append(k)
    return dedup


def _explorer_get_logs_for_pool_events(
    chain_id: int,
    pool_id: str,
    *,
    from_block: int,
    to_block: int,
    topic0s: list[str],
    max_pages: int = 50,
    offset: int = 1000,
) -> tuple[list[dict[str, Any]], dict[str, Any]]:
    cid = int(chain_id)
    pool = str(pool_id or "").strip().lower()
    if cid <= 0 or not _is_eth_address(pool):
        return [], {"source": "explorer_api_logs", "reason": "invalid_chain_or_pool"}
    templates = _explorer_logs_templates_for_chain(cid)
    if not templates:
        return [], {"source": "explorer_api_logs", "reason": "no_explorer_templates"}
    if not topic0s:
        return [], {"source": "explorer_api_logs", "reason": "no_topics"}
    lim_pages = max(1, min(200, int(max_pages or 50)))
    lim_off = max(10, min(1000, int(offset or 1000)))
    all_logs: list[dict[str, Any]] = []
    pages_used = 0
    req_used = 0
    template_used = ""
    topic_used = ""
    status_seen = ""
    message_seen = ""
    for tmpl in templates:
        local_any: list[dict[str, Any]] = []
        topic_hits: list[str] = []
        for t0 in topic0s:
            req_page = 1
            local_logs: list[dict[str, Any]] = []
            while req_page <= lim_pages:
                url = (
                    f"{tmpl}&fromBlock={hex(int(from_block))}&toBlock={hex(int(to_block))}&address={pool}"
                    f"&topic0={str(t0)}&page={int(req_page)}&offset={int(lim_off)}"
                )
                req_used += 1
                payload: dict[str, Any] = {}
                try:
                    req = UrlRequest(url, headers={"User-Agent": APP_USER_AGENT})
                    _wait_etherscan_rps_slot(url)
                    with urlopen(req, timeout=float(POSITIONS_EXPLORER_HTTP_TIMEOUT_SEC)) as resp:
                        payload = json.loads(resp.read().decode("utf-8"))
                except Exception:
                    payload = {}
                status_seen = str((payload or {}).get("status") or status_seen)
                message_seen = str((payload or {}).get("message") or message_seen)
                result_rows = _etherscan_api_coerce_result_rows((payload or {}).get("result"))
                if not result_rows:
                    break
                for r in result_rows:
                    if not isinstance(r, dict):
                        continue
                    txh = str((r.get("transactionHash") or r.get("hash") or "")).strip().lower()
                    topics = r.get("topics")
                    if not isinstance(topics, list):
                        topics = []
                        for k in ("topic0", "topic1", "topic2", "topic3"):
                            tv = str(r.get(k) or "").strip().lower()
                            if tv:
                                topics.append(tv)
                    local_logs.append(
                        {
                            "transactionHash": txh,
                            "blockNumber": r.get("blockNumber"),
                            "logIndex": r.get("logIndex"),
                            "data": r.get("data"),
                            "topics": topics,
                        }
                    )
                pages_used += 1
                if len(result_rows) < int(lim_off):
                    break
                req_page += 1
                time.sleep(0.10)
            if local_logs:
                local_any.extend(local_logs)
                topic_hits.append(str(t0))
        if local_any:
            all_logs.extend(local_any)
            template_used = str(tmpl).split("&apikey=", 1)[0]
            topic_used = ",".join(topic_hits[:8])
            break
    if not all_logs:
        return [], {
            "source": "explorer_api_logs",
            "reason": "no_records",
            "requests": int(req_used),
            "pages": int(pages_used),
            "status": str(status_seen),
            "message": str(message_seen),
        }
    dedup: list[dict[str, Any]] = []
    seen: set[str] = set()
    for lg in all_logs:
        txh = str((lg or {}).get("transactionHash") or "").strip().lower()
        lix = _eth_uint_from_rpc_field((lg or {}).get("logIndex"))
        t0 = str(((lg or {}).get("topics") or [""])[0] or "").strip().lower()
        if not txh:
            continue
        k = "|".join([txh, str(int(lix)), t0])
        if k in seen:
            continue
        seen.add(k)
        dedup.append(lg)
    return dedup, {
        "source": "explorer_api_logs",
        "requests": int(req_used),
        "pages": int(pages_used),
        "template": template_used,
        "topic0": topic_used,
        "status": str(status_seen),
        "message": str(message_seen),
    }


