def _collect_v3_pool_flow_events_temp(
    chain_id: int,
    protocol: str,
    pool_id: str,
    *,
    since_ts: int,
    max_chunks: int = 220,
) -> dict[str, Any]:
    cid = int(chain_id)
    proto = str(protocol or "").strip().lower()
    pool = str(pool_id or "").strip().lower()
    if cid <= 0 or not _is_eth_address(pool):
        return {"ok": False, "reason": "invalid_chain_or_pool"}
    from_block = _eth_first_block_at_or_after_ts(cid, int(since_ts))
    latest = _eth_block_number(cid)
    if (from_block <= 0 or from_block > latest) and latest > 0 and int(since_ts) > 0:
        approx_blocks_per_day = 7200 if cid == 1 else 345_600
        lookback_days = max(1, int((time.time() - int(since_ts)) // 86400) + 1)
        from_block = max(1, int(latest) - int(approx_blocks_per_day * lookback_days))
    if from_block <= 0 or latest <= 0 or from_block > latest:
        return {"ok": False, "reason": "invalid_block_window"}
    topic0_by_name = _v3_pool_flow_topic0_map()
    topic0_or = list(topic0_by_name.values())
    if not topic0_or:
        return {"ok": False, "reason": "no_topics"}
    chunk = _fee_collect_log_chunk_blocks(cid)
    chunks_cap = max(1, min(2000, int(max_chunks or _fee_collect_log_max_chunks())))
    run_id = str(uuid.uuid4())
    ts_now = float(time.time())
    with _analytics_conn() as conn:
        prev = conn.execute(
            """
            SELECT run_id, ts, from_block, to_block
            FROM temp_pool_flow_runs
            WHERE chain_id = ? AND pool_id = ? AND status = 'ok'
            ORDER BY ts DESC
            LIMIT 1
            """,
            (int(cid), str(pool)),
        ).fetchone()
        if prev:
            prev_run_id = str(prev[0] or "")
            prev_ts = float(prev[1] or 0.0)
            prev_from = int(prev[2] or 0)
            prev_to = int(prev[3] or 0)
            # Reuse very recent scan that already covers current window and almost-current tip.
            if prev_ts > 0 and (ts_now - prev_ts) <= 45.0 and prev_from <= int(from_block) and (int(latest) - int(prev_to)) <= int(chunk):
                rows = conn.execute(
                    """
                    SELECT event_name, COUNT(1)
                    FROM temp_pool_flow_events
                    WHERE chain_id = ? AND pool_id = ? AND ts >= ?
                    GROUP BY event_name
                    """,
                    (int(cid), str(pool), int(since_ts)),
                ).fetchall()
                by_type_cached = {str(k or ""): int(v or 0) for k, v in rows}
                events_total_cached = int(sum(by_type_cached.values()))
                return {
                    "ok": True,
                    "run_id": prev_run_id,
                    "chain_id": int(cid),
                    "pool_id": str(pool),
                    "from_block": int(prev_from),
                    "to_block": int(prev_to),
                    "chunks_used": 0,
                    "chunks_cap": int(chunks_cap),
                    "events_total": int(events_total_cached),
                    "inserted_rows": 0,
                    "event_counts": by_type_cached,
                    "truncated": False,
                    "cached": True,
                    "source": "cached",
                }
    range_blocks = max(0, int(latest) - int(from_block) + 1)
    required_chunks = int((range_blocks + int(chunk) - 1) // int(chunk)) if range_blocks > 0 else 0
    truncated_window = bool(required_chunks > int(chunks_cap))
    scan_from_block = int(from_block)
    if truncated_window:
        # For very large windows (L2), prioritize recent blocks first.
        scan_from_block = max(int(from_block), int(latest) - int(chunk) * int(chunks_cap) + 1)
    inserted = 0
    events_total = 0
    by_type: dict[str, int] = {}
    source = "rpc_logs"
    explorer_requests = 0
    explorer_pages = 0
    explorer_template = ""
    explorer_reason = ""
    explorer_status = ""
    explorer_message = ""
    block_ts_cache: dict[int, int] = {}
    def _merge_counts(dst: dict[str, int], src: dict[str, int]) -> None:
        for k, v in (src or {}).items():
            dst[str(k)] = int(dst.get(str(k), 0) + int(v or 0))

    def _rows_from_logs(raw_logs: list[dict[str, Any]]) -> tuple[list[tuple[Any, ...]], dict[str, int], int]:
        rows_to_insert: list[tuple[Any, ...]] = []
        counts: dict[str, int] = {}
        events_n = 0
        for lg in raw_logs or []:
            decoded = _decode_v3_pool_flow_log(lg, topic0_by_name)
            if not decoded:
                continue
            blk = _eth_uint_from_rpc_field((lg or {}).get("blockNumber"))
            lix = _eth_uint_from_rpc_field((lg or {}).get("logIndex"))
            txh = str((lg or {}).get("transactionHash") or "").strip().lower()
            if blk <= 0 or lix < 0 or not txh:
                continue
            ts = block_ts_cache.get(int(blk))
            if ts is None:
                ts = int(_eth_get_block_timestamp(cid, int(blk)) or 0)
                block_ts_cache[int(blk)] = int(ts)
            if ts <= 0 or int(ts) < int(since_ts):
                continue
            ev = str(decoded.get("event_name") or "").strip().lower()
            counts[ev] = int(counts.get(ev, 0) + 1)
            events_n += 1
            rows_to_insert.append(
                (
                    int(cid),
                    str(proto),
                    str(pool),
                    int(blk),
                    int(lix),
                    str(txh),
                    int(ts),
                    str(ev),
                    str(decoded.get("owner") or ""),
                    str(decoded.get("recipient") or ""),
                    int(decoded.get("tick_lower") or 0),
                    int(decoded.get("tick_upper") or 0),
                    str(int(decoded.get("amount0_raw") or 0)),
                    str(int(decoded.get("amount1_raw") or 0)),
                    str(int(decoded.get("liquidity_raw") or 0)),
                    float(ts_now),
                )
            )
        return rows_to_insert, counts, int(events_n)

    cur = int(scan_from_block)
    used = 0
    scanned_from = int(scan_from_block)
    scanned_to = int(scan_from_block) - 1
    with POOL_FLOW_EVENTS_LOCK:
        with _analytics_conn() as conn:
            while cur <= int(latest) and used < chunks_cap:
                to_b = min(int(cur) + int(chunk) - 1, int(latest))
                params = {
                    "fromBlock": hex(int(cur)),
                    "toBlock": hex(int(to_b)),
                    "address": str(pool),
                    "topics": [topic0_or],
                }
                try:
                    logs = _eth_get_logs(cid, params, timeout_sec=max(20.0, float(POSITIONS_ONCHAIN_TIMEOUT_SEC) * 4.0))
                except Exception:
                    logs = []
                rows_to_insert, inc_counts, inc_events = _rows_from_logs(logs)
                _merge_counts(by_type, inc_counts)
                events_total += int(inc_events)
                if rows_to_insert:
                    before_changes = int(conn.total_changes)
                    conn.executemany(
                        """
                        INSERT OR IGNORE INTO temp_pool_flow_events(
                          chain_id, protocol, pool_id, block_number, log_index, tx_hash, ts, event_name,
                          owner, recipient, tick_lower, tick_upper, amount0_raw, amount1_raw, liquidity_raw, inserted_at
                        ) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)
                        """,
                        rows_to_insert,
                    )
                    inserted += max(0, int(conn.total_changes) - int(before_changes))
                cur = int(to_b) + 1
                used += 1
                scanned_to = max(int(scanned_to), int(to_b))
            # If recent-window scan found nothing and we had to truncate, probe early window too.
            if truncated_window and events_total <= 0:
                head_cap = max(8, min(40, int(chunks_cap) // 5))
                hcur = int(from_block)
                hused = 0
                while hcur <= int(latest) and hused < head_cap:
                    hto = min(int(hcur) + int(chunk) - 1, int(latest))
                    params = {
                        "fromBlock": hex(int(hcur)),
                        "toBlock": hex(int(hto)),
                        "address": str(pool),
                        "topics": [topic0_or],
                    }
                    try:
                        logs = _eth_get_logs(cid, params, timeout_sec=max(20.0, float(POSITIONS_ONCHAIN_TIMEOUT_SEC) * 4.0))
                    except Exception:
                        logs = []
                    rows_to_insert, inc_counts, inc_events = _rows_from_logs(logs)
                    _merge_counts(by_type, inc_counts)
                    events_total += int(inc_events)
                    if rows_to_insert:
                        before_changes = int(conn.total_changes)
                        conn.executemany(
                            """
                            INSERT OR IGNORE INTO temp_pool_flow_events(
                              chain_id, protocol, pool_id, block_number, log_index, tx_hash, ts, event_name,
                              owner, recipient, tick_lower, tick_upper, amount0_raw, amount1_raw, liquidity_raw, inserted_at
                            ) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)
                            """,
                            rows_to_insert,
                        )
                        inserted += max(0, int(conn.total_changes) - int(before_changes))
                    scanned_from = min(int(scanned_from), int(hcur))
                    scanned_to = max(int(scanned_to), int(hto))
                    hcur = int(hto) + 1
                    hused += 1
                used += int(hused)
            # Explorer API fallback: when RPC window is truncated/limited and still empty.
            if events_total <= 0:
                exp_logs, exp_meta = _explorer_get_logs_for_pool_events(
                    int(cid),
                    str(pool),
                    from_block=int(scanned_from),
                    to_block=int(latest),
                    topic0s=topic0_or,
                    max_pages=60,
                    offset=1000,
                )
                explorer_requests = int((exp_meta or {}).get("requests") or 0)
                explorer_pages = int((exp_meta or {}).get("pages") or 0)
                explorer_template = str((exp_meta or {}).get("template") or "")
                explorer_reason = str((exp_meta or {}).get("reason") or "")
                explorer_status = str((exp_meta or {}).get("status") or "")
                explorer_message = str((exp_meta or {}).get("message") or "")
                if exp_logs:
                    source = "explorer_api_logs"
                    rows_to_insert, inc_counts, inc_events = _rows_from_logs(exp_logs)
                    _merge_counts(by_type, inc_counts)
                    events_total += int(inc_events)
                    if rows_to_insert:
                        before_changes = int(conn.total_changes)
                        conn.executemany(
                            """
                            INSERT OR IGNORE INTO temp_pool_flow_events(
                              chain_id, protocol, pool_id, block_number, log_index, tx_hash, ts, event_name,
                              owner, recipient, tick_lower, tick_upper, amount0_raw, amount1_raw, liquidity_raw, inserted_at
                            ) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)
                            """,
                            rows_to_insert,
                        )
                        inserted += max(0, int(conn.total_changes) - int(before_changes))
            conn.execute(
                """
                INSERT OR REPLACE INTO temp_pool_flow_runs(
                  run_id, ts, chain_id, protocol, pool_id, from_block, to_block, since_ts, latest_ts, events_total, status, note
                ) VALUES(?,?,?,?,?,?,?,?,?,?,?,?)
                """,
                (
                    str(run_id),
                    float(ts_now),
                    int(cid),
                    str(proto),
                    str(pool),
                    int(scanned_from),
                    int(max(int(scanned_to), int(scanned_from))),
                    int(since_ts),
                    int(time.time()),
                    int(events_total),
                    "ok",
                    ("chunk_cap_reached_recent_first" if truncated_window else ("" if cur > latest else "chunk_cap_reached"))
                    + (f"|explorer:{explorer_pages}p" if explorer_pages > 0 else ""),
                ),
            )
            conn.commit()
    return {
        "ok": True,
        "run_id": str(run_id),
        "chain_id": int(cid),
        "pool_id": str(pool),
        "from_block": int(scanned_from),
        "to_block": int(max(int(scanned_to), int(scanned_from))),
        "chunks_used": int(used),
        "chunks_cap": int(chunks_cap),
        "events_total": int(events_total),
        "inserted_rows": int(inserted),
        "event_counts": by_type,
        "truncated": bool(truncated_window or cur <= latest),
        "source": str(source),
        "explorer_requests": int(explorer_requests),
        "explorer_pages": int(explorer_pages),
        "explorer_template": str(explorer_template).split("&apikey=", 1)[0],
        "explorer_reason": str(explorer_reason),
        "explorer_status": str(explorer_status),
        "explorer_message": str(explorer_message),
    }


def _position_fee_rpc_fallback_enabled() -> bool:
    return os.environ.get("POSITIONS_FEE_RPC_FALLBACK", "1").strip().lower() in (
        "1",
        "true",
        "yes",
        "on",
    )


def _position_fee_rpc_force_onchain() -> bool:
    return os.environ.get("POSITIONS_FEE_RPC_FORCE", "0").strip().lower() in (
        "1",
        "true",
        "yes",
        "on",
    )


def _position_fee_rpc_alt_retry_enabled() -> bool:
    return os.environ.get("POSITIONS_FEE_RPC_ALT_RETRY", "0").strip().lower() in (
        "1",
        "true",
        "yes",
        "on",
    )


def _position_pool_flow_debug_enabled() -> bool:
    return os.environ.get("POSITIONS_POOL_FLOW_DEBUG", "0").strip().lower() in (
        "1",
        "true",
        "yes",
        "on",
    )


def _v3_npm_collect_topic0_variants() -> list[str]:
    out: list[str] = []
    for sig in (
        b"Collect(uint256,address,uint128,uint128)",
        b"Collect(uint256,address,uint256,uint256)",
    ):
        h = _keccak256_hex(sig)
        if h and h not in out:
            out.append(h)
    return out


def _fee_collect_log_chunk_blocks(chain_id: int) -> int:
    cid = int(chain_id)
    if cid == 1:
        return max(2000, min(50_000, int(os.environ.get("POSITIONS_FEE_LOG_CHUNK_ETH", "8000"))))
    # Many public L2 RPCs (including 1RPC) reject eth_getLogs ranges >10k blocks.
    return max(2000, min(20_000, int(os.environ.get("POSITIONS_FEE_LOG_CHUNK_L2", "10000"))))


def _fee_collect_log_max_chunks() -> int:
    return max(10, min(500, int(os.environ.get("POSITIONS_FEE_LOG_MAX_CHUNKS", "220"))))


def _collect_log_protocol_candidates(protocol: str) -> list[str]:
    p = str(protocol or "").strip().lower()
    if p not in {"uniswap_v3", "pancake_v3", "pancake_v3_staked"}:
        return [p] if p else []
    out = [p]
    for c in ("uniswap_v3", "pancake_v3", "pancake_v3_staked"):
        if c not in out:
            out.append(c)
    return out


def _eth_uint_from_rpc_field(val: Any) -> int:
    if isinstance(val, int):
        return int(val)
    s = str(val or "").strip().lower()
    if not s:
        return 0
    if s.startswith("0x"):
        return int(s, 16)
    try:
        return int(s)
    except ValueError:
        return 0


def _decode_v3_npm_collect_log_amounts_raw(data_hex: str) -> tuple[int, int]:
    words = _hex_words(str(data_hex or ""))
    if len(words) < 2:
        return 0, 0
    # INonfungiblePositionManager.Collect:
    #   event Collect(uint256 indexed tokenId, address recipient, uint256 amount0, uint256 amount1)
    # Data has 3 ABI words; first one is recipient (address padded to 32 bytes).
    # Legacy variants may still expose only two amount words in some indexers/traces.
    if len(words) >= 3:
        return _decode_uint_from_word(words[1]), _decode_uint_from_word(words[2])
    return _decode_uint_from_word(words[0]), _decode_uint_from_word(words[1])


def _v3_npm_fee_event_topic0_map() -> dict[str, list[str]]:
    out: dict[str, list[str]] = {"collect": [], "decrease": [], "increase": []}
    sigs: dict[str, tuple[bytes, ...]] = {
        "collect": (
            b"Collect(uint256,address,uint128,uint128)",
            b"Collect(uint256,address,uint256,uint256)",
        ),
        "decrease": (
            b"DecreaseLiquidity(uint256,uint128,uint256,uint256)",
        ),
        "increase": (
            b"IncreaseLiquidity(uint256,uint128,uint256,uint256)",
        ),
    }
    for name, arr in sigs.items():
        for sig in arr:
            h = _keccak256_hex(sig)
            if h and h not in out[name]:
                out[name].append(h)
    return out


def _decode_v3_npm_liq_amounts_raw(data_hex: str) -> tuple[int, int, int]:
    words = _hex_words(str(data_hex or ""))
    if len(words) < 3:
        return 0, 0, 0
    liq = _decode_uint_from_word(words[0])
    a0 = _decode_uint_from_word(words[1])
    a1 = _decode_uint_from_word(words[2])
    return int(liq), int(a0), int(a1)


def _scan_v3_npm_fee_events_to_temp(
    chain_id: int,
    protocol: str,
    token_ids: list[int],
    *,
    since_ts: int,
    max_chunks: int,
    deadline_ts: float | None = None,
) -> dict[str, Any]:
    cid = int(chain_id)
    proto = str(protocol or "").strip().lower()
    pids = [int(x) for x in (token_ids or []) if int(x) > 0]
    if cid <= 0 or not pids:
        return {"ok": False, "reason": "invalid_input"}
    pm = _position_manager_for_protocol(int(cid), str(proto))
    if not _is_eth_address(pm):
        return {"ok": False, "reason": "position_manager_missing"}
    from_block = _eth_first_block_at_or_after_ts(cid, int(since_ts))
    latest = _eth_block_number(cid)
    if (from_block <= 0 or from_block > latest) and latest > 0 and int(since_ts) > 0:
        approx_blocks_per_day = 7200 if cid == 1 else 345_600
        lookback_days = max(1, int((time.time() - int(since_ts)) // 86400) + 1)
        from_block = max(1, int(latest) - int(approx_blocks_per_day * lookback_days))
    if from_block <= 0 or latest <= 0 or from_block > latest:
        return {"ok": False, "reason": "invalid_block_window"}
    topic_map = _v3_npm_fee_event_topic0_map()
    topic_to_name: dict[str, str] = {}
    for n, hs in topic_map.items():
        for h in hs:
            topic_to_name[str(h)] = str(n)
    all_topic0 = list(topic_to_name.keys())
    if not all_topic0:
        return {"ok": False, "reason": "topic0_missing"}
    chunk = _fee_collect_log_chunk_blocks(cid)
    chunks_cap = max(1, min(2000, int(max_chunks or _fee_collect_log_max_chunks())))
    range_blocks = max(0, int(latest) - int(from_block) + 1)
    required_chunks = int((range_blocks + int(chunk) - 1) // int(chunk)) if range_blocks > 0 else 0
    truncated = bool(required_chunks > int(chunks_cap))
    used = 0
    inserted = 0
    events_total = 0
    by_type: dict[str, int] = {}
    block_ts_cache: dict[int, int] = {}
    ts_now = float(time.time())
    deadline_hit = False
    progress_done = 0
    progress_pending = 0
    explorer_requests = 0
    explorer_pages = 0
    explorer_status = ""
    explorer_message = ""

    def _progress_get(conn: sqlite3.Connection, tid: int) -> tuple[int, int]:
        row = conn.execute(
            """
            SELECT next_to_block, done
            FROM temp_npm_fee_scan_progress
            WHERE chain_id = ? AND protocol = ? AND token_id = ? AND since_ts = ?
            """,
            (int(cid), str(proto), int(tid), int(since_ts)),
        ).fetchone()
        if not row:
            return int(latest), 0
        try:
            nb = int(row[0] or 0)
            dn = int(row[1] or 0)
        except Exception:
            return int(latest), 0
        if nb <= 0:
            nb = int(latest)
        return int(nb), int(1 if dn else 0)

    def _progress_set(conn: sqlite3.Connection, tid: int, next_to: int, done_flag: bool) -> None:
        conn.execute(
            """
            INSERT OR REPLACE INTO temp_npm_fee_scan_progress(
              chain_id, protocol, token_id, since_ts, next_to_block, done, updated_at
            ) VALUES(?,?,?,?,?,?,?)
            """,
            (
                int(cid),
                str(proto),
                int(tid),
                int(since_ts),
                int(max(0, next_to)),
                int(1 if done_flag else 0),
                float(time.time()),
            ),
        )

    with _analytics_conn() as conn:
        for tid in pids:
            if deadline_ts is not None and time.monotonic() >= float(deadline_ts):
                deadline_hit = True
                break
            next_to_block, done_flag = _progress_get(conn, int(tid))
            if done_flag:
                progress_done += 1
                continue
            cur_to = int(min(max(1, next_to_block), latest))
            while cur_to >= int(from_block) and used < chunks_cap:
                if deadline_ts is not None and time.monotonic() >= float(deadline_ts):
                    deadline_hit = True
                    break
                from_b = max(int(from_block), int(cur_to) - int(chunk) + 1)
                params = {
                    "fromBlock": hex(int(from_b)),
                    "toBlock": hex(int(cur_to)),
                    "address": str(pm),
                    "topics": [all_topic0 if len(all_topic0) > 1 else all_topic0[0], "0x" + _encode_uint_word(int(tid))],
                }
                try:
                    logs = _eth_get_logs(cid, params, timeout_sec=max(20.0, float(POSITIONS_ONCHAIN_TIMEOUT_SEC) * 5.0))
                except Exception:
                    logs = []
                batch_rows: list[tuple[Any, ...]] = []
                for lg in logs or []:
                    if not isinstance(lg, dict):
                        continue
                    topics = [str(x or "").strip().lower() for x in (lg.get("topics") or [])]
                    if not topics:
                        continue
                    ev = str(topic_to_name.get(str(topics[0])) or "").strip().lower()
                    if ev not in {"collect", "decrease", "increase"}:
                        continue
                    blk = _eth_uint_from_rpc_field(lg.get("blockNumber"))
                    lix = _eth_uint_from_rpc_field(lg.get("logIndex"))
                    txh = str(lg.get("transactionHash") or "").strip().lower()
                    if blk <= 0 or lix < 0 or not txh:
                        continue
                    ts = block_ts_cache.get(int(blk))
                    if ts is None:
                        ts = int(_eth_get_block_timestamp(cid, int(blk)) or 0)
                        block_ts_cache[int(blk)] = ts
                    if ts <= 0 or int(ts) < int(since_ts):
                        continue
                    liq_raw = 0
                    a0_raw = 0
                    a1_raw = 0
                    dhex = str(lg.get("data") or "")
                    if ev == "collect":
                        a0_raw, a1_raw = _decode_v3_npm_collect_log_amounts_raw(dhex)
                    else:
                        liq_raw, a0_raw, a1_raw = _decode_v3_npm_liq_amounts_raw(dhex)
                    by_type[ev] = int(by_type.get(ev, 0) + 1)
                    events_total += 1
                    batch_rows.append(
                        (
                            int(cid),
                            str(proto),
                            int(tid),
                            int(blk),
                            int(lix),
                            str(txh),
                            int(ts),
                            str(ev),
                            str(int(a0_raw)),
                            str(int(a1_raw)),
                            str(int(liq_raw)),
                            float(ts_now),
                        )
                    )
                if batch_rows:
                    before = int(conn.total_changes)
                    conn.executemany(
                        """
                        INSERT OR IGNORE INTO temp_npm_fee_events(
                          chain_id, protocol, token_id, block_number, log_index, tx_hash, ts, event_name,
                          amount0_raw, amount1_raw, liquidity_raw, inserted_at
                        ) VALUES(?,?,?,?,?,?,?,?,?,?,?,?)
                        """,
                        batch_rows,
                    )
                    inserted += max(0, int(conn.total_changes) - int(before))
                used += 1
                cur_to = int(from_b) - 1
                done_now = bool(cur_to < int(from_block))
                _progress_set(conn, int(tid), int(cur_to), done_now)
                if done_now:
                    progress_done += 1
                    break
            # RPC chunk budget may leave old range uncovered; for small token set,
            # backfill complete history via explorer getLogs by tokenId.
            if cur_to >= int(from_block) and (not deadline_hit):
                exp_logs, exp_meta = _explorer_get_logs_for_npm_token_events(
                    int(cid),
                    str(pm),
                    int(tid),
                    from_block=int(from_block),
                    to_block=int(latest),
                    topic0s=list(all_topic0),
                    max_pages=160,
                    offset=1000,
                )
                explorer_requests += int((exp_meta or {}).get("requests") or 0)
                explorer_pages += int((exp_meta or {}).get("pages") or 0)
                if str((exp_meta or {}).get("status") or "").strip():
                    explorer_status = str((exp_meta or {}).get("status") or "")
                if str((exp_meta or {}).get("message") or "").strip():
                    explorer_message = str((exp_meta or {}).get("message") or "")
                if exp_logs:
                    batch_rows: list[tuple[Any, ...]] = []
                    for lg in exp_logs:
                        if not isinstance(lg, dict):
                            continue
                        topics = [str(x or "").strip().lower() for x in (lg.get("topics") or [])]
                        if not topics:
                            continue
                        ev = str(topic_to_name.get(str(topics[0])) or "").strip().lower()
                        if ev not in {"collect", "decrease", "increase"}:
                            continue
                        blk = _eth_uint_from_rpc_field(lg.get("blockNumber"))
                        lix = _eth_uint_from_rpc_field(lg.get("logIndex"))
                        txh = str(lg.get("transactionHash") or "").strip().lower()
                        if blk <= 0 or lix < 0 or not txh:
                            continue
                        ts = block_ts_cache.get(int(blk))
                        if ts is None:
                            ts = int(_eth_get_block_timestamp(cid, int(blk)) or 0)
                            block_ts_cache[int(blk)] = ts
                        if ts <= 0 or int(ts) < int(since_ts):
                            continue
                        liq_raw = 0
                        a0_raw = 0
                        a1_raw = 0
                        dhex = str(lg.get("data") or "")
                        if ev == "collect":
                            a0_raw, a1_raw = _decode_v3_npm_collect_log_amounts_raw(dhex)
                        else:
                            liq_raw, a0_raw, a1_raw = _decode_v3_npm_liq_amounts_raw(dhex)
                        by_type[ev] = int(by_type.get(ev, 0) + 1)
                        events_total += 1
                        batch_rows.append(
                            (
                                int(cid),
                                str(proto),
                                int(tid),
                                int(blk),
                                int(lix),
                                str(txh),
                                int(ts),
                                str(ev),
                                str(int(a0_raw)),
                                str(int(a1_raw)),
                                str(int(liq_raw)),
                                float(ts_now),
                            )
                        )
                    if batch_rows:
                        before = int(conn.total_changes)
                        conn.executemany(
                            """
                            INSERT OR IGNORE INTO temp_npm_fee_events(
                              chain_id, protocol, token_id, block_number, log_index, tx_hash, ts, event_name,
                              amount0_raw, amount1_raw, liquidity_raw, inserted_at
                            ) VALUES(?,?,?,?,?,?,?,?,?,?,?,?)
                            """,
                            batch_rows,
                        )
                        inserted += max(0, int(conn.total_changes) - int(before))
                    _progress_set(conn, int(tid), int(from_block) - 1, True)
                    progress_done += 1
                    cur_to = int(from_block) - 1
            if cur_to >= int(from_block):
                progress_pending += 1
        conn.commit()
    return {
        "ok": True,
        "source": "npm_events",
        "chunks_used": int(used),
        "chunks_cap": int(chunks_cap),
        "truncated": bool(truncated or progress_pending > 0 or deadline_hit),
        "deadline_hit": bool(deadline_hit),
        "events_total": int(events_total),
        "inserted_rows": int(inserted),
        "event_counts": by_type,
        "progress_done_tokens": int(progress_done),
        "progress_pending_tokens": int(progress_pending),
        "explorer_requests": int(explorer_requests),
        "explorer_pages": int(explorer_pages),
        "explorer_status": str(explorer_status),
        "explorer_message": str(explorer_message),
    }


def _build_v3_npm_fee_ledger_from_temp(
    chain_id: int,
    protocol: str,
    token_id: int,
    *,
    since_ts: int,
    token0_addr: str,
    token1_addr: str,
    use_historical_usd: bool = False,
) -> tuple[dict[int, float], dict[str, str]]:
    cid = int(chain_id)
    proto = str(protocol or "").strip().lower()
    tid = int(token_id)
    if cid <= 0 or tid <= 0:
        return {}, {"pricing": "none", "detail": ""}
    with _analytics_conn() as conn:
        rows = conn.execute(
            """
            SELECT ts, event_name, amount0_raw, amount1_raw
            FROM temp_npm_fee_events
            WHERE chain_id = ? AND protocol = ? AND token_id = ?
            ORDER BY ts ASC, block_number ASC, log_index ASC
            """,
            (int(cid), str(proto), int(tid)),
        ).fetchall() or []
    if not rows:
        return {}, {"pricing": "none", "detail": ""}
    t0 = str(token0_addr or "").strip().lower()
    t1 = str(token1_addr or "").strip().lower()
    if not _is_eth_address(t0) or not _is_eth_address(t1):
        snap = _fetch_v3_position_contract_snapshot(int(cid), str(proto), int(tid), "", include_quotes=False) or {}
        s0 = str(snap.get("token0") or "").strip().lower()
        s1 = str(snap.get("token1") or "").strip().lower()
        if not _is_eth_address(t0) and _is_eth_address(s0):
            t0 = s0
        if not _is_eth_address(t1) and _is_eth_address(s1):
            t1 = s1
    if not _is_eth_address(t0) or not _is_eth_address(t1):
        return {}, {"pricing": "none", "detail": "token addresses unresolved"}
    dec0 = _fetch_erc20_decimals_onchain(int(cid), str(t0))
    dec1 = _fetch_erc20_decimals_onchain(int(cid), str(t1))
    d0e = max(0, min(36, int(dec0)))
    d1e = max(0, min(36, int(dec1)))
    principal0 = 0.0
    principal1 = 0.0
    cum_fee0 = 0.0
    cum_fee1 = 0.0
    points: list[tuple[int, float, float]] = []
    for ts, ev, a0s, a1s in rows:
        try:
            a0 = float(Decimal(int(str(a0s or "0"))) / (Decimal(10) ** d0e))
            a1 = float(Decimal(int(str(a1s or "0"))) / (Decimal(10) ** d1e))
        except Exception:
            continue
        if str(ev or "").strip().lower() == "decrease":
            principal0 += max(0.0, float(a0))
            principal1 += max(0.0, float(a1))
            continue
        if str(ev or "").strip().lower() != "collect":
            continue
        c0 = max(0.0, float(a0))
        c1 = max(0.0, float(a1))
        fee0 = max(0.0, c0 - principal0)
        fee1 = max(0.0, c1 - principal1)
        principal0 = max(0.0, principal0 - c0)
        principal1 = max(0.0, principal1 - c1)
        cum_fee0 += float(fee0)
        cum_fee1 += float(fee1)
        if int(ts) >= int(since_ts):
            points.append((int(ts), float(cum_fee0), float(cum_fee1)))
    if not points:
        return {}, {"pricing": "none", "detail": "no_collect_points"}
    series_by_ts: dict[int, float] = {}
    priced_partial = False
    pricing_mode = "historical" if use_historical_usd else "spot"
    missing_hist_leg0 = 0
    missing_hist_leg1 = 0
    if use_historical_usd:
        t_lo = min(t for t, _, _ in points)
        t_hi = max(t for t, _, _ in points)
        stable0 = _fee_position_token_stable_usd_assumption(cid, t0) is not None
        stable1 = _fee_position_token_stable_usd_assumption(cid, t1) is not None
        hist0 = [] if stable0 else _series_daily_avg(_fetch_coingecko_contract_prices_range(cid, t0, t_lo, t_hi))
        hist1 = [] if stable1 else _series_daily_avg(_fetch_coingecko_contract_prices_range(cid, t1, t_lo, t_hi))
        prev_cf0 = 0.0
        prev_cf1 = 0.0
        cum_usd = 0.0
        for ts, cf0, cf1 in points:
            d0 = max(0.0, float(cf0) - float(prev_cf0))
            d1 = max(0.0, float(cf1) - float(prev_cf1))
            prev_cf0 = float(cf0)
            prev_cf1 = float(cf1)
            if d0 <= 0.0 and d1 <= 0.0:
                continue
            p0 = 1.0 if stable0 else (_price_usd_at_or_before_series(hist0, ts) if hist0 else None)
            p1 = 1.0 if stable1 else (_price_usd_at_or_before_series(hist1, ts) if hist1 else None)
            if d0 > 0 and (p0 is None or _safe_float(p0) <= 0):
                missing_hist_leg0 += 1
            if d1 > 0 and (p1 is None or _safe_float(p1) <= 0):
                missing_hist_leg1 += 1
            legs_expected = int(1 if d0 > 0 else 0) + int(1 if d1 > 0 else 0)
            legs_priced = 0
            usd_delta = 0.0
            if d0 > 0 and p0 is not None and float(p0) > 0:
                usd_delta += float(d0) * float(p0)
                legs_priced += 1
            if d1 > 0 and p1 is not None and float(p1) > 0:
                usd_delta += float(d1) * float(p1)
                legs_priced += 1
            if legs_priced <= 0:
                continue
            if legs_priced < legs_expected:
                priced_partial = True
            cum_usd += float(usd_delta)
            series_by_ts[int(ts)] = float(max(0.0, cum_usd))
        pricing = "ledger_historical" if not priced_partial else "ledger_historical_partial"
        if missing_hist_leg0 > 0 or missing_hist_leg1 > 0:
            pricing = "ledger_historical_missing_price_data"
    else:
        stable0 = _fee_position_token_stable_usd_assumption(cid, t0) is not None
        stable1 = _fee_position_token_stable_usd_assumption(cid, t1) is not None
        spot_map = _get_token_prices_usd(cid, [t0, t1])
        p0 = 1.0 if stable0 else _safe_float(spot_map.get(t0))
        p1 = 1.0 if stable1 else _safe_float(spot_map.get(t1))
        for ts, cf0, cf1 in points:
            legs_expected = int(1 if cf0 > 0 else 0) + int(1 if cf1 > 0 else 0)
            legs_priced = 0
            usd = 0.0
            if cf0 > 0 and float(p0) > 0:
                usd += float(cf0) * float(p0)
                legs_priced += 1
            if cf1 > 0 and float(p1) > 0:
                usd += float(cf1) * float(p1)
                legs_priced += 1
            if legs_priced <= 0:
                continue
            if legs_priced < legs_expected:
                priced_partial = True
            series_by_ts[int(ts)] = float(usd)
        pricing = "ledger_spot" if not priced_partial else "ledger_spot_partial"
    out = {int(ts): float(v) for ts, v in sorted(series_by_ts.items(), key=lambda x: x[0])}
    if not out:
        return {}, {"pricing": "none", "detail": "ledger_points_unpriced"}
    # Cache ledger per day into temp table for fast subsequent reads.
    by_day_cache: dict[int, tuple[int, float]] = {}
    for ts, usd in out.items():
        dts = (int(ts) // 86400) * 86400
        prev = by_day_cache.get(dts)
        if prev is None or int(ts) > prev[0]:
            by_day_cache[dts] = (int(ts), float(usd))
    now_ts = float(time.time())
    with _analytics_conn() as conn:
        rows_up = []
        for dts, (_ts, usd) in by_day_cache.items():
            rows_up.append((int(cid), str(proto), int(tid), int(dts), "0", "0", float(usd), str(pricing_mode), float(now_ts)))
        conn.executemany(
            """
            INSERT OR REPLACE INTO temp_npm_fee_ledger_day(
              chain_id, protocol, token_id, day_ts, cum_fee0, cum_fee1, cum_fee_usd, pricing_mode, updated_at
            ) VALUES(?,?,?,?,?,?,?,?,?)
            """,
            rows_up,
        )
        conn.commit()
    detail = "Position-level NPM ledger (event-level Collect minus Decrease principal)."
    if use_historical_usd and (missing_hist_leg0 > 0 or missing_hist_leg1 > 0):
        detail = (
            f"{detail} Historical price missing for collect legs: "
            f"token0_missing_legs={int(missing_hist_leg0)}, token1_missing_legs={int(missing_hist_leg1)}."
        )
    return out, {"pricing": pricing, "detail": detail}


def _load_v3_npm_fee_ledger_day_from_cache(
    chain_id: int,
    protocol: str,
    token_id: int,
    *,
    since_ts: int,
    pricing_mode: str,
    max_age_sec: int = 6 * 3600,
) -> dict[int, float]:
    cid = int(chain_id)
    proto = str(protocol or "").strip().lower()
    tid = int(token_id)
    mode = str(pricing_mode or "").strip().lower() or "spot"
    if cid <= 0 or not proto or tid <= 0:
        return {}
    min_updated_at = float(time.time() - max(60, int(max_age_sec)))
    with _analytics_conn() as conn:
        rows = conn.execute(
            """
            SELECT day_ts, cum_fee_usd
            FROM temp_npm_fee_ledger_day
            WHERE chain_id = ?
              AND protocol = ?
              AND token_id = ?
              AND pricing_mode = ?
              AND day_ts >= ?
              AND updated_at >= ?
            ORDER BY day_ts ASC
            """,
            (int(cid), str(proto), int(tid), str(mode), int((int(since_ts) // 86400) * 86400), float(min_updated_at)),
        ).fetchall() or []
    out: dict[int, float] = {}
    for dts, usd in rows:
        try:
            ts = int(dts)
            v = max(0.0, float(usd or 0.0))
        except Exception:
            continue
        out[ts] = v
    return out


def _count_v3_npm_fee_events_temp(
    chain_id: int,
    protocol: str,
    token_id: int,
    *,
    since_ts: int,
) -> int:
    cid = int(chain_id)
    proto = str(protocol or "").strip().lower()
    tid = int(token_id)
    if cid <= 0 or not proto or tid <= 0:
        return 0
    try:
        with _analytics_conn() as conn:
            row = conn.execute(
                """
                SELECT COUNT(1)
                FROM temp_npm_fee_events
                WHERE chain_id = ? AND protocol = ? AND token_id = ? AND ts >= ?
                """,
                (int(cid), str(proto), int(tid), int(since_ts)),
            ).fetchone()
        return int((row[0] if row else 0) or 0)
    except Exception:
        return 0


def _is_v3_npm_fee_scan_complete(
    chain_id: int,
    protocol: str,
    token_id: int,
    *,
    since_ts: int,
) -> bool:
    cid = int(chain_id)
    proto = str(protocol or "").strip().lower()
    tid = int(token_id)
    if cid <= 0 or not proto or tid <= 0:
        return False
    try:
        with _analytics_conn() as conn:
            row = conn.execute(
                """
                SELECT done
                FROM temp_npm_fee_scan_progress
                WHERE chain_id = ? AND protocol = ? AND token_id = ? AND since_ts = ?
                """,
                (int(cid), str(proto), int(tid), int(since_ts)),
            ).fetchone()
        return bool(row and int(row[0] or 0) == 1)
    except Exception:
        return False


def _fetch_v3_position_fees_by_collect_logs(
    chain_id: int,
    protocol: str,
    position_ids: list[str],
    *,
    since_ts: int,
    token0_addr: str,
    token1_addr: str,
    use_historical_usd: bool = False,
) -> tuple[dict[int, float], dict[str, str]]:
    """
    Cumulative collected fees (USD) from NPM Collect events via eth_getLogs.

    * ``use_historical_usd=False`` — mark cumulative token fees at **current** spot (CoinGecko / ratio).
    * ``use_historical_usd=True`` — add each Collect increment at **CoinGecko historical** (contract
      ``market_chart/range``) price at event time; stables assumed $1; gaps fall back to spot for that leg.
    """
    empty_meta: dict[str, str] = {"pricing": "none", "detail": ""}
    if os.environ.get("POSITIONS_DISABLE_V3_ONCHAIN_FALLBACK", "0").strip().lower() in (
        "1",
        "true",
        "yes",
        "on",
    ):
        return {}, empty_meta
    cid = int(chain_id)
    t0 = str(token0_addr or "").strip().lower()
    t1 = str(token1_addr or "").strip().lower()
    if not _is_eth_address(t0) or not _is_eth_address(t1):
        return {}, empty_meta
    pm = _position_manager_for_protocol(cid, protocol)
    if not _is_eth_address(pm):
        return {}, empty_meta
    topic0s = _v3_npm_collect_topic0_variants()
    if not topic0s:
        return {}, empty_meta

    dec0 = _fetch_erc20_decimals_onchain(cid, t0)
    dec1 = _fetch_erc20_decimals_onchain(cid, t1)
    from_block = _eth_first_block_at_or_after_ts(cid, int(since_ts))
    latest = _eth_block_number(cid)
    # Fallback when timestamp->block lookup is inconclusive: bounded recent window.
    if (from_block <= 0 or from_block > latest) and latest > 0 and int(since_ts) > 0:
        approx_blocks_per_day = 7200 if cid == 1 else 345_600
        lookback_days = max(1, int((time.time() - int(since_ts)) // 86400) + 1)
        from_block = max(1, int(latest) - int(approx_blocks_per_day * lookback_days))
    if from_block <= 0 or latest <= 0 or from_block > latest:
        return {}, empty_meta

    chunk = _fee_collect_log_chunk_blocks(cid)
    max_chunks = _fee_collect_log_max_chunks()
    topics_or = topic0s if len(topic0s) > 1 else topic0s[0]
    range_blocks = max(0, int(latest) - int(from_block) + 1)
    required_chunks = int((range_blocks + int(chunk) - 1) // int(chunk)) if range_blocks > 0 else 0
    truncated_window = bool(required_chunks > max_chunks)
    tail_from_block = int(from_block)
    if truncated_window:
        # On fast L2s the full window can be millions of blocks; prioritize recent history first.
        tail_from_block = max(int(from_block), int(latest) - int(chunk) * int(max_chunks) + 1)

    raw_events: list[tuple[int, int, int, int]] = []
    def _scan_collect_logs_window(start_block: int, end_block: int, chunk_cap: int) -> None:
        nonlocal raw_events
        s = max(1, int(start_block))
        e = max(s, int(end_block))
        cap = max(1, int(chunk_cap))
        for pid in position_ids:
            tid = _position_token_id_from_raw(pid)
            if tid <= 0:
                continue
            topic1 = "0x" + _encode_uint_word(int(tid))
            cur = int(s)
            chunks_used = 0
            while cur <= int(e) and chunks_used < cap:
                to_b = min(cur + int(chunk) - 1, int(e))
                params: dict[str, Any] = {
                    "fromBlock": hex(int(cur)),
                    "toBlock": hex(int(to_b)),
                    "address": pm,
                    "topics": [topics_or, topic1],
                }
                try:
                    logs = _eth_get_logs(cid, params, timeout_sec=max(20.0, float(POSITIONS_ONCHAIN_TIMEOUT_SEC) * 5.0))
                except Exception:
                    logs = []
                for lg in logs or []:
                    if not isinstance(lg, dict):
                        continue
                    data_hex = str(lg.get("data") or "")
                    r0, r1 = _decode_v3_npm_collect_log_amounts_raw(data_hex)
                    blk = _eth_uint_from_rpc_field(lg.get("blockNumber"))
                    lix = _eth_uint_from_rpc_field(lg.get("logIndex"))
                    raw_events.append((int(blk), int(lix), int(r0), int(r1)))
                cur = int(to_b) + 1
                chunks_used += 1

    # Pass 1: recent window (full window when small enough).
    _scan_collect_logs_window(int(tail_from_block), int(latest), int(max_chunks))
    # Pass 2: tiny early-window probe when range was truncated and recent window was empty.
    if truncated_window and not raw_events:
        head_chunks = max(8, min(40, int(max_chunks) // 5))
        head_to = min(int(latest), int(from_block) + int(chunk) * int(head_chunks) - 1)
        _scan_collect_logs_window(int(from_block), int(head_to), int(head_chunks))

    if not raw_events:
        return {}, empty_meta

    raw_events.sort(key=lambda x: (x[0], x[1]))
    block_ts_cache: dict[int, int] = {}
    d0e = max(0, min(36, int(dec0)))
    d1e = max(0, min(36, int(dec1)))

    evs: list[tuple[int, float, float]] = []
    for blk, _lix, amt0_raw, amt1_raw in raw_events:
        if blk <= 0:
            continue
        ts = block_ts_cache.get(blk)
        if ts is None:
            ts = int(_eth_get_block_timestamp(cid, blk) or 0)
            block_ts_cache[blk] = ts
        if ts <= 0 or ts < int(since_ts):
            continue
        dh0 = float(Decimal(int(amt0_raw)) / (Decimal(10) ** d0e))
        dh1 = float(Decimal(int(amt1_raw)) / (Decimal(10) ** d1e))
        evs.append((int(ts), dh0, dh1))

    if not evs:
        return {}, empty_meta

    by_day: dict[int, tuple[int, float]] = {}
    priced_partial = False

    if use_historical_usd:
        t_lo = min(t for t, _, _ in evs)
        t_hi = max(t for t, _, _ in evs)
        stable0 = _fee_position_token_stable_usd_assumption(cid, t0) is not None
        stable1 = _fee_position_token_stable_usd_assumption(cid, t1) is not None
        hist0 = [] if stable0 else _series_daily_avg(_fetch_coingecko_contract_prices_range(cid, t0, t_lo, t_hi))
        hist1 = [] if stable1 else _series_daily_avg(_fetch_coingecko_contract_prices_range(cid, t1, t_lo, t_hi))
        missing_leg0 = 0
        missing_leg1 = 0
        cum_usd = 0.0
        for ts, dh0, dh1 in evs:
            if stable0:
                p0 = 1.0
            else:
                p0 = _price_usd_at_or_before_series(hist0, ts) if hist0 else None
            if stable1:
                p1 = 1.0
            else:
                p1 = _price_usd_at_or_before_series(hist1, ts) if hist1 else None
            if float(dh0) > 0 and (p0 is None or p0 <= 0):
                missing_leg0 += 1
            if float(dh1) > 0 and (p1 is None or p1 <= 0):
                missing_leg1 += 1
            legs_expected = int(1 if float(dh0) > 0 else 0) + int(1 if float(dh1) > 0 else 0)
            legs_priced = 0
            inc_usd = 0.0
            if float(dh0) > 0 and p0 is not None and float(p0) > 0:
                inc_usd += float(dh0) * float(p0)
                legs_priced += 1
            if float(dh1) > 0 and p1 is not None and float(p1) > 0:
                inc_usd += float(dh1) * float(p1)
                legs_priced += 1
            if legs_priced <= 0 or inc_usd <= 0:
                continue
            if legs_priced < legs_expected:
                priced_partial = True
            cum_usd += float(inc_usd)
            day_ts = (int(ts) // 86400) * 86400
            prev = by_day.get(day_ts)
            if prev is None or ts > prev[0]:
                by_day[day_ts] = (int(ts), float(cum_usd))
        pricing = "onchain_historical"
        if missing_leg0 > 0 or missing_leg1 > 0 or priced_partial:
            pricing = "onchain_historical_missing_price_data"
        detail = (
            "Collect logs: USD per event via CoinGecko contract historical daily prices; "
            "stables=$1."
        )
        if truncated_window:
            detail += " Log scan window was truncated due to RPC range budget; recent blocks prioritized."
        if missing_leg0 > 0 or missing_leg1 > 0:
            detail += f" Missing historical price legs: token0={int(missing_leg0)}, token1={int(missing_leg1)}."
        if priced_partial:
            detail += " Some events were valued by one known token leg only."
        return {int(d): float(v) for d, (_ts, v) in by_day.items()}, {"pricing": pricing, "detail": detail}

    stable0 = _fee_position_token_stable_usd_assumption(cid, t0) is not None
    stable1 = _fee_position_token_stable_usd_assumption(cid, t1) is not None
    spot_map = _get_token_prices_usd(cid, [t0, t1])
    sp0 = 1.0 if stable0 else _safe_float(spot_map.get(t0))
    sp1 = 1.0 if stable1 else _safe_float(spot_map.get(t1))
    cum_usd = 0.0
    for ts, dh0, dh1 in evs:
        legs_expected = int(1 if float(dh0) > 0 else 0) + int(1 if float(dh1) > 0 else 0)
        legs_priced = 0
        inc_usd = 0.0
        if float(dh0) > 0 and float(sp0) > 0:
            inc_usd += float(dh0) * float(sp0)
            legs_priced += 1
        if float(dh1) > 0 and float(sp1) > 0:
            inc_usd += float(dh1) * float(sp1)
            legs_priced += 1
        if legs_priced <= 0 or inc_usd <= 0:
            continue
        if legs_priced < legs_expected:
            priced_partial = True
        cum_usd += float(inc_usd)
        day_ts = (int(ts) // 86400) * 86400
        prev = by_day.get(day_ts)
        if prev is None or ts > prev[0]:
            by_day[day_ts] = (int(ts), float(cum_usd))

    out = {int(d): float(v) for d, (_ts, v) in by_day.items()}
    pricing = "onchain_spot" if not priced_partial else "onchain_spot_partial"
    detail = "Collect logs: cumulative fees marked at current spot USD (CoinGecko / ratio)."
    if truncated_window:
        detail += " Log scan window was truncated due to RPC range budget; recent blocks prioritized."
    if priced_partial:
        detail += " Some events were valued by one known token leg only."
    meta = {
        "pricing": pricing,
        "detail": detail,
    }
    return out, meta


def _aave_markets_for_chains(chain_ids: list[int]) -> list[dict[str, Any]]:
    if not chain_ids:
        return []
    query = """
    query AaveMarkets($ids: [ChainId!]!) {
      markets(request: { chainIds: $ids }) {
        address
        chain { chainId name }
        name
      }
    }
    """
    data = graphql_query(AAVE_V3_GRAPHQL_ENDPOINT, query, {"ids": [int(x) for x in chain_ids]}, retries=1)
    markets = data.get("data", {}).get("markets", []) or []
    out: list[dict[str, Any]] = []
    for m in markets:
        addr = str(m.get("address") or "").strip()
        chain_id = int((m.get("chain") or {}).get("chainId") or 0)
        if not _is_eth_address(addr) or chain_id <= 0:
            continue
        out.append({"address": addr, "chainId": chain_id, "name": str(m.get("name") or "")})
    return out


def _scan_aave_positions(addresses: list[str], chain_ids: list[int]) -> tuple[list[dict[str, Any]], list[str]]:
    rows: list[dict[str, Any]] = []
    errors: list[str] = []
    supported_ids = [int(x) for x in chain_ids if int(x) in AAVE_CHAIN_ID_TO_NAME]
    if not supported_ids:
        return rows, errors
    try:
        markets = _aave_markets_for_chains(supported_ids)
    except Exception as e:
        return rows, [f"Lending scan failed (markets): {e}"]
    if not markets:
        return rows, errors
    query = """
    query AaveUserPositions($user: EvmAddress!, $markets: [MarketInput!]!) {
      userSupplies(request: { user: $user, markets: $markets, collateralsOnly: false, orderBy: { balance: DESC } }) {
        market { name chain { chainId name } }
        currency { symbol }
        balance { amount { value } usd }
        apy { value }
        isCollateral
      }
      userBorrows(request: { user: $user, markets: $markets, orderBy: { debt: DESC } }) {
        market { name chain { chainId name } }
        currency { symbol }
        debt { amount { value } usd }
        apy { value }
      }
    }
    """
    for owner in addresses:
        try:
            data = graphql_query(
                AAVE_V3_GRAPHQL_ENDPOINT,
                query,
                {"user": owner, "markets": [{"address": m["address"], "chainId": m["chainId"]} for m in markets]},
                retries=1,
            )
        except Exception as e:
            errors.append(f"Lending scan failed for {owner}: {e}")
            continue
        payload = data.get("data", {}) or {}
        for s in payload.get("userSupplies", []) or []:
            usd = _safe_float((s.get("balance") or {}).get("usd"))
            if usd <= 0:
                continue
            chain_obj = ((s.get("market") or {}).get("chain") or {})
            chain_id = int(chain_obj.get("chainId") or 0)
            chain_str = str(chain_obj.get("name") or AAVE_CHAIN_ID_TO_NAME.get(chain_id, chain_id))
            rows.append(
                {
                    "address": owner,
                    "protocol": "aave_v3",
                    "chain": chain_str,
                    "chain_id": chain_id,
                    "kind": "lending_supply",
                    "market": _market_name_without_chain(str((s.get("market") or {}).get("name") or ""), chain_str),
                    "asset": str((s.get("currency") or {}).get("symbol") or ""),
                    "amount": _safe_float(((s.get("balance") or {}).get("amount") or {}).get("value")),
                    "usd": usd,
                    "apy": _safe_float((s.get("apy") or {}).get("value")),
                    "is_collateral": bool(s.get("isCollateral")),
                }
            )
        for b in payload.get("userBorrows", []) or []:
            usd = _safe_float((b.get("debt") or {}).get("usd"))
            if usd <= 0:
                continue
            chain_obj = ((b.get("market") or {}).get("chain") or {})
            chain_id = int(chain_obj.get("chainId") or 0)
            chain_str = str(chain_obj.get("name") or AAVE_CHAIN_ID_TO_NAME.get(chain_id, chain_id))
            rows.append(
                {
                    "address": owner,
                    "protocol": "aave_v3",
                    "chain": chain_str,
                    "chain_id": chain_id,
                    "kind": "lending_borrow",
                    "market": _market_name_without_chain(str((b.get("market") or {}).get("name") or ""), chain_str),
                    "asset": str((b.get("currency") or {}).get("symbol") or ""),
                    "amount": _safe_float(((b.get("debt") or {}).get("amount") or {}).get("value")),
                    "usd": usd,
                    "apy": _safe_float((b.get("apy") or {}).get("value")),
                    "is_collateral": False,
                }
            )
    return rows, errors


def _scan_aave_merit_rewards(addresses: list[str], chain_ids: list[int]) -> tuple[list[dict[str, Any]], list[str]]:
    rows: list[dict[str, Any]] = []
    errors: list[str] = []
    supported_ids = [int(x) for x in chain_ids if int(x) in AAVE_CHAIN_ID_TO_NAME]
    if not supported_ids:
        return rows, errors
    query = """
    query MeritRewards($user: EvmAddress!, $chainId: ChainId!) {
      userMeritRewards(request: { user: $user, chainId: $chainId }) {
        chain
        claimable {
          currency { symbol }
          amount { amount { value } usd }
        }
      }
    }
    """
    for owner in addresses:
        for chain_id in supported_ids:
            try:
                data = graphql_query(
                    AAVE_V3_GRAPHQL_ENDPOINT,
                    query,
                    {"user": owner, "chainId": int(chain_id)},
                    retries=1,
                )
            except Exception:
                continue
            payload = ((data.get("data") or {}).get("userMeritRewards") or {})
            claimable = payload.get("claimable") or []
            for item in claimable:
                amount_obj = item.get("amount") or {}
                usd = _safe_float(amount_obj.get("usd"))
                amount = _safe_float((amount_obj.get("amount") or {}).get("value"))
                if usd <= 0 and amount <= 0:
                    continue
                rows.append(
                    {
                        "address": owner,
                        "protocol": "aave_v3",
                        "chain": AAVE_CHAIN_ID_TO_NAME.get(int(chain_id), str(chain_id)),
                        "chain_id": int(chain_id),
                        "asset": str((item.get("currency") or {}).get("symbol") or ""),
                        "amount": amount,
                        "usd": usd,
                    }
                )
    return rows, errors


def _stable_catalog_for_lending_scan() -> tuple[dict[str, list[str]], dict[str, str], set[str]]:
    catalog = _load_pair_lists_catalog(refresh=False)
    fiat_backed = [str(x or "").strip().lower() for x in (catalog.get("stablecoins_full") or catalog.get("stablecoins") or []) if str(x or "").strip()]
    non_usd = [str(x or "").strip().lower() for x in (catalog.get("fiat_nonusd_stables") or []) if str(x or "").strip()]
    algo_crypto = [
        str(x or "").strip().lower()
        for x in (catalog.get("stable_algo_crypto_full") or catalog.get("stable_algo_crypto") or [])
        if str(x or "").strip()
    ]
    categories = {
        "fiat_backed": list(dict.fromkeys(fiat_backed)),
        "fiat_nonusd": list(dict.fromkeys(non_usd)),
        "algo_crypto": list(dict.fromkeys(algo_crypto)),
    }
    symbol_to_bucket: dict[str, str] = {}
    for bucket in ("fiat_backed", "fiat_nonusd", "algo_crypto"):
        for sym in categories.get(bucket, []):
            symbol_to_bucket.setdefault(str(sym), bucket)
    symbols = set(symbol_to_bucket.keys())
    return categories, symbol_to_bucket, symbols


def _pct_from_percent_value(raw: Any) -> float:
    v = _safe_float(raw)
    if v <= 0:
        return 0.0
    # Aave PercentValue.value may be normalized (1.0 = 100%).
    return float(v * 100.0) if v <= 1.5 else float(v)


def _percent_value_ui_pct(obj: Any) -> float:
    """Aave GraphQL percent types: ``formatted`` (PercentValue UI), else ``normalized`` (PercentNumber), else ``value``."""
    if isinstance(obj, dict):
        fmt = obj.get("formatted")
        if fmt is not None and str(fmt).strip() != "":
            try:
                return float(str(fmt).strip())
            except ValueError:
                pass
        if obj.get("normalized") is not None:
            return float(_pct_from_percent_value(obj.get("normalized")))
        return _pct_from_percent_value(obj.get("value"))
    return _pct_from_percent_value(obj)


def _bonus_program_end_date_parse(raw: Any) -> date | None:
    """Parse bonus end instant to a calendar date (UTC)."""
    if raw is None:
        return None
    s = str(raw).strip()
    if not s:
        return None
    if "T" in s:
        head = s.split("T", 1)[0].strip()
        if len(head) >= 10 and head[4:5] == "-" and head[7:8] == "-":
            try:
                return date(int(head[0:4]), int(head[5:7]), int(head[8:10]))
            except ValueError:
                return None
        return None
    try:
        ts = float(s)
        if ts <= 0:
            return None
        return datetime.fromtimestamp(ts, tz=timezone.utc).date()
    except Exception:
        pass
    if len(s) >= 10 and s[4] == "-" and s[7] == "-":
        try:
            return date(int(s[0:4]), int(s[5:7]), int(s[8:10]))
        except ValueError:
            return None
    return None


def _bonus_program_end_date_str(raw: Any) -> str:
    """Bonus end for UI: ``16 Apr``; append year if not the current year (UTC). Empty if unknown."""
    d = _bonus_program_end_date_parse(raw)
    if d is None:
        return ""
    _mon_en = (
        "",
        "Jan",
        "Feb",
        "Mar",
        "Apr",
        "May",
        "Jun",
        "Jul",
        "Aug",
        "Sep",
        "Oct",
        "Nov",
        "Dec",
    )
    mon = _mon_en[d.month] if 1 <= d.month <= 12 else "?"
    now_y = datetime.now(timezone.utc).date().year
    if d.year == now_y:
        return f"{d.day} {mon}"
    return f"{d.day} {mon} {d.year}"


def _market_name_without_chain(market_name: str, chain_name: str) -> str:
    """Strip the network name from an Aave market title when it duplicates the Chain column."""
    m = str(market_name or "").strip()
    c = str(chain_name or "").strip()
    if not m or not c:
        return m
    out = re.sub(re.escape(c), "", m, flags=re.IGNORECASE)
    out = re.sub(r"\s+", " ", out).strip()
    out = re.sub(r"^[\s\-–—:|/,]+|[\s\-–—:|/,]+$", "", out)
    out = re.sub(r"\s+", " ", out).strip()
    return out if out else m


def _fetch_merkl_aave_bonus_index() -> tuple[dict[tuple[int, str], dict[str, Any]], set[tuple[int, str]], str]:
    """Return Merkl APR index, then a set of (chainId, addr) where Merkl lists an Aave opportunity with no APR.

    Used to suppress Aave v4 ``MerklSupplyReward`` fallback: that GraphQL field can stay non-zero while the
    Merkl REST API already reports ``apr: 0`` (e.g. ended campaigns), which inflated bonuses (e.g. USDG).
    """
    base = str(MERKL_API_ENDPOINT or "https://api.merkl.xyz/v4").rstrip("/")
    headers = {
        "User-Agent": APP_USER_AGENT,
        "Accept": "application/json",
    }
    api_key = str(MERKL_API_KEY or "").strip()
    if api_key:
        headers["X-API-Key"] = api_key
    items: list[dict[str, Any]] = []
    per_page = 100
    max_pages = 24
    for page in range(max_pages):
        url = f"{base}/opportunities?mainProtocolId=aave&items={per_page}&page={page}"
        req = UrlRequest(url, headers=headers)
        payload: Any = {}
        try:
            with urlopen(req, timeout=18) as resp:
                payload = json.loads(resp.read().decode("utf-8"))
        except HTTPError as e:
            code = int(getattr(e, "code", 0) or 0)
            if code in (401, 403):
                return {}, set(), f"Merkl opportunities endpoint is not accessible ({code})."
            raise
        page_items = payload if isinstance(payload, list) else (
            (payload.get("items") if isinstance(payload, dict) else None)
            or (payload.get("data") if isinstance(payload, dict) else None)
            or (payload.get("opportunities") if isinstance(payload, dict) else None)
            or []
        )
        chunk = [x for x in (page_items or []) if isinstance(x, dict)]
        if not chunk:
            break
        items.extend(chunk)
        if len(chunk) < per_page:
            break
    if not items:
        return {}, set(), "Merkl API returned no AAVE opportunities."
    out: dict[tuple[int, str], dict[str, Any]] = {}
    inactive_merkl_keys: set[tuple[int, str]] = set()
    for it in (items or []):
        if not isinstance(it, dict):
            continue
        apr = _safe_float(it.get("apr"))
        chain_id = int(
            _safe_float(
                it.get("chainId")
                or ((it.get("chain") or {}).get("chainId") if isinstance(it.get("chain"), dict) else 0)
                or ((it.get("distributionChain") or {}).get("chainId") if isinstance(it.get("distributionChain"), dict) else 0)
            )
        )
        if chain_id <= 0:
            continue
        explorer_addr = str(
            it.get("explorerAddress")
            or it.get("address")
            or ((it.get("tokens") or {}).get("address") if isinstance(it.get("tokens"), dict) else "")
            or ""
        ).strip().lower()
        reward_sym = str(
            it.get("rewardTokenSymbol")
            or ((it.get("rewardToken") or {}).get("symbol") if isinstance(it.get("rewardToken"), dict) else "")
            or ((it.get("token") or {}).get("symbol") if isinstance(it.get("token"), dict) else "")
            or "MERKL"
        ).strip().upper()
        end_raw = it.get("latestCampaignEnd") or it.get("earliestCampaignEnd")
        end_d = _bonus_program_end_date_str(end_raw)
        program_line = f"Merkl until {end_d}" if end_d else "Merkl until unknown"
        token_addrs: list[str] = []
        for tk in (it.get("tokens") or []):
            if not isinstance(tk, dict):
                continue
            a = str(tk.get("address") or "").strip().lower()
            if _is_eth_address(a):
                token_addrs.append(a)
        addrs = list(dict.fromkeys([explorer_addr, *token_addrs]))
        valid_addrs = [a for a in addrs if _is_eth_address(a)]
        if not valid_addrs:
            continue
        if apr <= 0:
            for addr in valid_addrs:
                inactive_merkl_keys.add((int(chain_id), str(addr)))
            continue
        per_addr_apr = float(apr) / float(len(valid_addrs))
        for addr in valid_addrs:
            key = (int(chain_id), str(addr))
            rec = out.setdefault(key, {"apr": 0.0, "programs": [], "tokens": set()})
            rec["apr"] = float(rec.get("apr") or 0.0) + per_addr_apr
            progs = rec.get("programs") if isinstance(rec.get("programs"), list) else []
            if program_line and program_line not in progs:
                progs.append(program_line)
            rec["programs"] = progs
            if reward_sym:
                toks = rec.get("tokens") if isinstance(rec.get("tokens"), set) else set(rec.get("tokens") or [])
                toks.add(reward_sym)
                rec["tokens"] = toks
    inactive_merkl_keys -= set(out.keys())
    for rec in out.values():
        rec["tokens"] = sorted(list(rec.get("tokens") or []))
    if not out:
        return {}, inactive_merkl_keys, "Merkl opportunities were loaded but none matched AAVE reserve token addresses."
    return out, inactive_merkl_keys, ""


def _merkl_inactive_covers_reserve(
    chain_id: int,
    underlying_addr: str,
    atoken_addr: str,
    vtoken_addr: str,
    inactive: set[tuple[int, str]],
) -> bool:
    """True if Merkl REST lists a zero-APR Aave opportunity touching any of these reserve addresses."""
    if not inactive:
        return False
    cid = int(chain_id)
    for raw in (underlying_addr, atoken_addr, vtoken_addr):
        a = str(raw or "").strip().lower()
        if _is_eth_address(a) and (cid, a) in inactive:
            return True
    return False


def _fetch_aave_v4_bonus_index(stable_symbols: set[str]) -> tuple[dict[tuple[int, str], dict[str, Any]], str]:
    # Public v4 endpoint currently supports Ethereum chainId=1 for reserve rewards.
    query = """
    query AaveV4StableRewards($query: ReservesRequestQuery!, $filter: ReservesRequestFilter) {
      value: reserves(request: { query: $query, filter: $filter }) {
        chain { chainId name }
        asset { underlying { address info { symbol } } }
        summary {
          rewards {
            __typename
            ... on MerklSupplyReward {
              id
              endDate
              extraApy { value normalized }
              payoutToken { info { symbol } }
            }
            ... on MerklBorrowReward {
              id
              endDate
              discountApy { value normalized }
              payoutToken { info { symbol } }
            }
            ... on SupplyPointsReward {
              id
              name
              endDate
              program { name }
            }
            ... on BorrowPointsReward {
              id
              name
              endDate
              program { name }
            }
          }
        }
      }
    }
    """
    variables = {
        "query": {"chainTokenCategories": [{"chainId": 1, "categories": ["STABLECOIN"]}]},
        "filter": "ALL",
    }
    data = graphql_query(AAVE_V4_GRAPHQL_ENDPOINT, query, variables, retries=1)
    reserves = ((data.get("data") or {}).get("value") or []) if isinstance(data, dict) else []
    out: dict[tuple[int, str], dict[str, Any]] = {}
    for reserve in reserves:
        if not isinstance(reserve, dict):
            continue
        chain = reserve.get("chain") or {}
        chain_id = int(_safe_float((chain or {}).get("chainId")))
        if chain_id <= 0:
            continue
        underlying = ((reserve.get("asset") or {}).get("underlying") or {})
        addr = str((underlying.get("address") or "")).strip().lower()
        if not _is_eth_address(addr):
            continue
        symbol = str(((underlying.get("info") or {}).get("symbol") or "")).strip().lower()
        if symbol and stable_symbols and symbol not in stable_symbols:
            continue
        rewards = ((reserve.get("summary") or {}).get("rewards") or [])
        supply_apr = 0.0
        borrow_discount = 0.0
        labels: list[str] = []
        tokens: set[str] = set()
        for rw in rewards:
            if not isinstance(rw, dict):
                continue
            t = str(rw.get("__typename") or "").strip()
            if t == "MerklSupplyReward":
                val = _percent_value_ui_pct(rw.get("extraApy"))
                if val > 0:
                    supply_apr += float(val)
                if val > 0:
                    ed = _bonus_program_end_date_str(rw.get("endDate"))
                    tag = f"Merkl until {ed}" if ed else "Merkl until unknown"
                    if tag not in labels:
                        labels.append(tag)
                tk = str((((rw.get("payoutToken") or {}).get("info") or {}).get("symbol") or "")).strip().upper()
                if tk:
                    tokens.add(tk)
            elif t == "MerklBorrowReward":
                val = _percent_value_ui_pct(rw.get("discountApy"))
                if val > 0:
                    borrow_discount += float(val)
                if val > 0:
                    ed = _bonus_program_end_date_str(rw.get("endDate"))
                    tag = f"Merkl borrow until {ed}" if ed else "Merkl borrow until unknown"
                    if tag not in labels:
                        labels.append(tag)
                tk = str((((rw.get("payoutToken") or {}).get("info") or {}).get("symbol") or "")).strip().upper()
                if tk:
                    tokens.add(tk)
            elif t in {"SupplyPointsReward", "BorrowPointsReward"}:
                ed = _bonus_program_end_date_str(rw.get("endDate"))
                tag = f"Points until {ed}" if ed else "Points until unknown"
                if tag not in labels:
                    labels.append(tag)
        if supply_apr <= 0 and borrow_discount <= 0 and not labels and not tokens:
            continue
        out[(int(chain_id), str(addr))] = {
            "supply_apr": float(supply_apr),
            "borrow_discount": float(borrow_discount),
            "labels": labels,
            "tokens": sorted(list(tokens)),
        }
    if not out:
        return {}, "Aave v4 rewards fallback returned no matching stable bonuses."
    return out, ""


_FLUID_FTOKEN_DETAILS_ARRAY_ABI = (
    "(address,bool,bool,string,string,uint256,address,uint256,uint256,uint256,uint256,uint256,uint256,int256,"
    "(bool,uint256,uint256,uint256,uint256,uint256,uint256,uint256,uint256,uint256,uint256,uint256))[]"
)
_FLUID_OVERALL_TOKENS_ARRAY_ABI = (
    "(uint256,uint256,uint256,uint256,uint256,uint256,uint256,uint256,uint256,uint256,uint256,uint256,uint256,uint256,"
    "uint256,uint256,(uint256,(address,uint256,uint256,uint256,uint256),"
    "(address,uint256,uint256,uint256,uint256,uint256,uint256)))[]"
)


def _fluid_underlying_symbol_key(ftoken_symbol: str) -> str:
    s = str(ftoken_symbol or "").strip()
    if len(s) >= 2 and s[0] in "fF" and s[1].isalpha():
        return s[1:].strip().lower()
    return s.lower()


def _fluid_borrow_rate_by_asset(
    chain_id: int, asset_addrs: list[str]
) -> dict[str, float]:
    liq = str(FLUID_LIQUIDITY_RESOLVER_BY_CHAIN_ID.get(int(chain_id)) or "").strip().lower()
    if not _is_eth_address(liq) or not asset_addrs:
        return {}
    try:
        from eth_abi import decode as _abi_decode, encode as _abi_encode
    except Exception:
        return {}
    sel = _evm_selector_4("getOverallTokensData(address[])")
    if len(sel) != 4:
        return {}
    out: dict[str, float] = {}
    chunk = 24
    for i in range(0, len(asset_addrs), chunk):
        batch = [a for a in asset_addrs[i : i + chunk] if _is_eth_address(a)]
        if not batch:
            continue
        try:
            body = _abi_encode(["address[]"], [batch])
        except Exception:
            continue
        data_hex = "0x" + (sel + body).hex()
        try:
            ret_hex = _eth_call_hex(int(chain_id), liq, data_hex)
            raw = bytes.fromhex(ret_hex[2:])
            rows = _abi_decode([_FLUID_OVERALL_TOKENS_ARRAY_ABI], raw)[0]
        except Exception:
            continue
        if not isinstance(rows, (list, tuple)) or len(rows) != len(batch):
            continue
        for addr, row in zip(batch, rows):
            if not isinstance(row, (list, tuple)) or len(row) < 2:
                continue
            br = _safe_float(row[0])
            if br > 0:
                out[str(addr).strip().lower()] = float(br)
    return out


def _scan_fluid_stable_lending_rows(
    stable_symbols: set[str], symbol_to_bucket: dict[str, str]
) -> tuple[list[dict[str, Any]], list[str], set[int], int]:
    rows: list[dict[str, Any]] = []
    warnings: list[str] = []
    seen_chains: set[int] = set()
    ftokens_seen = 0
    try:
        from eth_abi import decode as _abi_decode
    except Exception as e:
        warnings.append(f"Fluid lending scan skipped (eth_abi unavailable): {e}")
        return rows, warnings, seen_chains, 0
    sel = _evm_selector_4("getFTokensEntireData()")
    if len(sel) != 4:
        warnings.append("Fluid lending scan skipped (selector error).")
        return rows, warnings, seen_chains, 0
    resolver = str(FLUID_LENDING_RESOLVER).strip().lower()
    if not _is_eth_address(resolver):
        return rows, warnings, seen_chains, 0
    chain_ids = sorted(
        int(cid)
        for cid in FLUID_LIQUIDITY_RESOLVER_BY_CHAIN_ID.keys()
        if int(cid) in AAVE_CHAIN_ID_TO_NAME and _rpc_urls_for_chain(int(cid))
    )
    for chain_id in chain_ids:
        data_hex = "0x" + sel.hex()
        try:
            ret_hex = _eth_call_hex(int(chain_id), resolver, data_hex)
            raw = bytes.fromhex(ret_hex[2:])
            arr = _abi_decode([_FLUID_FTOKEN_DETAILS_ARRAY_ABI], raw)[0]
        except Exception as e:
            warnings.append(f"Fluid lending scan failed (chain_id={chain_id}): {e}")
            continue
        if not isinstance(arr, (list, tuple)) or not arr:
            continue
        seen_chains.add(int(chain_id))
        ftokens_seen += int(len(arr))
        chain_name = str(AAVE_CHAIN_ID_TO_NAME.get(int(chain_id), chain_id))
        candidates: list[tuple[str, dict[str, Any]]] = []
        asset_addrs: list[str] = []
        for tup in arr:
            if not isinstance(tup, (list, tuple)) or len(tup) < 15:
                continue
            ftoken_addr = str(tup[0] or "").strip().lower()
            f_sym = str(tup[4] or "")
            decimals_raw = int(tup[5] or 0)
            asset_addr = str(tup[6] or "").strip().lower()
            total_assets = int(tup[7] or 0)
            rewards_rate = int(tup[11] or 0)
            supply_rate = int(tup[12] or 0)
            u_key = _fluid_underlying_symbol_key(f_sym)
            if not u_key or u_key not in stable_symbols:
                continue
            if not _is_eth_address(asset_addr):
                continue
            dec = int(decimals_raw) if 0 < int(decimals_raw) <= 36 else 18
            scale = float(10**dec) if dec <= 36 else 0.0
            tvl_usd = float(total_assets) / scale if scale > 0 else 0.0
            supply_liq_pct = round(float(supply_rate) / 100.0, 4)
            rewards_pct = round(float(rewards_rate) / 1e12, 4) if rewards_rate > 0 else 0.0
            bonus_labels: list[str] = []
            if rewards_pct > 0:
                bonus_labels.append("Fluid rewards")
            row = {
                "protocol": "fluid",
                "protocol_version": "fluid_lending",
                "chain": chain_name,
                "chain_id": int(chain_id),
                "market": "Fluid lending",
                "asset": u_key.upper(),
                "bucket": str(symbol_to_bucket.get(u_key) or "other"),
                "tvl_usd": float(tvl_usd),
                "supply_apy_pct": float(supply_liq_pct),
                "supply_bonus_apr_pct": float(rewards_pct),
                "conditional_bonus_apr_pct": 0.0,
                "supply_total_apr_pct": float(round(supply_liq_pct + rewards_pct, 4)),
                "borrow_apy_pct": 0.0,
                "borrow_discount_apr_pct": 0.0,
                "borrow_effective_apr_pct": 0.0,
                "merkl_bonus_apr_pct": 0.0,
                "can_be_collateral": False,
                "paused": False,
                "frozen": False,
                "reward_tokens": [],
                "bonus_programs": list(bonus_labels),
                "fluid_ftoken": ftoken_addr,
                "fluid_underlying": asset_addr,
            }
            candidates.append((asset_addr, row))
            asset_addrs.append(asset_addr)
        borrow_map = _fluid_borrow_rate_by_asset(int(chain_id), list(dict.fromkeys(asset_addrs)))
        for asset_addr, row in candidates:
            br = float(borrow_map.get(str(asset_addr).strip().lower()) or 0.0)
            borrow_pct = round(br / 100.0, 4) if br > 0 else 0.0
            row["borrow_apy_pct"] = float(borrow_pct)
            row["borrow_effective_apr_pct"] = float(borrow_pct)
            rows.append(row)
    return rows, warnings, seen_chains, int(ftokens_seen)


def _scan_aave_stable_lending_rows() -> tuple[list[dict[str, Any]], dict[str, Any], list[str]]:
    categories, symbol_to_bucket, stable_symbols = _stable_catalog_for_lending_scan()
    if not stable_symbols:
        return (
            [],
            {"stable_catalog": categories, "chains": [], "chain_filter_options": [], "markets": 0},
            ["Stablecoin catalog is empty."],
        )

    chain_ids = sorted(int(x) for x in AAVE_CHAIN_ID_TO_NAME.keys())
    merkl_idx: dict[tuple[int, str], dict[str, Any]] = {}
    merkl_inactive_keys: set[tuple[int, str]] = set()
    v4_idx: dict[tuple[int, str], dict[str, Any]] = {}
    warnings: list[str] = []
    try:
        merkl_idx, merkl_inactive_keys, merkl_warn = _fetch_merkl_aave_bonus_index()
        if merkl_warn:
            warnings.append(merkl_warn)
    except Exception as e:
        warnings.append(f"Merkl bonus fetch failed: {e}")
        merkl_inactive_keys = set()
    try:
        v4_idx, v4_warn = _fetch_aave_v4_bonus_index(stable_symbols)
        if v4_warn:
            warnings.append(v4_warn)
    except Exception as e:
        warnings.append(f"Aave v4 rewards fallback failed: {e}")
    if not merkl_idx and v4_idx:
        warnings.append(
            "Merkl bonuses missing or unmatched; using Aave v4 GraphQL rewards where applicable (Ethereum stables, partial coverage)."
        )
    elif not merkl_idx and not v4_idx:
        key_set = bool(str(MERKL_API_KEY or "").strip())
        auth_blocked = any("Merkl opportunities endpoint is not accessible" in str(w) for w in warnings)
        fetch_failed = any("Merkl bonus fetch failed" in str(w) for w in warnings)
        if auth_blocked or fetch_failed or not key_set:
            warnings.append(
                "Merkl API unavailable and v4 fallback returned no matching rewards. Set MERKL_API_KEY (or check network) for Merkl bonus coverage."
            )

    query = """
    query AaveStableMarkets($ids: [ChainId!]!) {
      markets(request: { chainIds: $ids }) {
        address
        name
        chain { chainId name }
        reserves {
          underlyingToken { symbol address decimals }
          aToken { address symbol }
          vToken { address symbol }
          size { usd }
          supplyInfo { apy { value formatted } canBeCollateral }
          borrowInfo { apy { value formatted } }
          isFrozen
          isPaused
          incentives {
            __typename
            ... on MeritSupplyIncentive {
              extraSupplyApr { value formatted }
            }
            ... on AaveSupplyIncentive {
              extraSupplyApr { value formatted }
              rewardTokenSymbol
            }
            ... on MeritBorrowIncentive {
              borrowAprDiscount { value formatted }
            }
            ... on AaveBorrowIncentive {
              borrowAprDiscount { value formatted }
              rewardTokenSymbol
            }
            ... on MeritBorrowAndSupplyIncentiveCondition {
              extraApr { value formatted }
              supplyToken { symbol }
              borrowToken { symbol }
            }
          }
        }
      }
    }
    """
    scan_errors: list[str] = []
    try:
        data = graphql_query(AAVE_V3_GRAPHQL_ENDPOINT, query, {"ids": chain_ids}, retries=1)
    except Exception as e:
        data = {"data": {}}
        scan_errors.append(f"AAVE markets scan failed: {e}")

    markets = (data.get("data") or {}).get("markets") or []
    rows: list[dict[str, Any]] = []
    seen_chains: set[int] = set()
    for market in markets:
        chain = (market.get("chain") or {})
        chain_id = int(chain.get("chainId") or 0)
        chain_name = str(chain.get("name") or AAVE_CHAIN_ID_TO_NAME.get(chain_id, chain_id))
        if chain_id > 0:
            seen_chains.add(chain_id)
        market_name = _market_name_without_chain(str(market.get("name") or ""), chain_name)
        for reserve in (market.get("reserves") or []):
            token = (reserve.get("underlyingToken") or {})
            symbol = str(token.get("symbol") or "").strip().lower()
            if not symbol or symbol not in stable_symbols:
                continue
            if bool(reserve.get("isPaused")) or bool(reserve.get("isFrozen")):
                continue
            supply_apy_pct = _percent_value_ui_pct((reserve.get("supplyInfo") or {}).get("apy"))
            borrow_apy_pct = _percent_value_ui_pct((reserve.get("borrowInfo") or {}).get("apy"))
            supply_bonus_pct = 0.0
            borrow_discount_pct = 0.0
            conditional_bonus_pct = 0.0
            reward_tokens: set[str] = set()
            bonus_labels: list[str] = []
            for inc in (reserve.get("incentives") or []):
                t = str(inc.get("__typename") or "")
                if t in {"MeritSupplyIncentive", "AaveSupplyIncentive"}:
                    val = _percent_value_ui_pct(inc.get("extraSupplyApr"))
                    if val > 0:
                        supply_bonus_pct += float(val)
                        tag = "Merit until unknown" if t == "MeritSupplyIncentive" else "Aave until unknown"
                        if tag not in bonus_labels:
                            bonus_labels.append(tag)
                    rt = str(inc.get("rewardTokenSymbol") or "").strip().upper()
                    if rt:
                        reward_tokens.add(rt)
                elif t in {"MeritBorrowIncentive", "AaveBorrowIncentive"}:
                    val = _percent_value_ui_pct(inc.get("borrowAprDiscount"))
                    if val > 0:
                        borrow_discount_pct += float(val)
                        tag = "Merit borrow until unknown" if t == "MeritBorrowIncentive" else "Aave borrow until unknown"
                        if tag not in bonus_labels:
                            bonus_labels.append(tag)
                    rt = str(inc.get("rewardTokenSymbol") or "").strip().upper()
                    if rt:
                        reward_tokens.add(rt)
                elif t == "MeritBorrowAndSupplyIncentiveCondition":
                    val = _percent_value_ui_pct(inc.get("extraApr"))
                    if val > 0:
                        conditional_bonus_pct += float(val)
                        tag = "Conditional until unknown"
                        if tag not in bonus_labels:
                            bonus_labels.append(tag)
            supply_total_pct = float(supply_apy_pct + supply_bonus_pct + conditional_bonus_pct)
            borrow_effective_pct = float(max(0.0, borrow_apy_pct - borrow_discount_pct))
            rows.append(
                {
                    "protocol": "aave",
                    "protocol_version": "aave_v3",
                    "chain": chain_name,
                    "chain_id": int(chain_id),
                    "market": market_name,
                    "asset": symbol.upper(),
                    "bucket": str(symbol_to_bucket.get(symbol) or "other"),
                    "tvl_usd": float(_safe_float((reserve.get("size") or {}).get("usd"))),
                    "supply_apy_pct": float(supply_apy_pct),
                    "supply_bonus_apr_pct": float(supply_bonus_pct),
                    "conditional_bonus_apr_pct": float(conditional_bonus_pct),
                    "supply_total_apr_pct": float(supply_total_pct),
                    "borrow_apy_pct": float(borrow_apy_pct),
                    "borrow_discount_apr_pct": float(borrow_discount_pct),
                    "borrow_effective_apr_pct": float(borrow_effective_pct),
                    "can_be_collateral": bool((reserve.get("supplyInfo") or {}).get("canBeCollateral")),
                    "paused": bool(reserve.get("isPaused")),
                    "frozen": bool(reserve.get("isFrozen")),
                    "reward_tokens": sorted(reward_tokens),
                    "bonus_programs": bonus_labels,
                }
            )
            row = rows[-1]
            underlying_addr = str((token.get("address") or "")).strip().lower()
            atoken_addr = str(((reserve.get("aToken") or {}).get("address") or "")).strip().lower()
            vtoken_addr = str(((reserve.get("vToken") or {}).get("address") or "")).strip().lower()
            merkl_apr = 0.0
            merkl_tokens: list[str] = []
            merkl_program_lines: list[str] = []
            for addr in [underlying_addr, atoken_addr, vtoken_addr]:
                if not _is_eth_address(addr):
                    continue
                rec = merkl_idx.get((int(chain_id), addr))
                if not isinstance(rec, dict):
                    continue
                merkl_apr += float(rec.get("apr") or 0.0)
                for t in (rec.get("tokens") or []):
                    ts = str(t or "").strip().upper()
                    if ts and ts not in merkl_tokens:
                        merkl_tokens.append(ts)
                for pl in rec.get("programs") or []:
                    ps = str(pl or "").strip()
                    if ps and ps not in merkl_program_lines:
                        merkl_program_lines.append(ps)
            if merkl_apr > 0:
                merkl_apr = round(float(merkl_apr), 2)
                row["merkl_bonus_apr_pct"] = merkl_apr
                row["supply_total_apr_pct"] = float(row.get("supply_total_apr_pct") or 0.0) + merkl_apr
                for t in merkl_tokens:
                    if t and t not in reward_tokens:
                        reward_tokens.add(t)
                bonus_labels.extend(merkl_program_lines)
            else:
                row["merkl_bonus_apr_pct"] = 0.0
            v4_rec = v4_idx.get((int(chain_id), underlying_addr)) if _is_eth_address(underlying_addr) else None
            if isinstance(v4_rec, dict):
                v4_supply_apr = float(v4_rec.get("supply_apr") or 0.0)
                v4_borrow_discount = float(v4_rec.get("borrow_discount") or 0.0)
                v4_tokens = [str(x or "").strip().upper() for x in (v4_rec.get("tokens") or [])]
                v4_labels = [str(x or "").strip() for x in (v4_rec.get("labels") or [])]
                v4_stale = _merkl_inactive_covers_reserve(
                    int(chain_id), underlying_addr, atoken_addr, vtoken_addr, merkl_inactive_keys
                )
                if v4_stale:
                    v4_supply_apr = 0.0
                    v4_borrow_discount = 0.0
                    v4_tokens = []
                    v4_labels = [lb for lb in v4_labels if str(lb).startswith("Points")]
                for t in v4_tokens:
                    if t:
                        reward_tokens.add(t)
                for lb in v4_labels:
                    if lb and lb not in bonus_labels:
                        bonus_labels.append(lb)
                # Avoid double counting when Merkl API already supplied direct APR.
                # Skip v4 Merkl* numbers when Merkl REST reports apr<=0 for this market (stale v4 GraphQL).
                if (
                    float(row.get("merkl_bonus_apr_pct") or 0.0) <= 0.0
                    and v4_supply_apr > 0
                    and not v4_stale
                ):
                    row["merkl_bonus_apr_pct"] = float(v4_supply_apr)
                    row["supply_total_apr_pct"] = float(row.get("supply_total_apr_pct") or 0.0) + float(v4_supply_apr)
                if (
                    float(row.get("borrow_discount_apr_pct") or 0.0) <= 0.0
                    and v4_borrow_discount > 0
                    and not v4_stale
                ):
                    row["borrow_discount_apr_pct"] = float(v4_borrow_discount)
                    row["borrow_effective_apr_pct"] = float(
                        max(0.0, float(row.get("borrow_apy_pct") or 0.0) - float(v4_borrow_discount))
                    )
            row["reward_tokens"] = sorted(reward_tokens)
            row["bonus_programs"] = list(dict.fromkeys(bonus_labels))

    fluid_rows, fluid_warn, fluid_seen, fluid_n = _scan_fluid_stable_lending_rows(stable_symbols, symbol_to_bucket)
    if fluid_warn:
        warnings.extend(fluid_warn)
    seen_chains.update(int(x) for x in fluid_seen)
    rows.extend(fluid_rows)

    for row in rows:
        sb = float(row.get("supply_bonus_apr_pct") or 0.0)
        cb = float(row.get("conditional_bonus_apr_pct") or 0.0)
        mb = float(row.get("merkl_bonus_apr_pct") or 0.0)
        types: list[str] = []
        proto = str(row.get("protocol") or "").strip().lower()
        if sb > 0:
            types.append("Fluid rewards" if proto == "fluid" else "Protocol")
        if cb > 0:
            types.append("Conditional")
        if mb > 0:
            types.append("Merkl")
        row["supply_bonuses_apr_pct"] = float(sb + cb + mb)
        row["supply_bonus_types"] = types

    rows.sort(
        key=lambda r: (
            str(r.get("asset") or ""),
            -float(r.get("supply_total_apr_pct") or 0.0),
            str(r.get("chain") or ""),
            str(r.get("market") or ""),
        )
    )
    chain_filter_options = sorted(
        {
            str(AAVE_CHAIN_ID_TO_NAME[int(cid)]).strip()
            for cid in chain_ids
            if int(cid) in AAVE_CHAIN_ID_TO_NAME and str(AAVE_CHAIN_ID_TO_NAME[int(cid)]).strip()
        },
        key=lambda s: str(s).lower(),
    )
    meta = {
        "stable_catalog": categories,
        # Always expose the full Aave scan scope so chain filters (e.g. Base / 8453) do not
        # disappear when a chain has zero matching stable rows in this response.
        "chains": sorted(int(x) for x in chain_ids),
        "chains_with_data": sorted(int(x) for x in seen_chains),
        "chain_filter_options": chain_filter_options,
        "markets": int(len(markets)),
        "warnings": warnings,
        "fluid_ftokens_fetched": int(fluid_n),
    }
    return rows, meta, scan_errors


def _parse_pairs_str(raw: str) -> list[tuple[str, str]]:
    def _norm_sym(s: str) -> str:
        v = str(s or "").strip().lower()
        if not v:
            return ""
        if not re.fullmatch(r"[a-z0-9][a-z0-9._-]{0,31}", v):
            return ""
        return v
    out = []
    seen = set()
    for part in (raw or "").replace(" ", "").lower().split(";"):
        if "," not in part:
            continue
        a, b = part.split(",", 1)
        a, b = _norm_sym(a), _norm_sym(b)
        if not a or not b or a == b:
            continue
        key = (a, b)
        if key not in seen:
            seen.add(key)
            out.append(key)
    return out


def _pairs_to_string(pairs: list[tuple[str, str]]) -> str:
    return ";".join(f"{a},{b}" for a, b in pairs)


def _supported_tokens() -> list[str]:
    tokens = set()
    for per_chain in TOKEN_ADDRESSES.values():
        tokens.update(per_chain.keys())
    return sorted(tokens)


def _supported_chains() -> list[str]:
    chains = set(UNISWAP_V3_SUBGRAPHS.keys()) | set(UNISWAP_V4_SUBGRAPHS.keys()) | set(GOLDSKY_ENDPOINTS.keys())
    return sorted(chains)


def _iso_now() -> str:
    return datetime.now(timezone.utc).isoformat(timespec="seconds").replace("+00:00", "Z")


def _json_safe(obj: Any) -> Any:
    if obj is None or isinstance(obj, (str, int, bool)):
        return obj
    if isinstance(obj, float):
        return float(obj) if math.isfinite(obj) else 0.0
    if isinstance(obj, dict):
        return {str(k): _json_safe(v) for k, v in obj.items()}
    if isinstance(obj, (list, tuple)):
        return [_json_safe(v) for v in obj]
    if isinstance(obj, set):
        return [_json_safe(v) for v in sorted(obj, key=lambda x: str(x))]
    try:
        return float(obj) if isinstance(obj, Decimal) else str(obj)
    except Exception:
        return str(obj)


def _parse_utc_iso(value: str) -> datetime | None:
    raw = str(value or "").strip()
    if not raw:
        return None
    try:
        dt = datetime.fromisoformat(raw.replace("Z", "+00:00"))
    except ValueError:
        return None
    if dt.tzinfo is None:
        dt = dt.replace(tzinfo=timezone.utc)
    return dt.astimezone(timezone.utc)


def _read_json(path: Path) -> dict[str, Any] | None:
    if not path.is_file():
        return None
    try:
        import json

        with open(path, "r", encoding="utf-8") as f:
            return json.load(f)
    except Exception:
        return None


def _write_json(path: Path, data: dict[str, Any]) -> None:
    import json

    path.parent.mkdir(parents=True, exist_ok=True)
    with open(path, "w", encoding="utf-8") as f:
        json.dump(data, f, ensure_ascii=True, indent=2)


def _new_session_id() -> str:
    return secrets.token_urlsafe(24)


def _is_valid_session_id(value: str) -> bool:
    return bool(re.fullmatch(r"[A-Za-z0-9_-]{16,128}", value or ""))


def _ensure_session_cookie(request: Request, response: Response) -> str:
    _prune_runtime_state()
    sid = request.cookies.get(SESSION_COOKIE_NAME, "")
    if _is_valid_session_id(sid):
        with AUTH_LOCK:
            auth = AUTH_SESSIONS.get(sid)
            if isinstance(auth, dict):
                auth["last_seen_ts"] = time.time()
        return sid
    sid = _new_session_id()
    response.set_cookie(
        key=SESSION_COOKIE_NAME,
        value=sid,
        max_age=SESSION_TTL_SEC,
        httponly=True,
        samesite="lax",
        secure=(request.url.scheme == "https"),
        path="/",
    )
    return sid


def _load_chain_catalog(refresh: bool = False) -> dict[str, Any]:
    supported = _supported_chains()
    supported_set = {str(x).strip().lower() for x in supported if str(x).strip()}
    if not refresh:
        cached = _read_json(CHAIN_CATALOG_PATH)
        if cached and isinstance(cached.get("items"), list):
            from_cache = {str(x).strip().lower() for x in cached["items"] if str(x).strip()}
            # Canonical list from config; refresh on-disk catalog when it is missing chains (e.g. Base).
            merged = sorted(supported_set)
            prev = sorted(from_cache & supported_set)
            if merged != prev:
                out = {"updated_at": _iso_now(), "count": len(merged), "items": merged}
                _write_json(CHAIN_CATALOG_PATH, out)
                return out
            cached["items"] = merged
            cached["count"] = len(merged)
            return cached
    items = sorted(supported_set)
    out = {"updated_at": _iso_now(), "count": len(items), "items": items}
    _write_json(CHAIN_CATALOG_PATH, out)
    return out


def _is_clean_symbol(symbol: str) -> bool:
    # keep only plain alnum symbols to avoid spam/malicious names
    return bool(re.fullmatch(r"[A-Za-z0-9]{2,20}", symbol))


def _fetch_uniswap_verified_token_profiles() -> tuple[set[str], dict[str, list[str]], dict[str, set[str]]]:
    import json

    req = UrlRequest(UNISWAP_TOKEN_LIST_URL, headers={"User-Agent": APP_USER_AGENT, "Accept": "application/json"})
    with urlopen(req, timeout=20) as resp:
        payload = json.loads(resp.read().decode("utf-8"))

    supported = set(_supported_chains())
    by_chain_set: dict[str, set[str]] = {}
    all_tokens: set[str] = set()
    profiles: dict[str, set[str]] = {}
    for item in payload.get("tokens", []):
        symbol = str(item.get("symbol") or "").strip()
        if not _is_clean_symbol(symbol):
            continue
        chain_name = CHAIN_ID_TO_NAME.get(int(item.get("chainId") or 0))
        if not chain_name or chain_name not in supported:
            continue
        sym = symbol.lower()
        by_chain_set.setdefault(chain_name, set()).add(sym)
        all_tokens.add(sym)
        nm = str(item.get("name") or "").strip().lower()
        if nm:
            profiles.setdefault(sym, set()).add(nm)
        # include symbol text itself for lightweight keyword matching
        profiles.setdefault(sym, set()).add(sym)

    by_chain = {k: sorted(v) for k, v in by_chain_set.items()}
    return all_tokens, by_chain, profiles


def _fetch_uniswap_verified_tokens() -> tuple[set[str], dict[str, list[str]]]:
    all_tokens, by_chain, _profiles = _fetch_uniswap_verified_token_profiles()
    return all_tokens, by_chain


TOKEN_ICON_URLS_MEMO: dict[str, str] | None = None
TOKEN_ICON_URLS_LOCK = threading.Lock()


def _normalize_logo_uri(uri: str) -> str:
    raw = str(uri or "").strip()
    if not raw:
        return ""
    low = raw.lower()
    if low.startswith("ipfs://"):
        tail = raw[7:].lstrip("/")
        if tail.startswith("ipfs/"):
            tail = tail[5:]
        return f"https://ipfs.io/ipfs/{tail}"
    return raw


def _load_token_icon_url_map(refresh: bool = False) -> dict[str, str]:
    global TOKEN_ICON_URLS_MEMO
    with TOKEN_ICON_URLS_LOCK:
        if (not refresh) and isinstance(TOKEN_ICON_URLS_MEMO, dict) and TOKEN_ICON_URLS_MEMO:
            return TOKEN_ICON_URLS_MEMO
        cached = _read_json(TOKEN_ICON_MAP_PATH)
        if (not refresh) and isinstance(cached, dict) and cached:
            out_cached = {str(k).strip().lower(): str(v).strip() for k, v in cached.items() if _is_clean_symbol(str(k).strip()) and str(v).strip()}
            TOKEN_ICON_URLS_MEMO = out_cached
            return out_cached
        out: dict[str, str] = {}
        try:
            import json

            req = UrlRequest(UNISWAP_TOKEN_LIST_URL, headers={"User-Agent": APP_USER_AGENT, "Accept": "application/json"})
            with urlopen(req, timeout=20) as resp:
                payload = json.loads(resp.read().decode("utf-8"))
            for item in payload.get("tokens", []) or []:
                sym = str(item.get("symbol") or "").strip().lower()
                if (not _is_clean_symbol(sym)) or (sym in out):
                    continue
                logo = _normalize_logo_uri(str(item.get("logoURI") or ""))
                if not logo:
                    continue
                if not (logo.startswith("http://") or logo.startswith("https://")):
                    continue
                out[sym] = logo
        except Exception:
            out = {}
        try:
            _write_json(TOKEN_ICON_MAP_PATH, out)
        except Exception:
            pass
        TOKEN_ICON_URLS_MEMO = out
        return out


def _guess_image_ext_from_url(url: str) -> str:
    try:
        path = str(urlparse(str(url or "")).path or "").lower()
    except Exception:
        path = str(url or "").lower()
    for ext in (".png", ".jpg", ".jpeg", ".webp", ".gif", ".svg"):
        if path.endswith(ext):
            return ".jpg" if ext == ".jpeg" else ext
    return ".png"


def _token_icon_file_path(symbol: str, source_url: str) -> Path:
    sym = str(symbol or "").strip().lower()
    ext = _guess_image_ext_from_url(source_url)
    h = hashlib.sha1(str(source_url or "").encode("utf-8")).hexdigest()[:12]
    return TOKEN_ICON_DIR / f"{sym}_{h}{ext}"


def _ensure_token_icon_cached(symbol: str) -> Path | None:
    sym = str(symbol or "").strip().lower()
    if not _is_clean_symbol(sym):
        return None
    icon_map = _load_token_icon_url_map(refresh=False)
    source_url = str(icon_map.get(sym) or "").strip()
    if not source_url:
        return None
    path = _token_icon_file_path(sym, source_url)
    if path.exists() and path.stat().st_size > 0:
        return path
    try:
        req = UrlRequest(source_url, headers={"User-Agent": APP_USER_AGENT, "Accept": "image/*"})
        with urlopen(req, timeout=18) as resp:
            data = resp.read()
        if not data:
            return None
        tmp = path.with_suffix(path.suffix + ".tmp")
        tmp.write_bytes(data)
        os.replace(tmp, path)
        return path
    except Exception:
        return None


def _fetch_tokens_by_tvl_endpoint(endpoint: str, min_tvl_usd: float) -> set[str]:
    query = """
    query TokenListByTvl($minTvl: BigDecimal!, $skip: Int!) {
      tokens(
        first: 1000,
        skip: $skip,
        orderBy: totalValueLockedUSD,
        orderDirection: desc,
        where: { totalValueLockedUSD_gte: $minTvl }
      ) {
        symbol
      }
    }
    """
    out: set[str] = set()
    skip = 0
    while skip < 10000:
        data = graphql_query(endpoint, query, {"minTvl": str(min_tvl_usd), "skip": skip})
        rows = data.get("data", {}).get("tokens", [])
        if not rows:
            break
        for row in rows:
            sym = str(row.get("symbol") or "").strip()
            if _is_clean_symbol(sym):
                out.add(sym.lower())
        if len(rows) < 1000:
            break
        skip += 1000
    return out


def _fetch_top_token_addrs_by_tvl_graph(
    endpoint: str,
    *,
    limit: int,
    min_tvl_usd: float,
) -> dict[str, str]:
    """Топ `limit` токенов по TVL на одном subgraph endpoint → {address_lc: SYMBOL}."""
    lim = max(1, min(int(limit), 1000))
    if min_tvl_usd > 0:
        query = """
        query MajorTokens($first: Int!, $minTvl: BigDecimal!) {
          tokens(
            first: $first,
            orderBy: totalValueLockedUSD,
            orderDirection: desc,
            where: { totalValueLockedUSD_gte: $minTvl }
          ) {
            id
            symbol
          }
        }
        """
        variables: dict[str, Any] = {"first": lim, "minTvl": str(min_tvl_usd)}
    else:
        query = """
        query MajorTokens($first: Int!) {
          tokens(first: $first, orderBy: totalValueLockedUSD, orderDirection: desc) {
            id
            symbol
          }
        }
        """
        variables = {"first": lim}
    data = graphql_query(endpoint, query, variables, retries=1)
    rows = (data.get("data") or {}).get("tokens") or []
    out: dict[str, str] = {}
    for row in rows:
        if not isinstance(row, dict):
            continue
        tid = str(row.get("id") or "").strip().lower()
        sym = str(row.get("symbol") or "").strip()
        if not _is_eth_address(tid) or not _is_clean_symbol(sym):
            continue
        out[tid] = sym.upper()
    return out


def _merge_static_token_addr_maps(overlay_by_chain: dict[str, dict[str, str]] | None) -> dict[str, dict[str, str]]:
    """config.TOKEN_ADDRESSES + overlay (адреса из сабграфа top-N по сети)."""
    merged: dict[str, dict[str, str]] = {
        str(k).strip().lower(): dict(v) for k, v in _TOKEN_ADDR_TO_SYMBOL_BY_CHAIN.items()
    }
    if not overlay_by_chain:
        return merged
    for ck, mp in overlay_by_chain.items():
        if not isinstance(mp, dict):
            continue
        bucket = merged.setdefault(_normalize_chain_key_slug(str(ck)), {})
        for addr, sym in mp.items():
            a = str(addr).strip().lower()
            if not _is_eth_address(a):
                continue
            s = str(sym or "").strip().upper()
            if s:
                bucket[a] = s
    return merged


def _fetch_major_tokens_overlay_from_graph() -> dict[str, dict[str, str]]:
    """Только данные сабграфа (без merge с config), по одной сети — объединение v3+v4."""
    lim = max(1, min(int(TOKENS_MAJOR_TOP_N), 1000))
    min_tvl = float(TOKENS_MAJOR_TOP_MIN_TVL_USD or 0.0)
    out: dict[str, dict[str, str]] = {}
    for chain in _supported_chains():
        ck = str(chain).strip().lower()
        bucket: dict[str, str] = {}
        for version in ("v3", "v4"):
            ep = get_graph_endpoint(chain, version)
            if not ep:
                continue
            try:
                part = _fetch_top_token_addrs_by_tvl_graph(ep, limit=lim, min_tvl_usd=min_tvl)
                bucket.update(part)
            except Exception:
                continue
        if bucket:
            out[ck] = bucket
    return out


def _major_tokens_cache_meta_ok(raw: dict[str, Any] | None) -> bool:
    if not raw or not isinstance(raw.get("by_chain"), dict):
        return False
    try:
        if int(raw.get("top_n") or 0) != int(TOKENS_MAJOR_TOP_N):
            return False
        if abs(float(raw.get("min_tvl_usd") or 0) - float(TOKENS_MAJOR_TOP_MIN_TVL_USD)) > 1e-9:
            return False
    except (TypeError, ValueError):
        return False
    return True


def _overlay_dict_from_major_cache_raw(raw: dict[str, Any]) -> dict[str, dict[str, str]]:
    overlay: dict[str, dict[str, str]] = {}
    by_chain = raw.get("by_chain") if isinstance(raw, dict) else None
    if not isinstance(by_chain, dict):
        return overlay
    for ck, obj in by_chain.items():
        if not isinstance(obj, dict):
            continue
        d: dict[str, str] = {}
        for ad, sym in obj.items():
            a = str(ad).strip().lower()
            if _is_eth_address(a):
                d[a] = str(sym or "").strip().upper()
        nk = _normalize_chain_key_slug(str(ck))
        if nk in overlay:
            overlay[nk].update(d)
        else:
            overlay[nk] = dict(d)
    return overlay


def _prime_major_tokens_from_disk() -> bool:
    """Загрузить major_tokens_by_chain.json в память (без сети). False если файла нет или мета не совпала."""
    global _MERGED_TOKEN_ADDR_BY_CHAIN
    if int(TOKENS_MAJOR_TOP_N or 0) <= 0:
        with _MERGED_TOKEN_ADDR_LOCK:
            _MERGED_TOKEN_ADDR_BY_CHAIN = None
        return True
    raw = _read_json(MAJOR_TOKENS_CACHE_PATH)
    if not _major_tokens_cache_meta_ok(raw):
        return False
    overlay = _overlay_dict_from_major_cache_raw(raw)
    with _MERGED_TOKEN_ADDR_LOCK:
        _MERGED_TOKEN_ADDR_BY_CHAIN = _merge_static_token_addr_maps(overlay)
    return True


def _refresh_major_tokens_cache(*, force: bool = False) -> dict[str, Any]:
    """Обновить сабграф → major_tokens_by_chain.json + in-memory merge. При force=False и свежем файле — только prime."""
    global _MERGED_TOKEN_ADDR_BY_CHAIN
    if int(TOKENS_MAJOR_TOP_N or 0) <= 0:
        with _MERGED_TOKEN_ADDR_LOCK:
            _MERGED_TOKEN_ADDR_BY_CHAIN = None
        return {"ok": True, "skipped": "top_n_disabled"}
    if not force and MAJOR_TOKENS_CACHE_PATH.is_file():
        if not _catalog_stale(MAJOR_TOKENS_CACHE_PATH, MAJOR_TOKENS_CACHE_MAX_AGE_SEC):
            if _prime_major_tokens_from_disk():
                return {"ok": True, "skipped": "disk_cache_fresh"}
    try:
        overlay = _fetch_major_tokens_overlay_from_graph()
    except Exception as e:
        print(f"[catalog-refresh] major tokens subgraph fetch failed: {e}")
        if _prime_major_tokens_from_disk():
            return {"ok": True, "skipped": "fetch_failed_kept_disk", "error": str(e)[:200]}
        return {"ok": False, "error": str(e)[:400]}
    payload: dict[str, Any] = {
        "updated_at": _iso_now(),
        "top_n": int(TOKENS_MAJOR_TOP_N),
        "min_tvl_usd": float(TOKENS_MAJOR_TOP_MIN_TVL_USD),
        "by_chain": overlay,
        "source": "subgraph_v3_v4_top_n",
    }
    try:
        _write_json(MAJOR_TOKENS_CACHE_PATH, payload)
    except Exception as e:
        print(f"[catalog-refresh] major tokens write failed: {e}")
    with _MERGED_TOKEN_ADDR_LOCK:
        _MERGED_TOKEN_ADDR_BY_CHAIN = _merge_static_token_addr_maps(overlay)
    n_addr = sum(len(v) for v in overlay.values())
    return {"ok": True, "chains": len(overlay), "addresses": int(n_addr)}


def _get_merged_token_addr_to_symbol_by_chain() -> dict[str, dict[str, str]]:
    """Слой из файла/памяти + config; cold start без файла — один принудительный fetch."""
    global _MERGED_TOKEN_ADDR_BY_CHAIN
    if int(TOKENS_MAJOR_TOP_N or 0) <= 0:
        return _TOKEN_ADDR_TO_SYMBOL_BY_CHAIN
    with _MERGED_TOKEN_ADDR_LOCK:
        if _MERGED_TOKEN_ADDR_BY_CHAIN is not None:
            return _MERGED_TOKEN_ADDR_BY_CHAIN
    if _prime_major_tokens_from_disk():
        with _MERGED_TOKEN_ADDR_LOCK:
            if _MERGED_TOKEN_ADDR_BY_CHAIN is not None:
                return _MERGED_TOKEN_ADDR_BY_CHAIN
    _refresh_major_tokens_cache(force=True)
    with _MERGED_TOKEN_ADDR_LOCK:
        if _MERGED_TOKEN_ADDR_BY_CHAIN is not None:
            return _MERGED_TOKEN_ADDR_BY_CHAIN
    return _merge_static_token_addr_maps({})


def _token_addr_symbol_map_for_chain(chain_key: str) -> dict[str, str]:
    maps = _get_merged_token_addr_to_symbol_by_chain()
    k = _normalize_chain_key_slug(str(chain_key or ""))
    return dict((maps.get(k, {}) or {}))


def _normalize_token_symbol_for_lookup(sym: str) -> str:
    s = str(sym or "").strip().upper()
    if not s:
        return ""
    alias = {
        "WETH": "ETH",
        "WETH.E": "ETH",
        "WETH9": "ETH",
        "WBNB": "BNB",
        "WMATIC": "POL",
        "MATIC": "POL",
        "WPOL": "POL",
        "WAVAX": "AVAX",
        "WFTM": "FTM",
        "WCELO": "CELO",
    }
    return alias.get(s, s)


def _token_addr_by_symbol_for_chain(chain_key: str, symbol: str) -> str:
    want = _normalize_token_symbol_for_lookup(symbol)
    if not want:
        return ""
    addr_map = _token_addr_symbol_map_for_chain(chain_key)
    for addr, sym in addr_map.items():
        if _normalize_token_symbol_for_lookup(sym) == want and _is_eth_address(addr):
            return str(addr).strip().lower()
    return ""


def _build_token_catalog_from_merged_major(merged: dict[str, dict[str, str]], updated_at: str) -> dict[str, Any]:
    """Единый token_catalog.json из той же мапы адресов, что и везде на сайте."""
    by_chain_syms: dict[str, list[str]] = {}
    all_syms: set[str] = set()
    for ck, addr_map in merged.items():
        syms = sorted(
            {
                str(s).strip().lower()
                for s in (addr_map or {}).values()
                if _is_clean_symbol(str(s).strip())
            }
        )
        by_chain_syms[str(ck).strip().lower()] = syms
        all_syms.update(syms)
    return {
        "updated_at": updated_at,
        "count": len(all_syms),
        "items": sorted(all_syms),
        "by_chain": by_chain_syms,
        "source": "major_tokens_top_n_merged",
        "min_tvl_usd": 0.0,
        "major_top_n": int(TOKENS_MAJOR_TOP_N),
        "major_min_tvl_usd": float(TOKENS_MAJOR_TOP_MIN_TVL_USD),
    }


def _is_stablecoin_symbol(sym: str) -> bool:
    s = str(sym or "").strip().lower()
    if not s:
        return False
    return s in _STABLECOIN_SYMBOLS


def _curated_token_symbols() -> set[str]:
    return {
        str(sym or "").strip().lower()
        for sym in _supported_tokens()
        if _is_clean_symbol(str(sym or "").strip())
    }


