def _merge_ranked_symbol_lists(*lists: list[str]) -> list[str]:
    out: list[str] = []
    seen: set[str] = set()
    for arr in lists:
        for sym in (arr or []):
            s = str(sym or "").strip().lower()
            if not _is_clean_symbol(s):
                continue
            if s in seen:
                continue
            seen.add(s)
            out.append(s)
    return out


def _apply_manual_list(items: list[str], manual: list[str], *, strict: bool = False) -> list[str]:
    """Apply manual list as priority (or strict allowlist) over ranked items."""
    cleaned_items = _merge_ranked_symbol_lists(items or [])
    cleaned_manual = _merge_ranked_symbol_lists(manual or [])
    if not cleaned_manual:
        return cleaned_items
    if strict:
        return cleaned_manual
    manual_norm = {_normalize_pair_list_symbol_key(x) for x in cleaned_manual}
    tail = [s for s in cleaned_items if _normalize_pair_list_symbol_key(s) not in manual_norm]
    return cleaned_manual + tail


def _load_pair_lists_catalog(refresh: bool = False) -> dict[str, Any]:
    def _empty_pair_lists_catalog() -> dict[str, Any]:
        manual_cfg = _load_manual_pair_lists_overrides()
        fiat_cfg = manual_cfg.get("fiat_stable") if isinstance(manual_cfg.get("fiat_stable"), dict) else {}
        algo_cfg = manual_cfg.get("algo_stable") if isinstance(manual_cfg.get("algo_stable"), dict) else {}
        meme_cfg = manual_cfg.get("memes") if isinstance(manual_cfg.get("memes"), dict) else {}
        coins_cfg = manual_cfg.get("coins") if isinstance(manual_cfg.get("coins"), dict) else {}
        commodity_cfg = manual_cfg.get("commodity") if isinstance(manual_cfg.get("commodity"), dict) else {}
        nonusd_cfg = manual_cfg.get("fiat_nonusd") if isinstance(manual_cfg.get("fiat_nonusd"), dict) else {}
        fiat_all = _merge_ranked_symbol_lists(
            _normalize_symbol_list(fiat_cfg.get("core") if isinstance(fiat_cfg.get("core"), list) else []),
            _normalize_symbol_list(fiat_cfg.get("rwa") if isinstance(fiat_cfg.get("rwa"), list) else []),
        )
        algo_all = _merge_ranked_symbol_lists(
            _normalize_symbol_list(algo_cfg.get("main") if isinstance(algo_cfg.get("main"), list) else []),
            _normalize_symbol_list(algo_cfg.get("niche") if isinstance(algo_cfg.get("niche"), list) else []),
        )
        meme_all = _normalize_symbol_list(meme_cfg.get("top") if isinstance(meme_cfg.get("top"), list) else [])
        coins_all = _normalize_symbol_list(coins_cfg.get("top") if isinstance(coins_cfg.get("top"), list) else [])
        commodity_all = _normalize_symbol_list(commodity_cfg.get("top") if isinstance(commodity_cfg.get("top"), list) else [])
        nonusd_all = _normalize_symbol_list(nonusd_cfg.get("top") if isinstance(nonusd_cfg.get("top"), list) else [])
        return {
            "schema_version": int(PAIR_LISTS_SCHEMA_VERSION),
            "updated_at": _iso_now(),
            "source": "pair_lists_empty_cache",
            "stablecoins": [],
            "tokens": [],
            "coins": [],
            "stablecoins_full": [],
            "stable_algo_crypto": [],
            "stable_algo_crypto_full": [],
            "tokens_full": [],
            "coins_full": [],
            "commodity_stables": [],
            "fiat_nonusd_stables": [],
            "memes": [],
            "manual_overrides": {
                "fiat_stable": {
                    "enabled": bool(fiat_cfg.get("enabled", True)),
                    "strict": bool(fiat_cfg.get("strict", True)),
                    "selection_date": str(fiat_cfg.get("selection_date") or datetime.now(timezone.utc).date().isoformat()),
                    "core": _normalize_symbol_list(fiat_cfg.get("core") if isinstance(fiat_cfg.get("core"), list) else []),
                    "rwa": _normalize_symbol_list(fiat_cfg.get("rwa") if isinstance(fiat_cfg.get("rwa"), list) else []),
                    "count": len(fiat_all),
                },
                "algo_stable": {
                    "enabled": bool(algo_cfg.get("enabled", True)),
                    "strict": bool(algo_cfg.get("strict", True)),
                    "selection_date": str(algo_cfg.get("selection_date") or datetime.now(timezone.utc).date().isoformat()),
                    "main": _normalize_symbol_list(algo_cfg.get("main") if isinstance(algo_cfg.get("main"), list) else []),
                    "niche": _normalize_symbol_list(algo_cfg.get("niche") if isinstance(algo_cfg.get("niche"), list) else []),
                    "count": len(algo_all),
                },
                "memes": {
                    "enabled": bool(meme_cfg.get("enabled", True)),
                    "strict": bool(meme_cfg.get("strict", True)),
                    "selection_date": str(meme_cfg.get("selection_date") or datetime.now(timezone.utc).date().isoformat()),
                    "top": meme_all,
                    "count": len(meme_all),
                },
                "coins": {
                    "enabled": bool(coins_cfg.get("enabled", True)),
                    "strict": bool(coins_cfg.get("strict", True)),
                    "selection_date": str(coins_cfg.get("selection_date") or datetime.now(timezone.utc).date().isoformat()),
                    "top": coins_all,
                    "count": len(coins_all),
                },
                "commodity": {
                    "enabled": bool(commodity_cfg.get("enabled", True)),
                    "strict": bool(commodity_cfg.get("strict", True)),
                    "selection_date": str(commodity_cfg.get("selection_date") or datetime.now(timezone.utc).date().isoformat()),
                    "top": commodity_all,
                    "count": len(commodity_all),
                },
                "fiat_nonusd": {
                    "enabled": bool(nonusd_cfg.get("enabled", True)),
                    "strict": bool(nonusd_cfg.get("strict", True)),
                    "selection_date": str(nonusd_cfg.get("selection_date") or datetime.now(timezone.utc).date().isoformat()),
                    "top": nonusd_all,
                    "count": len(nonusd_all),
                },
            },
            "fiat_stable_hints": _manual_fiat_hints_lines(fiat_all),
            "fiat_nonusd_hints": _manual_fiat_nonusd_hints_lines(nonusd_all),
            "algo_stable_hints": _manual_algo_hints_lines(algo_all),
            "coin_hints": _manual_coins_hints_lines(coins_all),
            "commodity_hints": _manual_commodity_hints_lines(commodity_all),
            "meme_hints": _manual_meme_hints_lines(meme_all),
        }

    def _normalize_pair_lists_catalog(raw: dict[str, Any]) -> dict[str, Any]:
        base = _empty_pair_lists_catalog()
        if not isinstance(raw, dict):
            return base
        as_list = lambda v: v if isinstance(v, list) else []
        def _clean_sym_list(items: list[Any]) -> list[str]:
            out: list[str] = []
            seen: set[str] = set()
            for it in (items or []):
                s = str(it or "").strip().lower()
                if (not _is_clean_symbol(s)) or (s in _PAIR_LIST_BLOCKED_SYMBOLS):
                    continue
                if s in seen:
                    continue
                seen.add(s)
                out.append(s)
            return out
        out = dict(base)
        out["schema_version"] = int(raw.get("schema_version") or 0)
        out["updated_at"] = str(raw.get("updated_at") or base["updated_at"])
        out["source"] = str(raw.get("source") or base["source"])
        out["stablecoins"] = _clean_sym_list(as_list(raw.get("stablecoins")))
        out["stablecoins_full"] = _clean_sym_list(as_list(raw.get("stablecoins_full")) or list(out["stablecoins"]))
        out["stable_algo_crypto"] = _clean_sym_list(as_list(raw.get("stable_algo_crypto")))
        out["stable_algo_crypto_full"] = _clean_sym_list(as_list(raw.get("stable_algo_crypto_full")) or list(out["stable_algo_crypto"]))
        out["commodity_stables"] = _clean_sym_list(as_list(raw.get("commodity_stables")))
        out["fiat_nonusd_stables"] = _clean_sym_list(as_list(raw.get("fiat_nonusd_stables")))
        out["memes"] = _clean_sym_list(as_list(raw.get("memes")))
        meme_norm = {_normalize_pair_list_symbol_key(x) for x in out["memes"]}
        def _clean_non_meme(items: list[Any]) -> list[str]:
            cleaned = _clean_sym_list(items)
            return [s for s in cleaned if _normalize_pair_list_symbol_key(s) not in meme_norm]
        out["tokens"] = _clean_non_meme(as_list(raw.get("tokens")))
        out["coins"] = _clean_non_meme(as_list(raw.get("coins")) or list(out["tokens"]))
        out["tokens_full"] = _clean_non_meme(as_list(raw.get("tokens_full")) or list(out["tokens"]))
        out["coins_full"] = _clean_non_meme(as_list(raw.get("coins_full")) or as_list(raw.get("tokens_full")) or list(out["coins"]))
        manual_cfg_raw = raw.get("manual_overrides") if isinstance(raw.get("manual_overrides"), dict) else {}
        fiat_manual_raw = manual_cfg_raw.get("fiat_stable") if isinstance(manual_cfg_raw.get("fiat_stable"), dict) else {}
        algo_manual_raw = manual_cfg_raw.get("algo_stable") if isinstance(manual_cfg_raw.get("algo_stable"), dict) else {}
        meme_manual_raw = manual_cfg_raw.get("memes") if isinstance(manual_cfg_raw.get("memes"), dict) else {}
        coins_manual_raw = manual_cfg_raw.get("coins") if isinstance(manual_cfg_raw.get("coins"), dict) else {}
        commodity_manual_raw = manual_cfg_raw.get("commodity") if isinstance(manual_cfg_raw.get("commodity"), dict) else {}
        nonusd_manual_raw = manual_cfg_raw.get("fiat_nonusd") if isinstance(manual_cfg_raw.get("fiat_nonusd"), dict) else {}
        base_manual = base.get("manual_overrides", {}).get("fiat_stable", {})
        base_algo = base.get("manual_overrides", {}).get("algo_stable", {})
        base_meme = base.get("manual_overrides", {}).get("memes", {})
        base_coins = base.get("manual_overrides", {}).get("coins", {})
        base_commodity = base.get("manual_overrides", {}).get("commodity", {})
        base_nonusd = base.get("manual_overrides", {}).get("fiat_nonusd", {})
        fiat_manual = {
            "enabled": bool(fiat_manual_raw.get("enabled", base_manual.get("enabled", True))),
            "strict": bool(fiat_manual_raw.get("strict", base_manual.get("strict", True))),
            "selection_date": str(fiat_manual_raw.get("selection_date") or base_manual.get("selection_date") or datetime.now(timezone.utc).date().isoformat()),
            "core": _clean_sym_list(as_list(fiat_manual_raw.get("core")) or as_list(base_manual.get("core"))),
            "rwa": _clean_sym_list(as_list(fiat_manual_raw.get("rwa")) or as_list(base_manual.get("rwa"))),
        }
        fiat_manual["count"] = len(_merge_ranked_symbol_lists(fiat_manual.get("core", []), fiat_manual.get("rwa", [])))
        algo_manual = {
            "enabled": bool(algo_manual_raw.get("enabled", base_algo.get("enabled", True))),
            "strict": bool(algo_manual_raw.get("strict", base_algo.get("strict", True))),
            "selection_date": str(algo_manual_raw.get("selection_date") or base_algo.get("selection_date") or datetime.now(timezone.utc).date().isoformat()),
            "main": _clean_sym_list(as_list(algo_manual_raw.get("main")) or as_list(base_algo.get("main"))),
            "niche": _clean_sym_list(as_list(algo_manual_raw.get("niche")) or as_list(base_algo.get("niche"))),
        }
        algo_manual["count"] = len(_merge_ranked_symbol_lists(algo_manual.get("main", []), algo_manual.get("niche", [])))
        meme_manual = {
            "enabled": bool(meme_manual_raw.get("enabled", base_meme.get("enabled", True))),
            "strict": bool(meme_manual_raw.get("strict", base_meme.get("strict", True))),
            "selection_date": str(meme_manual_raw.get("selection_date") or base_meme.get("selection_date") or datetime.now(timezone.utc).date().isoformat()),
            "top": _clean_sym_list(as_list(meme_manual_raw.get("top")) or as_list(base_meme.get("top"))),
        }
        meme_manual["count"] = len(meme_manual.get("top", []))
        coins_manual = {
            "enabled": bool(coins_manual_raw.get("enabled", base_coins.get("enabled", True))),
            "strict": bool(coins_manual_raw.get("strict", base_coins.get("strict", True))),
            "selection_date": str(coins_manual_raw.get("selection_date") or base_coins.get("selection_date") or datetime.now(timezone.utc).date().isoformat()),
            "top": _clean_non_meme(as_list(coins_manual_raw.get("top")) or as_list(base_coins.get("top"))),
        }
        coins_manual["count"] = len(coins_manual.get("top", []))
        commodity_manual = {
            "enabled": bool(commodity_manual_raw.get("enabled", base_commodity.get("enabled", True))),
            "strict": bool(commodity_manual_raw.get("strict", base_commodity.get("strict", True))),
            "selection_date": str(commodity_manual_raw.get("selection_date") or base_commodity.get("selection_date") or datetime.now(timezone.utc).date().isoformat()),
            "top": _clean_sym_list(as_list(commodity_manual_raw.get("top")) or as_list(base_commodity.get("top"))),
        }
        commodity_manual["count"] = len(commodity_manual.get("top", []))
        nonusd_manual = {
            "enabled": bool(nonusd_manual_raw.get("enabled", base_nonusd.get("enabled", True))),
            "strict": bool(nonusd_manual_raw.get("strict", base_nonusd.get("strict", True))),
            "selection_date": str(nonusd_manual_raw.get("selection_date") or base_nonusd.get("selection_date") or datetime.now(timezone.utc).date().isoformat()),
            "top": _clean_sym_list(as_list(nonusd_manual_raw.get("top")) or as_list(base_nonusd.get("top"))),
        }
        nonusd_manual["count"] = len(nonusd_manual.get("top", []))
        out["manual_overrides"] = {
            "fiat_stable": fiat_manual,
            "algo_stable": algo_manual,
            "memes": meme_manual,
            "coins": coins_manual,
            "commodity": commodity_manual,
            "fiat_nonusd": nonusd_manual,
        }
        raw_hints = raw.get("fiat_stable_hints")
        if isinstance(raw_hints, list) and raw_hints:
            out["fiat_stable_hints"] = [str(x)[:220] for x in raw_hints if str(x or "").strip()]
        else:
            out["fiat_stable_hints"] = _manual_fiat_hints_lines(_merge_ranked_symbol_lists(fiat_manual.get("core", []), fiat_manual.get("rwa", [])))
        raw_algo_hints = raw.get("algo_stable_hints")
        if isinstance(raw_algo_hints, list) and raw_algo_hints:
            out["algo_stable_hints"] = [str(x)[:220] for x in raw_algo_hints if str(x or "").strip()]
        else:
            out["algo_stable_hints"] = _manual_algo_hints_lines(_merge_ranked_symbol_lists(algo_manual.get("main", []), algo_manual.get("niche", [])))
        raw_coin_hints = raw.get("coin_hints")
        if isinstance(raw_coin_hints, list) and raw_coin_hints:
            out["coin_hints"] = [str(x)[:220] for x in raw_coin_hints if str(x or "").strip()]
        else:
            out["coin_hints"] = _manual_coins_hints_lines(coins_manual.get("top", []))
        raw_commodity_hints = raw.get("commodity_hints")
        if isinstance(raw_commodity_hints, list) and raw_commodity_hints:
            out["commodity_hints"] = [str(x)[:220] for x in raw_commodity_hints if str(x or "").strip()]
        else:
            out["commodity_hints"] = _manual_commodity_hints_lines(commodity_manual.get("top", []))
        raw_nonusd_hints = raw.get("fiat_nonusd_hints")
        if isinstance(raw_nonusd_hints, list) and raw_nonusd_hints:
            out["fiat_nonusd_hints"] = [str(x)[:120] for x in raw_nonusd_hints if str(x or "").strip()]
        else:
            out["fiat_nonusd_hints"] = _manual_fiat_nonusd_hints_lines(nonusd_manual.get("top", []))
        raw_meme_hints = raw.get("meme_hints")
        if isinstance(raw_meme_hints, list) and raw_meme_hints:
            out["meme_hints"] = [str(x)[:220] for x in raw_meme_hints if str(x or "").strip()]
        else:
            out["meme_hints"] = _manual_meme_hints_lines(meme_manual.get("top", []))
        return out

    def _pair_lists_core_empty(pl: dict[str, Any]) -> bool:
        if not isinstance(pl, dict):
            return True
        return (
            len(pl.get("stablecoins_full") or []) == 0
            and len(pl.get("stable_algo_crypto_full") or []) == 0
            and len(pl.get("coins_full") or []) == 0
            and len(pl.get("commodity_stables") or []) == 0
            and len(pl.get("fiat_nonusd_stables") or []) == 0
            and len(pl.get("memes") or []) == 0
        )

    cached = _read_json(PAIR_LISTS_CATALOG_PATH)
    out = _normalize_pair_lists_catalog(cached) if isinstance(cached, dict) else _empty_pair_lists_catalog()
    # Keep existing non-manual buckets from cache exactly as-is; no auto discovery/update.
    # Only apply explicit manual overrides and hints.
    out["schema_version"] = int(PAIR_LISTS_SCHEMA_VERSION)
    out["updated_at"] = str(_iso_now()) if refresh else str(out.get("updated_at") or _iso_now())
    out["source"] = "manual_only_catalog"
    manual_cfg = _load_manual_pair_lists_overrides()
    fiat_manual = manual_cfg.get("fiat_stable") if isinstance(manual_cfg.get("fiat_stable"), dict) else {}
    nonusd_manual = manual_cfg.get("fiat_nonusd") if isinstance(manual_cfg.get("fiat_nonusd"), dict) else {}
    fiat_manual_core = _normalize_symbol_list(fiat_manual.get("core") if isinstance(fiat_manual.get("core"), list) else [])
    fiat_manual_rwa = _normalize_symbol_list(fiat_manual.get("rwa") if isinstance(fiat_manual.get("rwa"), list) else [])
    fiat_manual_all = _merge_ranked_symbol_lists(fiat_manual_core, fiat_manual_rwa)
    if bool(fiat_manual.get("enabled", True)) and fiat_manual_all:
        ranked_fiat = _apply_manual_list(
            list(out.get("stablecoins_full") or out.get("stablecoins") or []),
            fiat_manual_all,
            strict=bool(fiat_manual.get("strict", True)),
        )
        out["stablecoins_full"] = ranked_fiat[:200]
        out["stablecoins"] = ranked_fiat[:20]
        src_cur = str(out.get("source") or "")
        if "manual_fiat_override" not in src_cur:
            out["source"] = f"{src_cur}+manual_fiat_override".strip("+")
    out["manual_overrides"] = {
        "fiat_stable": {
            "enabled": bool(fiat_manual.get("enabled", True)),
            "strict": bool(fiat_manual.get("strict", True)),
            "selection_date": str(fiat_manual.get("selection_date") or datetime.now(timezone.utc).date().isoformat()),
            "core": fiat_manual_core,
            "rwa": fiat_manual_rwa,
            "count": len(fiat_manual_all),
        },
    }
    out["fiat_stable_hints"] = _manual_fiat_hints_lines(fiat_manual_all)
    nonusd_manual_top = _normalize_symbol_list(nonusd_manual.get("top") if isinstance(nonusd_manual.get("top"), list) else [])
    if bool(nonusd_manual.get("enabled", True)) and nonusd_manual_top:
        out["fiat_nonusd_stables"] = _apply_manual_list(
            list(out.get("fiat_nonusd_stables") or []),
            nonusd_manual_top,
            strict=bool(nonusd_manual.get("strict", True)),
        )[:200]
        src_cur = str(out.get("source") or "")
        if "manual_nonusd_override" not in src_cur:
            out["source"] = f"{src_cur}+manual_nonusd_override".strip("+")
    out["manual_overrides"]["fiat_nonusd"] = {
        "enabled": bool(nonusd_manual.get("enabled", True)),
        "strict": bool(nonusd_manual.get("strict", True)),
        "selection_date": str(nonusd_manual.get("selection_date") or datetime.now(timezone.utc).date().isoformat()),
        "top": nonusd_manual_top,
        "count": len(nonusd_manual_top),
    }
    out["fiat_nonusd_hints"] = _manual_fiat_nonusd_hints_lines(out.get("fiat_nonusd_stables", []))
    algo_manual = manual_cfg.get("algo_stable") if isinstance(manual_cfg.get("algo_stable"), dict) else {}
    algo_manual_main = _normalize_symbol_list(algo_manual.get("main") if isinstance(algo_manual.get("main"), list) else [])
    algo_manual_niche = _normalize_symbol_list(algo_manual.get("niche") if isinstance(algo_manual.get("niche"), list) else [])
    algo_manual_all = _merge_ranked_symbol_lists(algo_manual_main, algo_manual_niche)
    if bool(algo_manual.get("enabled", True)) and algo_manual_all:
        ranked_algo = _apply_manual_list(
            list(out.get("stable_algo_crypto_full") or out.get("stable_algo_crypto") or []),
            algo_manual_all,
            strict=bool(algo_manual.get("strict", True)),
        )
        out["stable_algo_crypto_full"] = ranked_algo[:200]
        out["stable_algo_crypto"] = ranked_algo[:200]
        src_cur = str(out.get("source") or "")
        if "manual_algo_override" not in src_cur:
            out["source"] = f"{src_cur}+manual_algo_override".strip("+")
    out["manual_overrides"]["algo_stable"] = {
        "enabled": bool(algo_manual.get("enabled", True)),
        "strict": bool(algo_manual.get("strict", True)),
        "selection_date": str(algo_manual.get("selection_date") or datetime.now(timezone.utc).date().isoformat()),
        "main": algo_manual_main,
        "niche": algo_manual_niche,
        "count": len(algo_manual_all),
    }
    out["algo_stable_hints"] = _manual_algo_hints_lines(algo_manual_all)
    coins_manual = manual_cfg.get("coins") if isinstance(manual_cfg.get("coins"), dict) else {}
    coins_manual_top = _normalize_symbol_list(coins_manual.get("top") if isinstance(coins_manual.get("top"), list) else [])
    if bool(coins_manual.get("enabled", True)) and coins_manual_top:
        ranked_coins = _apply_manual_list(
            list(out.get("coins_full") or out.get("tokens_full") or []),
            coins_manual_top,
            strict=bool(coins_manual.get("strict", True)),
        )
        out["coins_full"] = ranked_coins[:200]
        out["tokens_full"] = ranked_coins[:200]
        out["coins"] = ranked_coins[:20]
        out["tokens"] = ranked_coins[:20]
        src_cur = str(out.get("source") or "")
        if "manual_coins_override" not in src_cur:
            out["source"] = f"{src_cur}+manual_coins_override".strip("+")
    out["manual_overrides"]["coins"] = {
        "enabled": bool(coins_manual.get("enabled", True)),
        "strict": bool(coins_manual.get("strict", True)),
        "selection_date": str(coins_manual.get("selection_date") or datetime.now(timezone.utc).date().isoformat()),
        "top": coins_manual_top,
        "count": len(coins_manual_top),
    }
    out["coin_hints"] = _manual_coins_hints_lines(coins_manual_top)
    commodity_manual = manual_cfg.get("commodity") if isinstance(manual_cfg.get("commodity"), dict) else {}
    commodity_manual_top = _normalize_symbol_list(commodity_manual.get("top") if isinstance(commodity_manual.get("top"), list) else [])
    if bool(commodity_manual.get("enabled", True)) and commodity_manual_top:
        out["commodity_stables"] = _apply_manual_list(
            list(out.get("commodity_stables") or []),
            commodity_manual_top,
            strict=bool(commodity_manual.get("strict", True)),
        )[:200]
    out["manual_overrides"]["commodity"] = {
        "enabled": bool(commodity_manual.get("enabled", True)),
        "strict": bool(commodity_manual.get("strict", True)),
        "selection_date": str(commodity_manual.get("selection_date") or datetime.now(timezone.utc).date().isoformat()),
        "top": commodity_manual_top,
        "count": len(commodity_manual_top),
    }
    out["commodity_hints"] = _manual_commodity_hints_lines(out.get("commodity_stables", []))
    meme_manual = manual_cfg.get("memes") if isinstance(manual_cfg.get("memes"), dict) else {}
    meme_manual_top = _normalize_symbol_list(meme_manual.get("top") if isinstance(meme_manual.get("top"), list) else [])
    if bool(meme_manual.get("enabled", True)) and meme_manual_top:
        ranked_memes = _apply_manual_list(
            list(out.get("memes") or []),
            meme_manual_top,
            strict=bool(meme_manual.get("strict", True)),
        )
        out["memes"] = ranked_memes[:200]
        src_cur = str(out.get("source") or "")
        if "manual_meme_override" not in src_cur:
            out["source"] = f"{src_cur}+manual_meme_override".strip("+")
    out["manual_overrides"]["memes"] = {
        "enabled": bool(meme_manual.get("enabled", True)),
        "strict": bool(meme_manual.get("strict", True)),
        "selection_date": str(meme_manual.get("selection_date") or datetime.now(timezone.utc).date().isoformat()),
        "top": meme_manual_top,
        "count": len(meme_manual_top),
    }
    out["meme_hints"] = _manual_meme_hints_lines(meme_manual_top)
    if _pair_lists_core_empty(out):
        # Still persist manual config/hints even if user has not set all sections yet.
        out["source"] = "manual_only_catalog+core_empty"
    try:
        _write_json(PAIR_LISTS_CATALOG_PATH, out)
    except Exception:
        pass
    return out


def _fetch_tokens_by_chain_tvl(min_tvl_usd: float) -> tuple[set[str], dict[str, list[str]]]:
    all_tokens: set[str] = set()
    by_chain: dict[str, set[str]] = {}
    for chain in _supported_chains():
        chain_set: set[str] = set()
        for version in ("v3", "v4"):
            endpoint = get_graph_endpoint(chain, version)
            if not endpoint:
                continue
            try:
                chain_set.update(_fetch_tokens_by_tvl_endpoint(endpoint, min_tvl_usd))
            except Exception:
                continue
        if chain_set:
            by_chain[chain] = chain_set
            all_tokens.update(chain_set)
    return all_tokens, {k: sorted(v) for k, v in by_chain.items()}


def _load_token_catalog(refresh: bool = False) -> dict[str, Any]:
    """Каталог символов для UI: при TOKENS_MAJOR_TOP_N>0 — та же мапа, что и major_tokens (топ по TVL + config)."""
    if int(TOKENS_MAJOR_TOP_N or 0) > 0:
        cached = _read_json(TOKEN_CATALOG_PATH)
        if not refresh and cached and isinstance(cached.get("items"), list):
            try:
                if int(cached.get("major_top_n") or 0) == int(TOKENS_MAJOR_TOP_N):
                    if abs(float(cached.get("major_min_tvl_usd") or 0) - float(TOKENS_MAJOR_TOP_MIN_TVL_USD)) < 1e-9:
                        return cached
            except (TypeError, ValueError):
                pass
        merged = _get_merged_token_addr_to_symbol_by_chain()
        mt = _read_json(MAJOR_TOKENS_CACHE_PATH) or {}
        ts = str(mt.get("updated_at") or _iso_now())
        out = _build_token_catalog_from_merged_major(merged, ts)
        _write_json(TOKEN_CATALOG_PATH, out)
        return out

    cached = _read_json(TOKEN_CATALOG_PATH)
    if not refresh and cached and isinstance(cached.get("items"), list):
        try:
            cached_min_tvl = float(cached.get("min_tvl_usd") or 0)
        except (TypeError, ValueError):
            cached_min_tvl = 0.0
        if abs(cached_min_tvl - TOKENS_MIN_TVL_USD) < 1e-9 and not cached.get("major_top_n"):
            return cached

    by_chain: dict[str, list[str]] = {}
    all_tokens: set[str] = set()
    source = "tokens-tvl-threshold"
    try:
        all_tokens, by_chain = _fetch_tokens_by_chain_tvl(TOKENS_MIN_TVL_USD)
        try:
            verified_all, verified_by_chain = _fetch_uniswap_verified_tokens()
            if verified_all:
                all_tokens = {t for t in all_tokens if t in verified_all}
                filtered_by_chain: dict[str, list[str]] = {}
                for chain, items in by_chain.items():
                    allowed = set(verified_by_chain.get(chain, []))
                    keep = [t for t in items if t in allowed]
                    if keep:
                        filtered_by_chain[chain] = keep
                by_chain = filtered_by_chain
                source = "tokens-tvl-threshold+verified"
        except Exception:
            pass
    except Exception as e:
        print(f"[catalog-refresh] active pools tokens fetch failed: {e}")

    if not all_tokens and cached and isinstance(cached.get("items"), list):
        return cached

    if not all_tokens:
        source = "local-config-fallback"
        all_tokens.update(_supported_tokens())
    out = {
        "updated_at": _iso_now(),
        "count": len(all_tokens),
        "items": sorted(all_tokens),
        "by_chain": by_chain,
        "source": source,
        "min_tvl_usd": TOKENS_MIN_TVL_USD,
    }
    _write_json(TOKEN_CATALOG_PATH, out)
    return out


def _refresh_catalogs_once() -> None:
    """Refresh tokens/chains catalogs and keep app responsive on partial failures."""
    try:
        _load_chain_catalog(refresh=True)
    except Exception as e:
        print(f"[catalog-refresh] chains refresh failed: {e}")
    try:
        if int(TOKENS_MAJOR_TOP_N or 0) > 0:
            # force=False: не дергать сабграф чаще MAJOR_TOKENS_CACHE_MAX_AGE_SEC (дефолт 24ч),
            # даже если интервал общего catalog-refresh меньше.
            _refresh_major_tokens_cache(force=False)
    except Exception as e:
        print(f"[catalog-refresh] major tokens refresh failed: {e}")
    try:
        _load_token_catalog(refresh=True)
    except Exception as e:
        print(f"[catalog-refresh] tokens refresh failed: {e}")
    try:
        _load_pair_lists_catalog(refresh=True)
    except Exception as e:
        print(f"[catalog-refresh] pair lists refresh failed: {e}")


def _catalog_stale(path: Path, max_age_sec: int) -> bool:
    cached = _read_json(path)
    if not cached:
        return True
    updated_at_raw = str(cached.get("updated_at") or "").strip()
    if not updated_at_raw:
        return True
    try:
        updated_at = datetime.fromisoformat(updated_at_raw.replace("Z", "+00:00"))
    except ValueError:
        return True
    if updated_at.tzinfo is None:
        updated_at = updated_at.replace(tzinfo=timezone.utc)
    age_sec = (datetime.now(timezone.utc) - updated_at.astimezone(timezone.utc)).total_seconds()
    return age_sec >= max_age_sec


def _catalog_refresh_loop(interval_sec: int, run_on_startup: bool) -> None:
    # Не дергать сабграф при каждом деплое: при наличии кэшей на диске стартуем без сети.
    if run_on_startup and (
        not CHAIN_CATALOG_PATH.is_file()
        or (int(TOKENS_MAJOR_TOP_N or 0) > 0 and not MAJOR_TOKENS_CACHE_PATH.is_file())
        or not TOKEN_CATALOG_PATH.is_file()
        or not PAIR_LISTS_CATALOG_PATH.is_file()
    ):
        _refresh_catalogs_once()
    while not CATALOG_REFRESH_STOP.wait(interval_sec):
        _refresh_catalogs_once()


def _erc721_contract_refresh_weekly_loop(interval_sec: int, run_on_startup: bool) -> None:
    if run_on_startup:
        try:
            result = _run_erc721_contract_refresh_once()
            if str(result.get("status") or "") == "skipped":
                _indexer_log_run(
                    "erc721_contract_refresh",
                    "skip",
                    f"weekly_startup reason={result.get('reason') or 'unknown'}",
                )
        except Exception as e:
            _indexer_log_run("erc721_contract_refresh", "error", f"weekly_startup error={str(e)[:220]}")
    while not INFINITY_INDEXER_DAILY_STOP.wait(interval_sec):
        try:
            result = _run_erc721_contract_refresh_once()
            if str(result.get("status") or "") == "skipped":
                _indexer_log_run(
                    "erc721_contract_refresh",
                    "skip",
                    f"weekly reason={result.get('reason') or 'unknown'}",
                )
        except Exception as e:
            _indexer_log_run("erc721_contract_refresh", "error", f"weekly_loop error={str(e)[:220]}")


def _start_catalog_auto_refresh() -> None:
    global CATALOG_REFRESH_THREAD
    if CATALOG_REFRESH_THREAD and CATALOG_REFRESH_THREAD.is_alive():
        return
    CATALOG_REFRESH_STOP.clear()
    CATALOG_REFRESH_THREAD = threading.Thread(
        target=_catalog_refresh_loop,
        args=(CATALOG_REFRESH_INTERVAL_SEC, CATALOG_REFRESH_ON_STARTUP),
        daemon=True,
        name="catalog-auto-refresh",
    )
    CATALOG_REFRESH_THREAD.start()

def _start_erc721_contract_refresh_weekly() -> None:
    global INFINITY_INDEXER_DAILY_THREAD
    if not INFINITY_INDEXER_DAILY_ENABLED:
        return
    if INFINITY_INDEXER_DAILY_THREAD and INFINITY_INDEXER_DAILY_THREAD.is_alive():
        return
    INFINITY_INDEXER_DAILY_STOP.clear()
    INFINITY_INDEXER_DAILY_THREAD = threading.Thread(
        target=_erc721_contract_refresh_weekly_loop,
        args=(INFINITY_INDEXER_DAILY_INTERVAL_SEC, INFINITY_INDEXER_DAILY_ON_STARTUP),
        daemon=True,
        name="erc721-contract-refresh-daily-gate-weekly",
    )
    INFINITY_INDEXER_DAILY_THREAD.start()


def _stop_catalog_auto_refresh() -> None:
    CATALOG_REFRESH_STOP.set()


def _stop_erc721_contract_refresh_weekly() -> None:
    INFINITY_INDEXER_DAILY_STOP.set()


def _final_income(data: dict) -> float:
    fees = data.get("fees") or []
    return float(fees[-1][1]) if fees else 0.0


def _fee_over_threshold(data: dict, threshold_pct: float) -> bool:
    """True when pool fee is above configured threshold."""
    try:
        if float(data.get("fee_pct") or 0) > threshold_pct:
            return True
    except (TypeError, ValueError):
        pass
    raw = data.get("raw_fee_tier")
    if raw is None:
        return False
    try:
        raw_int = int(raw)
    except (TypeError, ValueError):
        return False
    if (raw_int / 10000.0) > threshold_pct:
        return True
    if raw_int > 100000 and (raw_int / 1e6) > threshold_pct:
        return True
    return False


def _merge_for_web(
    token_pairs: str,
    include_chains: list[str],
    min_fee_pct: float,
    max_fee_pct: float,
    min_apy_pct: float,
    min_tvl: float,
    days: int,
    lp_allocation_usd: float,
    exclude_suffixes: list[str],
    merged_override: dict[str, dict] | None = None,
) -> dict[str, Any]:
    suffix = pairs_to_filename_suffix(token_pairs)
    if merged_override is None:
        v3_path = DATA_DIR / f"pools_v3_{suffix}.json"
        v4_path = DATA_DIR / f"pools_v4_{suffix}.json"
        v3_data = load_chart_data_json(str(v3_path))
        v4_data = load_chart_data_json(str(v4_path))
        merged: dict[str, dict] = {}
        merged.update(v3_data)
        merged.update(v4_data)
    else:
        merged = dict(merged_override)

    in_chains = {x.strip().lower() for x in include_chains if x.strip()}
    if in_chains:
        merged = {k: v for k, v in merged.items() if v.get("chain", "").lower() in in_chains}

    suffix_set = {str(s).strip().lower().replace("0x", "")[-4:] for s in exclude_suffixes if str(s).strip()}

    def in_fee_range(item: dict) -> bool:
        try:
            pct = float(item.get("fee_pct") or 0)
        except (TypeError, ValueError):
            pct = 0.0
        return min_fee_pct <= pct <= max_fee_pct

    def excluded_by_suffix(item: dict, pid: str) -> bool:
        if not suffix_set:
            return False
        pool_id = str(item.get("pool_id") or pid or "").lower().replace("0x", "")
        return any(pool_id.endswith(suf) for suf in suffix_set)

    all_items = sorted(merged.items(), key=lambda kv: _final_income(kv[1]), reverse=True)

    rows = []
    chart_series = []
    filtered_out = 0
    filtered_by_apy = 0
    filtered_by_min_tvl = 0
    default_visible = 0
    days_safe = max(1, int(days or 1))
    alloc_safe = float(lp_allocation_usd or 0.0)

    def _last_positive_value(series: list | None) -> float:
        arr = series or []
        for item in reversed(arr):
            try:
                if not isinstance(item, (list, tuple)) or len(item) < 2:
                    continue
                v = float(item[1] or 0.0)
                if v > 0.0:
                    return float(v)
            except Exception:
                continue
        return 0.0

    def _align_series_end(series: list, end_ts: int) -> list:
        arr = [x for x in (series or []) if isinstance(x, (list, tuple)) and len(x) >= 2]
        if not arr:
            return []
        out = [(int(x[0]), float(x[1])) for x in arr]
        if int(end_ts) <= 0:
            return out
        last_ts = int(out[-1][0])
        last_val = float(out[-1][1])
        if last_ts < int(end_ts):
            out.append((int(end_ts), float(last_val)))
        return out

    def _short_source_label(src_raw: str) -> str:
        s = str(src_raw or "").strip().lower()
        if not s:
            return "unknown source"
        onchain = "on-chain"
        if "state_view" in s:
            onchain = "StateView"
        elif "pool_manager" in s:
            onchain = "PoolManager"
        elif "onchain_balance" in s or "full_pool" in s:
            onchain = "on-chain balances"
        price = "price feed"
        if "coingecko+defillama" in s:
            price = "CoinGecko/DefiLlama"
        elif "coingecko" in s:
            price = "CoinGecko"
        elif "defillama" in s:
            price = "DefiLlama"
        elif "dexscreener" in s:
            price = "Dexscreener"
        return f"{onchain} + {price}"

    def _calc_path_human(v: dict, *, branch: str = "", anchor_type: str = "", has_strict_compare: bool = False) -> str:
        ver = str(v.get("version") or "").strip().lower()
        src = str(v.get("tvl_price_source") or "").strip()
        src_l = src.lower()
        br = str(branch or "").strip().lower()
        anc = str(anchor_type or "").strip().lower()
        if has_strict_compare:
            if br == "estimated":
                anchor_lbl = "active" if anc == "active" else "full"
                return f"Estimated {anchor_lbl} | TVL shape=poolDayData + NOW anchor | fees=subgraph feesUSD"
            return "Estimated path"
        # Fast legacy / estimate mode
        if ver == "v4":
            if "v4_interface:totalliquidity" in src_l:
                return "Fast legacy: TVL NOW=Uniswap Interface | TVL history shape=poolDayData | fees=subgraph feesUSD"
            return "Fast legacy: TVL NOW=on-chain reserves + oracle prices | TVL history shape=poolDayData | fees=subgraph feesUSD"
        if ver == "v3":
            return "Fast legacy: TVL NOW=on-chain reserves + oracle prices | TVL history shape=poolDayData | fees=subgraph feesUSD"
        return "Fast legacy: standard pipeline"

    def _append_compare_row(
        *,
        pool_id: str,
        chain: str,
        version: str,
        base_pair: str,
        branch: str,
        anchor_type: str,
        fee_pct: float,
        income: float,
        apy: float,
        last_tvl: float,
        data_quality: str,
        data_quality_reason: str,
        status: str,
        calc_path_human: str = "",
        risk_level: str = "none",
        risk_reason: str = "",
        risk_flags: list[str] | None = None,
    ) -> None:
        rows.append(
            {
                "pool_id": str(pool_id or ""),
                "chain": str(chain or ""),
                "version": str(version or ""),
                "pair": f"{str(base_pair or '')} ({str(branch or '').strip()})",
                "anchor_type": str(anchor_type or ""),
                "fee_pct": float(fee_pct or 0.0),
                "final_income": float(income or 0.0),
                "apy_pct": float(apy or 0.0),
                "last_tvl": float(last_tvl or 0.0),
                "data_quality": str(data_quality or ""),
                "data_quality_reason": str(data_quality_reason or ""),
                "status": str(status or ""),
                "calc_path_human": str(calc_path_human or ""),
                "risk_level": str(risk_level or "none"),
                "risk_reason": str(risk_reason or ""),
                "risk_flags": list(risk_flags or []),
            }
        )

    def _risk_assessment(
        *,
        apy_pct: float,
        last_tvl: float,
        dq_reason: str,
        tvl_price_source: str,
        fees_series: list | None,
    ) -> tuple[str, str, list[str]]:
        flags: list[str] = []
        reasons: list[str] = []
        apy = float(apy_pct or 0.0)
        tvl_now = float(last_tvl or 0.0)
        reason_blob = str(dq_reason or "").strip().lower()
        src_blob = str(tvl_price_source or "").strip().lower()
        if apy <= 100.0:
            return "none", "", []
        flags.append("apr_gt_100")
        reasons.append("APR > 100%")
        if tvl_now > 0 and tvl_now < 50_000:
            flags.append("tiny_tvl_now")
            reasons.append(f"low TVL (${tvl_now:,.0f})")
        if alloc_safe > 0 and tvl_now > 0 and alloc_safe > tvl_now:
            flags.append("lp_allocation_gt_tvl")
            reasons.append("LP allocation > pool TVL")
        if ("raw_zero=" in reason_blob) or ("strict_required:v4_exact2" in reason_blob and "no_day_data" in reason_blob):
            flags.append("tvl_shape_missing_or_broken")
            reasons.append("TVL day-shape missing/broken")
        if "volume24h=0" in src_blob:
            flags.append("volume24h_zero")
            reasons.append("24h volume is zero")
        # Fees concentration check from cumulative series: one day dominates.
        cumul = []
        for p in (fees_series or []):
            if isinstance(p, (list, tuple)) and len(p) >= 2:
                try:
                    cumul.append(float(p[1] or 0.0))
                except Exception:
                    continue
        if len(cumul) >= 3:
            inc: list[float] = []
            prev = 0.0
            for v in cumul:
                d = float(v) - float(prev)
                if d > 0:
                    inc.append(d)
                prev = float(v)
            tot = float(sum(inc))
            mx = float(max(inc)) if inc else 0.0
            if tot > 0 and (mx / tot) >= 0.70:
                flags.append("fees_spike_concentration")
                reasons.append("single-day fees spike dominates")
        if not flags:
            return "none", "", []
        return "suspicious", "; ".join(reasons), flags

    def _infer_anchor_type_for_normal_row(v: dict, dq_reason: str) -> str:
        explicit = str(v.get("anchor_type") or "").strip().lower()
        if explicit in {"full", "active"}:
            return "Full" if explicit == "full" else "Active"
        src = str(v.get("tvl_price_source") or "").strip().lower()
        reason = str(dq_reason or "").strip().lower()
        blob = f"{src} {reason}"
        # Prefer explicit active hints from data source/reason.
        if ("active_window" in blob) or ("active anchor" in blob):
            return "Active"
        # Default non-strict anchor semantics are full-pool TVL.
        return "Full"
    for pool_id, v in all_items:
        fees = v.get("fees") or []
        tvl = v.get("tvl") or []
        dq = str(v.get("data_quality") or "estimated")
        dq_reason = str(v.get("data_quality_reason") or "").strip()
        strict_diagnostic = bool(dq == "strict_unavailable" or str(dq_reason).startswith("strict_required:"))
        has_strict_compare = bool(
            (v.get("strict_compare_estimated_fees") or [])
            or (v.get("strict_compare_estimated_tvl") or [])
            or (v.get("strict_compare_estimated_active_fees") or [])
            or (v.get("strict_compare_estimated_active_tvl") or [])
        )
        final_income = _final_income(v)
        apy_pct = (final_income / alloc_safe) * (365.0 / days_safe) * 100.0 if alloc_safe > 0 else 0.0
        if strict_diagnostic:
            status = "ok"
        else:
            if float(apy_pct) < float(min_apy_pct or 0.0):
                filtered_out += 1
                filtered_by_apy += 1
                continue
        if excluded_by_suffix(v, pool_id):
            status = "filtered_suffix"
        elif in_fee_range(v):
            status = "ok"
        else:
            status = "filtered_fee_range"
        if status != "ok":
            filtered_out += 1
        try:
            pool_tvl_now_usd = float(v.get("pool_tvl_now_usd") or 0.0)
        except (TypeError, ValueError):
            pool_tvl_now_usd = 0.0
        if float(pool_tvl_now_usd) < float(min_tvl or 0.0):
            filtered_out += 1
            filtered_by_min_tvl += 1
            continue
        if not dq_reason:
            ver = str(v.get("version") or "").strip().lower()
            if dq == "exact":
                dq_reason = "ok"
            elif ver == "v4":
                dq_reason = "v4_estimated_mode"
            elif ver == "v3":
                dq_reason = "v3_estimated_legacy_or_cache"
            else:
                dq_reason = "not_reported"
        base_pool_id = v.get("pool_id", pool_id)
        base_chain = v.get("chain", "")
        base_version = v.get("version", "")
        base_pair = v.get("pair", "")
        base_fee_pct = float(v.get("fee_pct") or 0)
        tvl_src_raw = str(v.get("tvl_price_source") or "")
        strict_compare_reason = str(dq_reason or "")
        if has_strict_compare:
            now_ts = int(time.time())
            est_fees = v.get("strict_compare_estimated_fees") or []
            est_tvl = v.get("strict_compare_estimated_tvl") or []
            est_active_fees = v.get("strict_compare_estimated_active_fees") or []
            est_active_tvl = v.get("strict_compare_estimated_active_tvl") or []
            strict_compare_reason = str(v.get("strict_compare_reason") or dq_reason or "estimated_compare")

            tvl_end_ts = max(
                [0]
                + [int(x[0]) for x in (est_tvl or []) if isinstance(x, (list, tuple)) and len(x) >= 2]
                + [int(x[0]) for x in (est_active_tvl or []) if isinstance(x, (list, tuple)) and len(x) >= 2]
                + [int(now_ts)]
            )
            fees_end_ts = max(
                [0]
                + [int(x[0]) for x in (est_fees or []) if isinstance(x, (list, tuple)) and len(x) >= 2]
                + [int(x[0]) for x in (est_active_fees or []) if isinstance(x, (list, tuple)) and len(x) >= 2]
                + [int(now_ts)]
            )
            est_tvl = _align_series_end(est_tvl, tvl_end_ts)
            est_active_tvl = _align_series_end(est_active_tvl, tvl_end_ts)
            est_fees = _align_series_end(est_fees, fees_end_ts)
            est_active_fees = _align_series_end(est_active_fees, fees_end_ts)

            src_lbl = _short_source_label(str(v.get("tvl_price_source") or ""))
            est_income = float(est_fees[-1][1]) if est_fees else 0.0
            est_apy = (est_income / alloc_safe) * (365.0 / days_safe) * 100.0 if alloc_safe > 0 else 0.0
            est_last_tvl = _last_positive_value(est_tvl) if est_tvl else float(pool_tvl_now_usd)
            if est_last_tvl <= 0.0:
                est_last_tvl = float(pool_tvl_now_usd)
            est_risk_level, est_risk_reason, est_risk_flags = _risk_assessment(
                apy_pct=est_apy,
                last_tvl=est_last_tvl,
                dq_reason=f"Estimate full anchor ({src_lbl})",
                tvl_price_source=tvl_src_raw,
                fees_series=est_fees,
            )
            _append_compare_row(
                pool_id=base_pool_id,
                chain=base_chain,
                version=base_version,
                base_pair=base_pair,
                branch="estimated",
                anchor_type="Full",
                fee_pct=base_fee_pct,
                income=est_income,
                apy=est_apy,
                last_tvl=est_last_tvl,
                data_quality="estimated",
                data_quality_reason=f"Estimate full anchor ({src_lbl})",
                status=status,
                calc_path_human=_calc_path_human(v, branch="estimated", anchor_type="Full", has_strict_compare=True),
                risk_level=est_risk_level,
                risk_reason=est_risk_reason,
                risk_flags=est_risk_flags,
            )

            if est_active_tvl:
                est_act_income = float(est_active_fees[-1][1]) if est_active_fees else 0.0
                est_act_apy = (est_act_income / alloc_safe) * (365.0 / days_safe) * 100.0 if alloc_safe > 0 else 0.0
                est_act_last_tvl = _last_positive_value(est_active_tvl) if est_active_tvl else 0.0
                est_act_risk_level, est_act_risk_reason, est_act_risk_flags = _risk_assessment(
                    apy_pct=est_act_apy,
                    last_tvl=est_act_last_tvl,
                    dq_reason=f"Estimate active anchor ({src_lbl})",
                    tvl_price_source=tvl_src_raw,
                    fees_series=est_active_fees,
                )
                _append_compare_row(
                    pool_id=base_pool_id,
                    chain=base_chain,
                    version=base_version,
                    base_pair=base_pair,
                    branch="estimated",
                    anchor_type="Active",
                    fee_pct=base_fee_pct,
                    income=est_act_income,
                    apy=est_act_apy,
                    last_tvl=est_act_last_tvl,
                    data_quality="estimated",
                    data_quality_reason=f"Estimate active anchor ({src_lbl})",
                    status=status,
                    calc_path_human=_calc_path_human(v, branch="estimated", anchor_type="Active", has_strict_compare=True),
                    risk_level=est_act_risk_level,
                    risk_reason=est_act_risk_reason,
                    risk_flags=est_act_risk_flags,
                )

        else:
            anchor_type = _infer_anchor_type_for_normal_row(v, dq_reason)
            row_risk_level, row_risk_reason, row_risk_flags = _risk_assessment(
                apy_pct=float(apy_pct),
                last_tvl=pool_tvl_now_usd,
                dq_reason=dq_reason,
                tvl_price_source=tvl_src_raw,
                fees_series=fees,
            )
            row = {
                "pool_id": base_pool_id,
                "chain": base_chain,
                "version": base_version,
                "pair": base_pair,
                "anchor_type": anchor_type,
                "fee_pct": base_fee_pct,
                "final_income": final_income,
                "apy_pct": float(apy_pct),
                "last_tvl": pool_tvl_now_usd,
                "data_quality": dq,
                "data_quality_reason": dq_reason,
                "status": status,
                "calc_path_human": _calc_path_human(v, has_strict_compare=False),
                "risk_level": row_risk_level,
                "risk_reason": row_risk_reason,
                "risk_flags": row_risk_flags,
            }
            rows.append(row)
        if fees or tvl or has_strict_compare:
            chart_series.append(
                {
                    "label": f"{base_chain} {base_version} {base_pair} ...{str(base_pool_id)[-4:]}",
                    "chain": base_chain,
                    "version": base_version,
                    "pair": base_pair,
                    "fee_pct": base_fee_pct,
                    "status": status,
                    "pool_id": base_pool_id,
                    "fees": fees,
                    "tvl": tvl,
                    "strict_compare_estimated_fees": (est_fees if has_strict_compare else (v.get("strict_compare_estimated_fees") or [])),
                    "strict_compare_estimated_tvl": (est_tvl if has_strict_compare else (v.get("strict_compare_estimated_tvl") or [])),
                    "strict_compare_estimated_active_fees": (est_active_fees if has_strict_compare else (v.get("strict_compare_estimated_active_fees") or [])),
                    "strict_compare_estimated_active_tvl": (est_active_tvl if has_strict_compare else (v.get("strict_compare_estimated_active_tvl") or [])),
                    "strict_compare_reason": strict_compare_reason,
                    "pool_tvl_now_usd": pool_tvl_now_usd,
                }
            )
            if status == "ok":
                default_visible += 1

    return {
        "suffix": suffix,
        "total": len(merged),
        "chart_pools": default_visible,
        "error_pools": filtered_out,
        "result_flags": {
            "empty_due_to_min_apy": bool((len(rows) == 0) and (filtered_by_apy > 0)),
            "empty_due_to_min_tvl": bool((len(rows) == 0) and (filtered_by_min_tvl > 0)),
            "filtered_by_apy_count": int(filtered_by_apy),
            "filtered_by_min_tvl_count": int(filtered_by_min_tvl),
        },
        "rows": rows,
        "series": chart_series,
    }


def _canonical_token_symbol(sym: str) -> str:
    return _canonical_wrapped_native_symbol(sym)


def _requested_pair_key(a: str, b: str) -> tuple[str, str]:
    x = _canonical_token_symbol(a)
    y = _canonical_token_symbol(b)
    return tuple(sorted((x, y)))


def _pair_label_key(pair_label: str) -> tuple[str, str] | None:
    if "/" not in (pair_label or ""):
        return None
    a_raw, b_raw = pair_label.split("/", 1)
    # Subgraph symbols may use variants (USD₮0, USDC.e); align with request-side keys.
    a = (_normalize_fee_symbol_hint(a_raw).strip().lower() or str(a_raw or "").strip().lower())
    b = (_normalize_fee_symbol_hint(b_raw).strip().lower() or str(b_raw or "").strip().lower())
    if not a or not b:
        return None
    return _requested_pair_key(a, b)


_TOKEN_SYMBOL_RE = re.compile(r"[a-z0-9][a-z0-9._-]{0,31}")
RUN_PAIRS_LIMIT = max(1, min(400, int(os.environ.get("RUN_PAIRS_LIMIT", "120"))))

_STABLECOIN_SYMBOLS = {
    "usdc", "usdt", "dai", "frax", "fdusd", "pyusd", "usde", "susde", "usdp", "tusd", "gusd",
    "lusd", "usdd", "usdbc", "usdt0", "rlusd", "eurc", "ageur", "usds", "usd0", "usdm",
    "eura", "eurt", "eurs", "xsgd", "audd", "cchf", "cadc", "jpyc", "gbpt", "gbpc", "brz", "tryb",
}
_COMMODITY_MANUAL_LIST = tuple(
    str(x or "").strip().lower()
    for x in os.environ.get("COMMODITY_MANUAL_LIST", "xaut,paxg,kau,kag,cgo").replace(" ", "").split(",")
    if _is_clean_symbol(str(x or "").strip().lower())
)
_COMMODITY_MANUAL_STRICT = str(os.environ.get("COMMODITY_MANUAL_STRICT", "1")).strip().lower() in {"1", "true", "yes", "on"}
_COMMODITY_STABLE_SYMBOLS = set(_COMMODITY_MANUAL_LIST) if _COMMODITY_MANUAL_LIST else {"paxg", "xaut", "xagx", "kag", "xag", "dgx"}
_NON_USD_FIAT_STABLE_SYMBOLS = {
    "eurc", "eurt", "eura", "eurs", "xsgd", "audd", "cchf", "cadc", "jpyc", "gbpt", "gbpc", "brz", "tryb",
}


def _clean_run_pairs(raw_pairs: list[str], *, limit: int = RUN_PAIRS_LIMIT) -> list[str]:
    """Normalize and validate input pairs in form 'tokenA,tokenB'."""
    out: list[str] = []
    seen: set[str] = set()
    for raw_pair in (raw_pairs or [])[: max(1, int(limit))]:
        part = str(raw_pair or "").strip().lower().replace(" ", "")
        if "," not in part:
            continue
        a_raw, b_raw = part.split(",", 1)
        a = str(a_raw or "").strip().lower()
        b = str(b_raw or "").strip().lower()
        if not _TOKEN_SYMBOL_RE.fullmatch(a):
            continue
        if not _TOKEN_SYMBOL_RE.fullmatch(b):
            continue
        if a == b:
            continue
        pair = f"{a},{b}"
        if pair in seen:
            continue
        seen.add(pair)
        out.append(pair)
    return out


def _parse_run_pair_tuples(clean_pairs: list[str], *, limit: int = RUN_PAIRS_LIMIT) -> list[tuple[str, str]]:
    pairs: list[tuple[str, str]] = []
    for pair in (clean_pairs or [])[: max(1, int(limit))]:
        part = str(pair or "").strip().lower()
        if "," not in part:
            continue
        a, b = part.split(",", 1)
        a = a.strip()
        b = b.strip()
        if a and b and a != b:
            pairs.append((a, b))
    return list(dict.fromkeys(pairs))


def _run_output_dir(job_id: str) -> Path:
    root = DATA_DIR / "run_tmp" / str(job_id)
    root.mkdir(parents=True, exist_ok=True)
    return root


def _agent_data_path(script_name: str, pair_suffix: str) -> Path:
    if str(script_name) == "agent_v3.py":
        return DATA_DIR / f"pools_v3_{pair_suffix}.json"
    return DATA_DIR / f"pools_v4_{pair_suffix}.json"


def _run_agent_and_load_timed(
    *,
    script_name: str,
    env: dict[str, str],
    min_tvl: float,
    logs: list[str],
    pair_suffix: str,
) -> tuple[dict[str, dict], dict[str, Any]]:
    t0 = time.perf_counter()
    subprocess_ms = _run_subprocess(script_name, env, min_tvl, logs)
    t_load0 = time.perf_counter()
    data = load_chart_data_json(str(_agent_data_path(script_name, pair_suffix)))
    load_json_ms = int(round(max(0.0, time.perf_counter() - t_load0) * 1000.0))
    total_ms = int(round(max(0.0, time.perf_counter() - t0) * 1000.0))
    dbg = {
        "script": str(script_name),
        "subprocess_ms": int(subprocess_ms),
        "load_json_ms": int(load_json_ms),
        "total_ms": int(total_ms),
        "pools_loaded": int(len(data)),
    }
    logs.append(
        f"[timing] {script_name}: subprocess={int(subprocess_ms)}ms "
        f"load_json={int(load_json_ms)}ms total={int(total_ms)}ms pools={int(len(data))}"
    )
    return data, dbg


def _pair_worker_count(speed_mode: str, total_pairs: int) -> int:
    key = "WEB_MAX_PAIR_WORKERS_FAST" if str(speed_mode) == "fast" else "WEB_MAX_PAIR_WORKERS_NORMAL"
    default_val = "4" if str(speed_mode) == "fast" else "3"
    try:
        cfg = int(os.environ.get(key, default_val))
    except Exception:
        cfg = int(default_val)
    return max(1, min(max(1, int(total_pairs or 1)), max(1, min(6, int(cfg)))))


def _run_single_pair_scan(
    *,
    pair_index: int,
    total_pairs: int,
    pair_tokens: tuple[str, str],
    base_env: dict[str, str],
    min_tvl: float,
    run_v3: bool,
    run_v4: bool,
) -> tuple[dict[str, dict], dict[str, Any], list[str]]:
    a, b = pair_tokens
    t_pair0 = time.perf_counter()
    pair_str = f"{a},{b}"
    pair_suffix = pairs_to_filename_suffix(pair_str)
    env = dict(base_env)
    env["TOKEN_PAIRS"] = pair_str
    pair_logs: list[str] = []
    pair_dbg: dict[str, Any] = {
        "pair": pair_str,
        "index": int(pair_index),
        "agents": [],
        "merged_before": 0,
        "merged_after": 0,
        "merged_added": 0,
    }
    merged_piece: dict[str, dict] = {}
    if run_v3 and run_v4:
        with ThreadPoolExecutor(max_workers=2) as ex:
            f_v3 = ex.submit(
                _run_agent_and_load_timed,
                script_name="agent_v3.py",
                env=dict(env),
                min_tvl=min_tvl,
                logs=pair_logs,
                pair_suffix=pair_suffix,
            )
            f_v4 = ex.submit(
                _run_agent_and_load_timed,
                script_name="agent_v4.py",
                env=dict(env),
                min_tvl=min_tvl,
                logs=pair_logs,
                pair_suffix=pair_suffix,
            )
            data_v3, dbg_v3 = f_v3.result()
            data_v4, dbg_v4 = f_v4.result()
            pair_dbg["agents"].append(dbg_v3)
            pair_dbg["agents"].append(dbg_v4)
            merged_piece.update(data_v3)
            merged_piece.update(data_v4)
    else:
        if run_v3:
            data_v3, dbg_v3 = _run_agent_and_load_timed(
                script_name="agent_v3.py",
                env=env,
                min_tvl=min_tvl,
                logs=pair_logs,
                pair_suffix=pair_suffix,
            )
            pair_dbg["agents"].append(dbg_v3)
            merged_piece.update(data_v3)
        if run_v4:
            data_v4, dbg_v4 = _run_agent_and_load_timed(
                script_name="agent_v4.py",
                env=env,
                min_tvl=min_tvl,
                logs=pair_logs,
                pair_suffix=pair_suffix,
            )
            pair_dbg["agents"].append(dbg_v4)
            merged_piece.update(data_v4)
    pair_dbg["merged_after"] = int(len(merged_piece))
    pair_dbg["merged_added"] = int(len(merged_piece))
    pair_dbg["total_ms"] = int(round(max(0.0, time.perf_counter() - t_pair0) * 1000.0))
    pair_logs.append(
        f"[timing] pair {pair_index}/{max(1, total_pairs)} {pair_str}: total={int(pair_dbg['total_ms'])}ms merged={int(len(merged_piece))}"
    )
    return merged_piece, pair_dbg, pair_logs


def _build_run_job_env(
    *,
    req: "PoolsRunRequest",
    speed_mode: str,
    token_pairs: str,
    include_chains: list[str],
    run_v4: bool,
) -> dict[str, str]:
    env = os.environ.copy()
    # Per-chain RPC routing (no shared/global RPC across chains).
    # Priority for each chain:
    # 1) chain-specific env (ALCHEMY_RPC_URL_<CHAIN>/RPC_URL_<CHAIN>/WEB3_RPC_URL_<CHAIN>)
    # 2) chain-id specific env (ALCHEMY_RPC_URL_<ID>/RPC_URL_<ID>)
    # 3) existing V3_RPC_URLS_<ID> list (kept as fallback list)
    chain_id_by_key = {
        "ethereum": 1,
        "optimism": 10,
        "bsc": 56,
        "unichain": 130,
        "polygon": 137,
        "base": 8453,
        "arbitrum": 42161,
        "avalanche": 43114,
        "celo": 42220,
    }

    # Keep explicit user-provided Alchemy defaults only per chain.
    arb_alchemy_url = "https://arb-mainnet.g.alchemy.com/v2/Ik0heQiNfzyztV2MGhKEe"
    polygon_alchemy_url = "https://polygon-mainnet.g.alchemy.com/v2/Ik0heQiNfzyztV2MGhKEe"
    # Public per-chain defaults (used only when env for that chain is not set).
    public_rpc_defaults = {
        "ETHEREUM": "https://ethereum-rpc.publicnode.com",
        "OPTIMISM": "https://optimism-rpc.publicnode.com",
        "BSC": "https://bsc-dataseed.binance.org",
        "UNICHAIN": "https://mainnet.unichain.org",
        "POLYGON": "https://polygon-bor-rpc.publicnode.com",
        "BASE": "https://base-rpc.publicnode.com",
        "ARBITRUM": "https://arbitrum-one-rpc.publicnode.com",
        "AVALANCHE": "https://api.avax.network/ext/bc/C/rpc",
        "CELO": "https://forno.celo.org",
    }
    if not str(env.get("ALCHEMY_RPC_URL_ARBITRUM", "") or "").strip():
        env["ALCHEMY_RPC_URL_ARBITRUM"] = arb_alchemy_url
    if not str(env.get("ALCHEMY_RPC_URL_POLYGON", "") or "").strip():
        env["ALCHEMY_RPC_URL_POLYGON"] = polygon_alchemy_url
    for chain_u, rpc_url in public_rpc_defaults.items():
        key = f"RPC_URL_{chain_u}"
        if not str(env.get(key, "") or "").strip():
            env[key] = str(rpc_url)

    def _prepend_rpc(chain_key: str, chain_id: int) -> None:
        ck = str(chain_key or "").strip().lower()
        cu = ck.upper()
        cid = int(chain_id)
        chain_rpc = (
            str(env.get(f"ALCHEMY_RPC_URL_{cu}", "") or "").strip()
            or str(env.get(f"RPC_URL_{cu}", "") or "").strip()
            or str(env.get(f"WEB3_RPC_URL_{cu}", "") or "").strip()
            or str(env.get(f"ALCHEMY_RPC_URL_{cid}", "") or "").strip()
            or str(env.get(f"RPC_URL_{cid}", "") or "").strip()
        )
        if not chain_rpc:
            return
        key = f"V3_RPC_URLS_{cid}"
        existing = [x.strip() for x in str(env.get(key, "") or "").split(",") if x.strip()]
        merged: list[str] = []
        seen: set[str] = set()
        for u in [chain_rpc] + existing:
            if u and u not in seen:
                merged.append(u)
                seen.add(u)
        env[key] = ",".join(merged)

    for _ck, _cid in chain_id_by_key.items():
        _prepend_rpc(_ck, _cid)
    exact_days_default = str(max(1, min(int(req.days), 7 if speed_mode == "fast" else 14)))
    # Agents resolve symbols via the same top-N cache as site catalog.
    try:
        env["MAJOR_TOKENS_CACHE_PATH"] = str(MAJOR_TOKENS_CACHE_PATH.resolve())
    except Exception:
        env["MAJOR_TOKENS_CACHE_PATH"] = str(MAJOR_TOKENS_CACHE_PATH)
    env["TOKEN_PAIRS"] = token_pairs
    env["FEE_DAYS"] = str(req.days)
    env["INCLUDE_CHAINS"] = ",".join(include_chains)
    # Web pool jobs only: always allow Base in the agent when INCLUDE_CHAINS includes it (CLI agents
    # still default-disable Base unless set). INCLUDE_CHAINS remains the real filter.
    env["ENABLE_BASE_CHAIN"] = "1"
    # Base v3 web path: use isolated Goldsky route with low-load profile.
    env["BASE_V3_ISOLATED_PIPELINE"] = os.environ.get("WEB_BASE_V3_ISOLATED_PIPELINE", "1")
    env["V3_SKIP_HEALTHCHECK_GOLDSKY"] = os.environ.get("WEB_V3_SKIP_HEALTHCHECK_GOLDSKY", "1")
    env["V3_BASE_GOLDSKY_USE_FILTERED_QUERY"] = os.environ.get("WEB_V3_BASE_GOLDSKY_USE_FILTERED_QUERY", "0")
    env["V3_BASE_GOLDSKY_PAGE_SIZE"] = os.environ.get(
        "WEB_V3_BASE_GOLDSKY_PAGE_SIZE_FAST" if speed_mode == "fast" else "WEB_V3_BASE_GOLDSKY_PAGE_SIZE_NORMAL",
        "40" if speed_mode == "fast" else "60",
    )
    env["V3_BASE_GOLDSKY_SCAN_PAGES"] = os.environ.get(
        "WEB_V3_BASE_GOLDSKY_SCAN_PAGES_FAST" if speed_mode == "fast" else "WEB_V3_BASE_GOLDSKY_SCAN_PAGES_NORMAL",
        "1" if speed_mode == "fast" else "2",
    )
    env["V3_BASE_ONCHAIN_DISCOVERY"] = os.environ.get("WEB_V3_BASE_ONCHAIN_DISCOVERY", "1")
    # Expensive diagnostic fallback; keep disabled in web runs unless explicitly enabled.
    env["V3_ONCHAIN_SWAPS_FALLBACK_ENABLE"] = os.environ.get("WEB_V3_ONCHAIN_SWAPS_FALLBACK_ENABLE", "0")
    # If user did not select chains (all), keep full set.
    env["V3_EXACT_TVL_CHAINS"] = (
        ",".join(include_chains)
        if include_chains
        else ",".join(sorted(UNISWAP_V3_SUBGRAPHS.keys()))
    )
    env["DISABLE_PDF_OUTPUT"] = "1"
    env["GRAPHQL_RETRIES"] = os.environ.get("WEB_GRAPHQL_RETRIES", "1")
    env["GRAPHQL_CONNECT_TIMEOUT_SEC"] = os.environ.get(
        "WEB_GRAPHQL_CONNECT_TIMEOUT_SEC_FAST" if speed_mode == "fast" else "WEB_GRAPHQL_CONNECT_TIMEOUT_SEC_NORMAL",
        "5" if speed_mode == "fast" else "8",
    )
    env["GRAPHQL_READ_TIMEOUT_SEC"] = os.environ.get(
        "WEB_GRAPHQL_READ_TIMEOUT_SEC_FAST" if speed_mode == "fast" else "WEB_GRAPHQL_READ_TIMEOUT_SEC_NORMAL",
        "8" if speed_mode == "fast" else "10",
    )
    env["POOL_SERIES_WORKERS"] = os.environ.get(
        "WEB_POOL_SERIES_WORKERS_FAST" if speed_mode == "fast" else "WEB_POOL_SERIES_WORKERS_NORMAL",
        "16" if speed_mode == "fast" else "8",
    )
    env["V3_DISCOVERY_CHAIN_WORKERS"] = os.environ.get(
        "WEB_V3_DISCOVERY_CHAIN_WORKERS_FAST" if speed_mode == "fast" else "WEB_V3_DISCOVERY_CHAIN_WORKERS_NORMAL",
        "6" if speed_mode == "fast" else "4",
    )
    env["MAX_DISCOVERY_POOLS_PER_PAIR_CHAIN"] = os.environ.get(
        "WEB_MAX_DISCOVERY_POOLS_PER_PAIR_CHAIN_FAST" if speed_mode == "fast" else "WEB_MAX_DISCOVERY_POOLS_PER_PAIR_CHAIN_NORMAL",
        "12" if speed_mode == "fast" else "24",
    )
    env["MAX_POOLS_PER_PAIR_CHAIN"] = os.environ.get(
        "WEB_MAX_POOLS_PER_PAIR_CHAIN_FAST" if speed_mode == "fast" else "WEB_MAX_POOLS_PER_PAIR_CHAIN_NORMAL",
        "20" if speed_mode == "fast" else "40",
    )
    env["MAX_POOLS_TOTAL"] = os.environ.get(
        "WEB_MAX_POOLS_TOTAL_FAST" if speed_mode == "fast" else "WEB_MAX_POOLS_TOTAL_NORMAL",
        "120" if speed_mode == "fast" else "240",
    )
    env["GRAPHQL_PAGE_DELAY_SEC"] = os.environ.get(
        "WEB_GRAPHQL_PAGE_DELAY_SEC_FAST" if speed_mode == "fast" else "WEB_GRAPHQL_PAGE_DELAY_SEC_NORMAL",
        "0",
    )
    env["DISABLE_V4_SYMBOL_FALLBACK"] = os.environ.get(
        "WEB_DISABLE_V4_SYMBOL_FALLBACK_FAST" if speed_mode == "fast" else "WEB_DISABLE_V4_SYMBOL_FALLBACK_NORMAL",
        "1" if speed_mode == "fast" else "1",
    )
    env["V4_SKIP_CHAIN_AFTER_TIMEOUT"] = os.environ.get(
        "WEB_V4_SKIP_CHAIN_AFTER_TIMEOUT",
        "1",
    )
    # Keep Base v4 disabled by default unless explicit override endpoint is configured.
    env["V4_SKIP_BASE_WITHOUT_OVERRIDE"] = os.environ.get(
        "WEB_V4_SKIP_BASE_WITHOUT_OVERRIDE",
        "1",
    )
    # Fail-fast package: tighter endpoint checks and smaller Base fallback scan window.
    env["V3_ENDPOINT_HEALTHCHECK"] = os.environ.get("WEB_V3_ENDPOINT_HEALTHCHECK", "1")
    env["V4_ENDPOINT_HEALTHCHECK"] = os.environ.get("WEB_V4_ENDPOINT_HEALTHCHECK", "1")
    env["V3_ENDPOINT_HEALTHCHECK_TIMEOUT_SEC"] = os.environ.get(
        "WEB_V3_ENDPOINT_HEALTHCHECK_TIMEOUT_SEC_FAST" if speed_mode == "fast" else "WEB_V3_ENDPOINT_HEALTHCHECK_TIMEOUT_SEC_NORMAL",
        "3" if speed_mode == "fast" else "4",
    )
    env["BASE_V4_HEALTHCHECK_TIMEOUT_SEC"] = os.environ.get(
        "WEB_BASE_V4_HEALTHCHECK_TIMEOUT_SEC_FAST" if speed_mode == "fast" else "WEB_BASE_V4_HEALTHCHECK_TIMEOUT_SEC_NORMAL",
        "3" if speed_mode == "fast" else "4",
    )
    env["V3_BASE_LIGHT_SCAN_PAGES"] = os.environ.get(
        "WEB_V3_BASE_LIGHT_SCAN_PAGES_FAST" if speed_mode == "fast" else "WEB_V3_BASE_LIGHT_SCAN_PAGES_NORMAL",
        "2" if speed_mode == "fast" else "3",
    )
    env["V3_BASE_FALLBACK_READ_TIMEOUT_SEC"] = os.environ.get(
        "WEB_V3_BASE_FALLBACK_READ_TIMEOUT_SEC_FAST" if speed_mode == "fast" else "WEB_V3_BASE_FALLBACK_READ_TIMEOUT_SEC_NORMAL",
        "4" if speed_mode == "fast" else "6",
    )
    env["V3_EXACT_TVL_DAYS_MAX"] = exact_days_default
    env["V3_EXACT_TVL_MAX_POOLS"] = "0"
    env["V3_EXACT_TVL_POOL_BUDGET_SEC"] = "0"
    env["V3_EXACT_TVL_ENABLE"] = "0"
    env["V3_EXACT_TVL_STRICT_MODE"] = "0"
    # v4 endpoint config uses this list at import-time.
    # When UI sends "all chains", include_chains is empty; in that case force all known v4 chains.
    if run_v4:
        if include_chains:
            v4_supported = {c for c in include_chains if c in UNISWAP_V4_SUBGRAPHS}
        else:
            v4_supported = set(UNISWAP_V4_SUBGRAPHS.keys())
        env["V4_CHAINS"] = ",".join(sorted(v4_supported))
    return env


def _run_subprocess(script_name: str, env: dict[str, str], min_tvl: float, logs: list[str]) -> int:
    cmd = [sys.executable, str(BASE_DIR / script_name), "--min-tvl", str(min_tvl)]
    timeout_sec = int(env.get("AGENT_TIMEOUT_SEC", "480"))
    logs.append(f"$ {' '.join(cmd)}  # timeout={timeout_sec}s")
    t0 = time.perf_counter()
    try:
        proc = subprocess.run(
            cmd,
            cwd=str(BASE_DIR),
            env=env,
            text=True,
            capture_output=True,
            timeout=timeout_sec,
        )
        if proc.stdout:
            logs.append(proc.stdout[-4000:])
        if proc.stderr:
            logs.append(proc.stderr[-4000:])
        if proc.returncode != 0:
            err_tail = str(proc.stderr or proc.stdout or "").strip()
            if err_tail:
                err_tail = err_tail[-700:]
                raise RuntimeError(f"{script_name} failed with code {proc.returncode}: {err_tail}")
            raise RuntimeError(f"{script_name} failed with code {proc.returncode}")
        return int(round(max(0.0, time.perf_counter() - t0) * 1000.0))
    except subprocess.TimeoutExpired as e:
        if e.stdout:
            logs.append(str(e.stdout)[-4000:])
        if e.stderr:
            logs.append(str(e.stderr)[-4000:])
        raise RuntimeError(
            f"{script_name} timed out after {timeout_sec}s. "
            "Try fewer chains or smaller history window."
        )


def _push_run_history(
    *,
    session_id: str,
    status: str,
    token_pairs: str,
    include_chains: list[str],
    min_tvl: float,
    days: int,
    include_versions: list[str],
    speed_mode: str,
    min_fee_pct: float,
    max_fee_pct: float,
    min_apy_pct: float,
    exclude_suffixes: list[str],
    logs: list[str],
    error: str | None = None,
) -> None:
    item = {
        "ts": _iso_now(),
        "status": status,
        "request": {
            "pairs": token_pairs,
            "include_chains": include_chains,
            "min_tvl": min_tvl,
            "days": days,
            "include_versions": include_versions,
            "speed_mode": speed_mode,
            "min_fee_pct": min_fee_pct,
            "max_fee_pct": max_fee_pct,
            "min_apy_pct": min_apy_pct,
            "exclude_suffixes": exclude_suffixes,
        },
        "error": error or "",
        "logs": logs[-8:],
    }
    with JOB_LOCK:
        bucket = RUN_HISTORY.setdefault(session_id, [])
        bucket.insert(0, item)
        del bucket[RUN_HISTORY_LIMIT:]
    _analytics_log_event(
        session_id=session_id,
        event_type="run_done" if status == "done" else "run_failed",
        path="/api/pools/run",
        payload=token_pairs,
    )


def _pool_run_cache_key(req: "PoolsRunRequest") -> str:
    pairs = sorted(str(x).strip().lower() for x in (req.pairs or []) if str(x).strip())
    chains = sorted(str(x).strip().lower() for x in (req.include_chains or []) if str(x).strip())
    versions = sorted(str(x).strip().lower() for x in (req.include_versions or []) if str(x).strip())
    suffixes = sorted(str(x).strip().lower() for x in (req.exclude_suffixes or []) if str(x).strip())
    run_mode = "fast_legacy"
    payload = {
        "pairs": pairs,
        "chains": chains,
        "versions": versions,
        "days": int(req.days or 0),
        "min_tvl": float(req.min_tvl or 0.0),
        "speed_mode": str(req.speed_mode or "fast").strip().lower(),
        "run_mode": run_mode,
        "min_fee_pct": float(req.min_fee_pct or 0.0),
        "max_fee_pct": float(req.max_fee_pct or 0.0),
        "min_apy_pct": float(req.min_apy_pct or 0.0),
        "exclude_suffixes": suffixes,
    }
    try:
        return json.dumps(payload, sort_keys=True, separators=(",", ":"))
    except Exception:
        return str(payload)


def _run_result_cache_get(key: str) -> dict[str, Any] | None:
    now = time.time()
    with JOB_LOCK:
        rec = RUN_RESULT_CACHE.get(str(key))
        if not rec:
            return None
        ts = float(rec.get("ts") or 0.0)
        if ts <= 0 or (now - ts) > float(RUN_RESULT_CACHE_TTL_SEC):
            RUN_RESULT_CACHE.pop(str(key), None)
            return None
        return dict(rec.get("result") or {})


def _run_result_cache_put(key: str, result: dict[str, Any]) -> None:
    now = time.time()
    with JOB_LOCK:
        RUN_RESULT_CACHE[str(key)] = {"ts": now, "result": _json_safe(result or {})}
        if len(RUN_RESULT_CACHE) > int(RUN_RESULT_CACHE_LIMIT):
            items = sorted(RUN_RESULT_CACHE.items(), key=lambda kv: float((kv[1] or {}).get("ts") or 0.0), reverse=True)
            keep = {k for k, _ in items[: int(RUN_RESULT_CACHE_LIMIT)]}
            for k in list(RUN_RESULT_CACHE.keys()):
                if k not in keep:
                    RUN_RESULT_CACHE.pop(k, None)


def _job_snapshot_path(job_id: str) -> Path:
    return JOB_STATUS_DIR / f"{str(job_id)}.json"


def _job_snapshot_delete(job_id: str) -> None:
    try:
        _job_snapshot_path(str(job_id)).unlink(missing_ok=True)
    except Exception:
        pass


def _job_snapshot_save(job: dict[str, Any]) -> None:
    if not isinstance(job, dict):
        return
    job_id = str(job.get("id") or "").strip()
    if not job_id:
        return
    p = _job_snapshot_path(job_id)
    tmp = p.with_suffix(".json.tmp")
    try:
        payload = _json_safe(job)
        with open(tmp, "w", encoding="utf-8") as f:
            json.dump(payload, f, ensure_ascii=True, indent=2)
        os.replace(tmp, p)
    except Exception:
        with contextlib.suppress(Exception):
            tmp.unlink(missing_ok=True)


def _job_snapshot_load(job_id: str) -> dict[str, Any] | None:
    p = _job_snapshot_path(str(job_id))
    if not p.exists():
        return None
    try:
        with open(p, "r", encoding="utf-8") as f:
            obj = json.load(f)
        if isinstance(obj, dict) and str(obj.get("id") or "") == str(job_id):
            return obj
    except Exception:
        return None
    return None


def _prune_run_jobs_locked(now: float | None = None) -> None:
    ts_now = float(now or time.time())
    # Convert stale active jobs to failed so they don't block counters forever.
    stale_active = []
    for jid, rec in list(JOBS.items()):
        st = str((rec or {}).get("status") or "")
        if st not in {"queued", "running"}:
            continue
        created_at = float((rec or {}).get("created_at") or 0.0)
        started_at = float((rec or {}).get("started_at") or 0.0)
        base_ts = started_at if started_at > 0 else created_at
        if base_ts <= 0:
            continue
        if (ts_now - base_ts) > float(RUN_ACTIVE_STALE_SEC):
            stale_active.append(str(jid))
    for jid in stale_active:
        rec = JOBS.get(str(jid))
        if not isinstance(rec, dict):
            continue
        rec["status"] = "failed"
        rec["stage"] = "failed"
        rec["stage_label"] = "Interrupted (stale active job pruned)"
        rec["progress"] = 100
        rec["finished_at"] = ts_now
        if not str(rec.get("error") or "").strip():
            rec["error"] = "Scan state became stale and was auto-pruned. Please run scan again."
        _job_snapshot_save(rec)
    stale_ids = [
        jid
        for jid, rec in JOBS.items()
        if (
            str((rec or {}).get("status") or "") in {"done", "failed"}
            and (ts_now - float((rec or {}).get("created_at") or ts_now)) > float(RUN_JOB_TTL_SEC)
        )
    ]
    for jid in stale_ids:
        JOBS.pop(str(jid), None)
        _job_snapshot_delete(str(jid))
    if len(JOBS) > int(RUN_JOB_LIMIT):
        active_ids = {
            str(jid)
            for jid, rec in JOBS.items()
            if str((rec or {}).get("status") or "") in {"queued", "running"}
        }
        terminal_items = sorted(
            [(jid, rec) for jid, rec in JOBS.items() if str(jid) not in active_ids],
            key=lambda kv: float(((kv[1] or {}).get("created_at") or 0.0)),
            reverse=True,
        )
        reserve_for_terminal = max(0, int(RUN_JOB_LIMIT) - len(active_ids))
        keep_terminal = {str(k) for k, _ in terminal_items[:reserve_for_terminal]}
        keep = set(active_ids) | keep_terminal
        for k in list(JOBS.keys()):
            if str(k) not in keep:
                JOBS.pop(k, None)
                _job_snapshot_delete(str(k))


def _compact_job_result_inplace(job: dict[str, Any]) -> None:
    """Drop bulky payload from old finished jobs to cap RSS."""
    if not isinstance(job, dict):
        return
    result = job.get("result")
    if not isinstance(result, dict):
        return
    rows = result.get("rows")
    series = result.get("series")
    if not rows and not series:
        return
    job["result"] = {
        "request": result.get("request") or {},
        "logs": (result.get("logs") or [])[-8:],
        "debug_timing": result.get("debug_timing") or {},
        "result_trimmed": True,
        "trim_reason": "memory_prune",
        "rows_count": int(len(rows or [])),
        "series_count": int(len(series or [])),
    }


def _prune_mapping_by_limit_and_ttl(
    cache: dict[Any, Any],
    *,
    limit: int,
    now_ts: float,
    ttl_sec: float | None = None,
    ts_getter: Any | None = None,
) -> None:
    if not isinstance(cache, dict) or not cache:
        return
    if ttl_sec and ts_getter:
        for k, v in list(cache.items()):
            try:
                ts = float(ts_getter(v) or 0.0)
            except Exception:
                ts = 0.0
            if ts <= 0.0 or (now_ts - ts) > float(ttl_sec):
                cache.pop(k, None)
    if len(cache) <= int(limit):
        return
    if ts_getter:
        items = sorted(
            cache.items(),
            key=lambda kv: float(ts_getter(kv[1]) or 0.0),
            reverse=True,
        )
        keep = {k for k, _ in items[: int(limit)]}
        for k in list(cache.keys()):
            if k not in keep:
                cache.pop(k, None)
    else:
        # dict order is insertion order; drop oldest first.
        while len(cache) > int(limit):
            oldest = next(iter(cache.keys()), None)
            if oldest is None:
                break
            cache.pop(oldest, None)


def _prune_runtime_state(force: bool = False) -> None:
    global _LAST_RUNTIME_PRUNE_TS
    now = time.time()
    if not force and (now - float(_LAST_RUNTIME_PRUNE_TS)) < float(RUNTIME_PRUNE_INTERVAL_SEC):
        return
    _LAST_RUNTIME_PRUNE_TS = now

    with JOB_LOCK:
        _prune_run_jobs_locked(now=now)
        # Remove expired run cache entries even if count is below limit.
        _prune_mapping_by_limit_and_ttl(
            RUN_RESULT_CACHE,
            limit=int(RUN_RESULT_CACHE_LIMIT),
            now_ts=now,
            ttl_sec=float(RUN_RESULT_CACHE_TTL_SEC),
            ts_getter=lambda v: (v or {}).get("ts"),
        )
        # Keep run-history bounded not only per-session but globally by session count.
        for sid, items in list(RUN_HISTORY.items()):
            if not isinstance(items, list) or not items:
                RUN_HISTORY.pop(sid, None)
                continue
            del items[RUN_HISTORY_LIMIT:]
        if len(RUN_HISTORY) > int(RUN_HISTORY_SESSION_LIMIT):
            ranked = sorted(
                RUN_HISTORY.items(),
                key=lambda kv: str(((kv[1] or [{}])[0] or {}).get("ts") or ""),
                reverse=True,
            )
            keep = {k for k, _ in ranked[: int(RUN_HISTORY_SESSION_LIMIT)]}
            for sid in list(RUN_HISTORY.keys()):
                if sid not in keep:
                    RUN_HISTORY.pop(sid, None)
        # Compact old finished job payloads to avoid keeping large chart datasets in RAM.
        cutoff = now - float(RUN_JOB_RESULT_TTL_SEC)
        for rec in JOBS.values():
            if not isinstance(rec, dict):
                continue
            status = str(rec.get("status") or "")
            if status not in {"done", "failed"}:
                continue
            finished_at = float(rec.get("finished_at") or rec.get("created_at") or 0.0)
            if finished_at > 0.0 and finished_at <= cutoff:
                _compact_job_result_inplace(rec)

    with AUTH_LOCK:
        # Nonces are short-lived by design.
        for sid, rec in list(AUTH_NONCES.items()):
            ts = float((rec or {}).get("issued_at_ts") or 0.0)
            if ts <= 0.0 or (now - ts) > float(AUTH_NONCE_TTL_SEC):
                AUTH_NONCES.pop(sid, None)
        # Session cleanup is required on long-running instances.
        for sid, rec in list(AUTH_SESSIONS.items()):
            base_ts = float((rec or {}).get("last_seen_ts") or (rec or {}).get("authenticated_at_ts") or 0.0)
            if base_ts <= 0.0 or (now - base_ts) > float(SESSION_TTL_SEC):
                AUTH_SESSIONS.pop(sid, None)

    with TOKEN_PRICE_CACHE_LOCK:
        _prune_mapping_by_limit_and_ttl(
            TOKEN_PRICE_CACHE,
            limit=int(TOKEN_PRICE_CACHE_LIMIT),
            now_ts=now,
            ttl_sec=float(PRICE_CACHE_TTL_SEC),
            ts_getter=lambda v: (v or (0.0, 0.0))[0],
        )
    with TOKEN_SYMBOL_CACHE_LOCK:
        _prune_mapping_by_limit_and_ttl(
            TOKEN_SYMBOL_CACHE,
            limit=int(TOKEN_SYMBOL_CACHE_LIMIT),
            now_ts=now,
            ttl_sec=None,
            ts_getter=None,
        )
    with CONTRACT_CREATION_DATE_CACHE_LOCK:
        _prune_mapping_by_limit_and_ttl(
            CONTRACT_CREATION_DATE_CACHE,
            limit=int(CONTRACT_CREATION_DATE_CACHE_LIMIT),
            now_ts=now,
            ttl_sec=None,
            ts_getter=None,
        )
    with POSITION_CREATION_DATE_CACHE_LOCK:
        _prune_mapping_by_limit_and_ttl(
            POSITION_CREATION_DATE_CACHE,
            limit=int(POSITION_CREATION_DATE_CACHE_LIMIT),
            now_ts=now,
            ttl_sec=None,
            ts_getter=None,
        )
    with EXPLORER_NFT_META_CACHE_LOCK:
        _prune_mapping_by_limit_and_ttl(
            EXPLORER_NFT_META_CACHE,
            limit=int(EXPLORER_NFT_META_CACHE_LIMIT),
            now_ts=now,
            ttl_sec=None,
            ts_getter=None,
        )
    with POSITION_CONTRACT_SNAPSHOT_CACHE_LOCK:
        _prune_mapping_by_limit_and_ttl(
            POSITION_CONTRACT_SNAPSHOT_CACHE,
            limit=int(POSITION_CONTRACT_SNAPSHOT_CACHE_LIMIT),
            now_ts=now,
            ttl_sec=float(POSITION_CONTRACT_SNAPSHOT_TTL_SEC),
            ts_getter=lambda v: (v or (0.0, {}))[0],
        )
    with COINGECKO_RANGE_CACHE_LOCK:
        _prune_mapping_by_limit_and_ttl(
            COINGECKO_RANGE_CACHE,
            limit=int(COINGECKO_RANGE_CACHE_LIMIT),
            now_ts=now,
            ttl_sec=float(FEE_SERIES_CACHE_TTL_SEC),
            ts_getter=lambda v: (v or (0.0, []))[0],
        )
    with POOL_TVL_SERIES_CACHE_LOCK:
        _prune_mapping_by_limit_and_ttl(
            POOL_TVL_SERIES_CACHE,
            limit=int(POOL_TVL_SERIES_CACHE_LIMIT),
            now_ts=now,
            ttl_sec=float(FEE_SERIES_CACHE_TTL_SEC),
            ts_getter=lambda v: (v or (0.0, []))[0],
        )
    with POOL_VOLUME_SERIES_CACHE_LOCK:
        _prune_mapping_by_limit_and_ttl(
            POOL_VOLUME_SERIES_CACHE,
            limit=int(POOL_VOLUME_SERIES_CACHE_LIMIT),
            now_ts=now,
            ttl_sec=float(FEE_SERIES_CACHE_TTL_SEC),
            ts_getter=lambda v: (v or (0.0, []))[0],
        )
    with POSITION_SNAPSHOT_SERIES_CACHE_LOCK:
        _prune_mapping_by_limit_and_ttl(
            POSITION_SNAPSHOT_SERIES_CACHE,
            limit=int(POSITION_SNAPSHOT_SERIES_CACHE_LIMIT),
            now_ts=now,
            ttl_sec=float(FEE_SERIES_CACHE_TTL_SEC),
            ts_getter=lambda v: (v or (0.0, []))[0],
        )


def _logs_indicate_incomplete_discovery(logs: list[str]) -> bool:
    if not logs:
        return False
    try:
        txt = "\n".join(str(x or "") for x in logs).lower()
    except Exception:
        return False
    markers = (
        "discovery_cap_hit",
        "discovery_potentially_truncated",
        "cap_trim_applied",
    )
    return any(m in txt for m in markers)


def _extract_price_drop_stats(logs: list[str]) -> dict[str, Any]:
    """
    Parse agent logs and collect strict-price exclusion counters for UI/debug.
    """
    stats: dict[str, Any] = {
        "dropped_no_reserves_by_chain": {},
        "price_unavailable_missing_reserves_by_chain": {},
    }
    if not logs:
        return stats
    pat_unavail = re.compile(
        r"PRICE_UNAVAILABLE\s+chain=(?P<chain>[a-z0-9_-]+).*?reason=(?P<reason>[a-z0-9_:-]+)",
        re.IGNORECASE,
    )
    pat_dropped = re.compile(
        r"PRICE_FILTER_DROPPED\s+chain=(?P<chain>[a-z0-9_-]+).*?count=(?P<count>\d+)",
        re.IGNORECASE,
    )
    dropped: dict[str, int] = {}
    unavailable_missing: dict[str, int] = {}
    try:
        chunks = [str(x or "") for x in logs]
    except Exception:
        chunks = []
    for chunk in chunks:
        for line in str(chunk).splitlines():
            m_drop = pat_dropped.search(line)
            if m_drop:
                ch = str(m_drop.group("chain") or "").strip().lower()
                cnt = int(m_drop.group("count") or 0)
                if ch and cnt > 0:
                    dropped[ch] = int(dropped.get(ch, 0)) + int(cnt)
            m_un = pat_unavail.search(line)
            if m_un:
                ch = str(m_un.group("chain") or "").strip().lower()
                rs = str(m_un.group("reason") or "").strip().lower()
                if ch and rs == "missing_pool_reserves":
                    unavailable_missing[ch] = int(unavailable_missing.get(ch, 0)) + 1
    # Prefer explicit dropped counters; fill holes from per-pool unavailable counters.
    merged = dict(dropped)
    for ch, cnt in unavailable_missing.items():
        if ch not in merged and int(cnt) > 0:
            merged[ch] = int(cnt)
    stats["dropped_no_reserves_by_chain"] = merged
    stats["price_unavailable_missing_reserves_by_chain"] = unavailable_missing
    return stats


def _diagnose_subgraph_from_logs(logs: list[str]) -> str | None:
    """
    When pool scans return zero pools, agent stdout often contains Graph healthcheck skips
    or GraphQL auth errors. Surface a short hint for the UI instead of a generic empty result.
    """
    blob = "\n".join(str(x) for x in (logs or [])).lower()
    if not blob.strip():
        return None
    if "payment required" in blob and "api key" in blob:
        return (
            "The Graph rejected requests (payment required / quota). "
            "Renew billing or replace THE_GRAPH_API_KEY; until then subgraph scans stay empty."
        )
    if "payment required" in blob:
        return "The Graph returned payment required — check API key billing and quota."
    if "auth error" in blob:
        return "The Graph auth error — verify THE_GRAPH_API_KEY is valid and has access."
    # Healthcheck failures with HTTP 200 + GraphQL errors still print our skip lines.
    if "healthcheck failed" in blob and "skip (endpoint healthcheck" in blob:
        return (
            "Subgraph endpoints failed the health check (often the same as an expired or unpaid Graph API key). "
            "See job logs for the exact message."
        )
    return None


def _recent_failed_runs(limit: int = 50) -> list[dict[str, Any]]:
    rows: list[dict[str, Any]] = []
    with JOB_LOCK:
        for sid, items in RUN_HISTORY.items():
            for item in items:
                if str(item.get("status") or "") != "failed":
                    continue
                req = item.get("request") or {}
                logs = item.get("logs") or []
                rows.append(
                    {
                        "ts": item.get("ts", ""),
                        "session_id": sid,
                        "pairs": req.get("pairs", ""),
                        "chains": ",".join(req.get("include_chains") or []),
                        "versions": ",".join(req.get("include_versions") or []),
                        "days": req.get("days"),
                        "min_tvl": req.get("min_tvl"),
                        "error": item.get("error", ""),
                        "logs": "\n\n".join(str(x) for x in logs if str(x).strip())[:6000],
                    }
                )
    rows.sort(key=lambda x: str(x.get("ts") or ""), reverse=True)
    return rows[: max(1, min(200, int(limit)))]


def _run_pool_job(job_id: str, req: "PoolsRunRequest", session_id: str) -> None:
    job_t0 = time.perf_counter()

    def _set_stage(stage: str, label: str, progress: int) -> None:
        with JOB_LOCK:
            j = JOBS.get(job_id)
            if not j:
                return
            j["stage"] = stage
            j["stage_label"] = label
            j["progress"] = max(0, min(100, progress))
            _job_snapshot_save(j)

    timing_debug: dict[str, Any] = {
        "total_ms": 0,
        "stage_ms": {},
        "pairs": [],
    }

    t_prepare0 = time.perf_counter()
    speed_mode = str(req.speed_mode or "fast").strip().lower()
    if speed_mode not in {"normal", "fast"}:
        speed_mode = "normal"
    mode_fast_legacy = True
    run_mode = "fast_legacy"

    with JOB_LOCK:
        job = JOBS[job_id]
        # Mark as queued until semaphore slot is actually acquired.
        # This avoids treating queue-waiting jobs as actively scanning.
        job["status"] = "queued"
        job["stage"] = "prepare"
        job["stage_label"] = f"Preparing parameters ({speed_mode}, {run_mode})"
        job["progress"] = 5
        _job_snapshot_save(job)

    # Build selected token pairs (bounded by RUN_PAIRS_LIMIT).
    t_pairs_parse0 = time.perf_counter()
    pairs = _parse_run_pair_tuples(req.pairs, limit=RUN_PAIRS_LIMIT)
    timing_debug["stage_ms"]["parse_pairs"] = int(round(max(0.0, time.perf_counter() - t_pairs_parse0) * 1000.0))
    if not pairs:
        with JOB_LOCK:
            job["status"] = "failed"
            job["error"] = "No valid pairs provided."
            job["stage"] = "failed"
            job["stage_label"] = "Validation failed"
            job["progress"] = 100
            timing_debug["total_ms"] = int(round(max(0.0, time.perf_counter() - job_t0) * 1000.0))
            job["result"] = {"logs": [], "debug_timing": timing_debug}
            _job_snapshot_save(job)
        return
    token_pairs = _pairs_to_string(pairs)
    requested_pair_keys = {_requested_pair_key(a, b) for a, b in pairs}

    include_chains = [c.strip().lower() for c in req.include_chains if c.strip()]
    include_versions = [v.strip().lower() for v in req.include_versions if v.strip()]
    run_v3 = "v3" in include_versions
    run_v4 = "v4" in include_versions

    t_env0 = time.perf_counter()
    logs: list[str] = []
    env = _build_run_job_env(
        req=req,
        speed_mode=speed_mode,
        token_pairs=token_pairs,
        include_chains=include_chains,
        run_v4=run_v4,
    )
    timing_debug["stage_ms"]["build_env"] = int(round(max(0.0, time.perf_counter() - t_env0) * 1000.0))
    timing_debug["stage_ms"]["prepare"] = int(round(max(0.0, time.perf_counter() - t_prepare0) * 1000.0))

    try:
        merged_raw: dict[str, dict] = {}
        running_jobs = 0
        with JOB_LOCK:
            for _jid, _j in JOBS.items():
                if str(_jid) == str(job_id):
                    continue
                if str((_j or {}).get("status") or "") == "running":
                    running_jobs += 1
        wait_label = (
            f"Waiting for scan slot ({running_jobs} active run(s), "
            f"timeout={int(RUN_SLOT_WAIT_TIMEOUT_SEC)}s)"
        )
        _set_stage("queue", wait_label, 8)
        t_lock_wait0 = time.perf_counter()
        slot_acquired = RUN_SLOTS_SEMAPHORE.acquire(timeout=float(RUN_SLOT_WAIT_TIMEOUT_SEC))
        timing_debug["stage_ms"]["run_lock_wait"] = int(round(max(0.0, time.perf_counter() - t_lock_wait0) * 1000.0))
        if not slot_acquired:
            msg = f"Queue timeout: no scan slot within {int(RUN_SLOT_WAIT_TIMEOUT_SEC)}s. Please retry."
            timing_debug["total_ms"] = int(round(max(0.0, time.perf_counter() - job_t0) * 1000.0))
            with JOB_LOCK:
                job["status"] = "failed"
                job["error"] = msg
                job["stage"] = "failed"
                job["stage_label"] = "Queue timeout"
                job["progress"] = 100
                job["result"] = {"logs": logs[-8:], "debug_timing": timing_debug}
                _job_snapshot_save(job)
            _push_run_history(
                session_id=session_id,
                status="failed",
                token_pairs=token_pairs,
                include_chains=include_chains,
                min_tvl=req.min_tvl,
                days=req.days,
                include_versions=include_versions,
                speed_mode=speed_mode,
                min_fee_pct=req.min_fee_pct,
                max_fee_pct=req.max_fee_pct,
                min_apy_pct=req.min_apy_pct,
                exclude_suffixes=req.exclude_suffixes,
                logs=logs,
                error=msg,
            )
            return
        with JOB_LOCK:
            j = JOBS.get(job_id)
            if j:
                j["status"] = "running"
                if float(j.get("started_at") or 0.0) <= 0:
                    j["started_at"] = time.time()
                j["stage"] = "queue"
                j["stage_label"] = "Scan slot acquired"
                j["progress"] = max(10, int(j.get("progress") or 0))
                _job_snapshot_save(j)
        try:
            t_agents_total0 = time.perf_counter()
            total_pairs = max(1, len(pairs))
            pair_workers = _pair_worker_count(speed_mode, total_pairs)
            _set_stage(
                "pairs",
                f"Running pair scans ({total_pairs} pair(s), workers={pair_workers})",
                12,
            )
            def _merge_pair_result(res: tuple[dict[str, dict], dict[str, Any], list[str]]) -> None:
                merged_piece, pair_dbg, pair_logs = res
                pair_dbg["merged_before"] = int(len(merged_raw))
                merged_raw.update(merged_piece or {})
                pair_dbg["merged_after"] = int(len(merged_raw))
                pair_dbg["merged_added"] = int(max(0, int(pair_dbg["merged_after"]) - int(pair_dbg["merged_before"])))
                timing_debug["pairs"].append(pair_dbg)
                if pair_logs:
                    logs.extend(pair_logs)
                    # Avoid unbounded growth of in-memory logs on huge scans.
                    if len(logs) > 400:
                        del logs[:-200]

            if pair_workers <= 1 or total_pairs <= 1:
                for idx, pair_tokens in enumerate(pairs, start=1):
                    _merge_pair_result(
                        _run_single_pair_scan(
                            pair_index=idx,
                            total_pairs=total_pairs,
                            pair_tokens=pair_tokens,
                            base_env=env,
                            min_tvl=req.min_tvl,
                            run_v3=run_v3,
                            run_v4=run_v4,
                        )
                    )
                    _set_stage("pairs", f"Running pair scans ({idx}/{total_pairs})", int(10 + (65 * idx / total_pairs)))
            else:
                with ThreadPoolExecutor(max_workers=pair_workers) as pair_ex:
                    future_to_idx = {
                        pair_ex.submit(
                            _run_single_pair_scan,
                            pair_index=idx,
                            total_pairs=total_pairs,
                            pair_tokens=pair_tokens,
                            base_env=env,
                            min_tvl=req.min_tvl,
                            run_v3=run_v3,
                            run_v4=run_v4,
                        ): idx
                        for idx, pair_tokens in enumerate(pairs, start=1)
                    }
                    done_n = 0
                    for fut in as_completed(list(future_to_idx.keys())):
                        _merge_pair_result(fut.result())
                        done_n += 1
                        _set_stage("pairs", f"Running pair scans ({done_n}/{total_pairs})", int(10 + (65 * done_n / total_pairs)))

            timing_debug["stage_ms"]["agents_total"] = int(round(max(0.0, time.perf_counter() - t_agents_total0) * 1000.0))
        finally:
            RUN_SLOTS_SEMAPHORE.release()

        # Keep only pools that really match requested pairs.
        # Protects against occasional cross-token resolution artifacts (e.g. POL instead of ETH).
        t_filter0 = time.perf_counter()
        if requested_pair_keys:
            merged_raw = {
                k: v
                for k, v in merged_raw.items()
                if (_pair_label_key(str(v.get("pair") or "")) in requested_pair_keys)
            }
        timing_debug["stage_ms"]["pair_filter"] = int(round(max(0.0, time.perf_counter() - t_filter0) * 1000.0))

        _set_stage("merge", "Merging results for web", 85)
        t_merge0 = time.perf_counter()
        result = _merge_for_web(
            token_pairs,
            include_chains=include_chains,
            min_fee_pct=req.min_fee_pct,
            max_fee_pct=req.max_fee_pct,
            min_apy_pct=req.min_apy_pct,
            min_tvl=req.min_tvl,
            days=req.days,
            lp_allocation_usd=float(env.get("LP_ALLOCATION_USD", "1000") or 1000.0),
            exclude_suffixes=req.exclude_suffixes,
            merged_override=merged_raw,
        )
        try:
            if int(result.get("total") or 0) <= 0:
                sg_hint = _diagnose_subgraph_from_logs(logs)
                if sg_hint:
                    logs.append("[subgraph_diag] " + sg_hint)
                    rf = dict(result.get("result_flags") or {})
                    rf["empty_due_to_subgraph"] = True
                    rf["subgraph_user_hint"] = sg_hint
                    result["result_flags"] = rf
        except Exception:
            pass
        timing_debug["stage_ms"]["merge_for_web"] = int(round(max(0.0, time.perf_counter() - t_merge0) * 1000.0))
        timing_debug["stage_ms"]["merged_rows"] = int(len(result.get("rows") or []))
        timing_debug["stage_ms"]["merged_series"] = int(len(result.get("series") or []))
        timing_debug["total_ms"] = int(round(max(0.0, time.perf_counter() - job_t0) * 1000.0))
        if timing_debug["pairs"]:
            slow_pair = max(
                timing_debug["pairs"],
                key=lambda x: int((x or {}).get("total_ms") or 0),
            )
            logs.append(
                "[timing] slowest_pair="
                f"{str((slow_pair or {}).get('pair') or '')} "
                f"{int((slow_pair or {}).get('total_ms') or 0)}ms"
            )
        stage_ms = timing_debug.get("stage_ms") or {}
        if isinstance(stage_ms, dict):
            slow_stage = max(stage_ms.items(), key=lambda kv: int(kv[1] or 0)) if stage_ms else ("", 0)
            logs.append(f"[timing] slowest_stage={str(slow_stage[0])} {int(slow_stage[1] or 0)}ms")
        result_payload = _json_safe({
            "request": {
                "pairs": token_pairs,
                "days": req.days,
                "min_tvl": req.min_tvl,
                "include_chains": include_chains,
                "include_versions": include_versions,
                "speed_mode": speed_mode,
                "run_mode": run_mode,
                "min_fee_pct": req.min_fee_pct,
                "max_fee_pct": req.max_fee_pct,
                "min_apy_pct": req.min_apy_pct,
                "exclude_suffixes": req.exclude_suffixes,
                "lp_allocation_usd": float(env.get("LP_ALLOCATION_USD", "1000")),
                "ignore_cache": bool(getattr(req, "ignore_cache", False)),
                "mode_fast_legacy": mode_fast_legacy,
            },
            **result,
            "debug_timing": timing_debug,
            "logs": logs[-24:],
        })
        with JOB_LOCK:
            job["status"] = "done"
            job["stage"] = "done"
            job["stage_label"] = "Completed"
            job["progress"] = 100
            job["result"] = result_payload
            _job_snapshot_save(job)
        if not bool(getattr(req, "ignore_cache", False)):
            _run_result_cache_put(_pool_run_cache_key(req), result_payload)
        _push_run_history(
            session_id=session_id,
            status="done",
            token_pairs=token_pairs,
            include_chains=include_chains,
            min_tvl=req.min_tvl,
            days=req.days,
            include_versions=include_versions,
            speed_mode=speed_mode,
            min_fee_pct=req.min_fee_pct,
            max_fee_pct=req.max_fee_pct,
            min_apy_pct=req.min_apy_pct,
            exclude_suffixes=req.exclude_suffixes,
            logs=logs,
        )
    except Exception as e:
        timing_debug["total_ms"] = int(round(max(0.0, time.perf_counter() - job_t0) * 1000.0))
        with JOB_LOCK:
            job["status"] = "failed"
            job["error"] = str(e)
            job["stage"] = "failed"
            job["stage_label"] = "Failed"
            job["progress"] = 100
            job["result"] = {"logs": logs[-8:], "debug_timing": timing_debug}
            _job_snapshot_save(job)
        _push_run_history(
            session_id=session_id,
            status="failed",
            token_pairs=token_pairs,
            include_chains=include_chains,
            min_tvl=req.min_tvl,
            days=req.days,
            include_versions=include_versions,
            speed_mode=speed_mode,
            min_fee_pct=req.min_fee_pct,
            max_fee_pct=req.max_fee_pct,
            min_apy_pct=req.min_apy_pct,
            exclude_suffixes=req.exclude_suffixes,
            logs=logs,
            error=str(e),
        )
    finally:
        with JOB_LOCK:
            job["finished_at"] = time.time()
            _job_snapshot_save(job)


def _riko_default_whitelist_symbols() -> list[str]:
    """
    Default seed: top-20 coins + top-20 fiat-backed stablecoins from pair-lists catalog.
    """
    pl = _load_pair_lists_catalog(refresh=False)
    coins = _normalize_symbol_list((pl.get("coins") or [])[:20] if isinstance(pl.get("coins"), list) else [])
    stables = _normalize_symbol_list((pl.get("stablecoins") or [])[:20] if isinstance(pl.get("stablecoins"), list) else [])
    out: list[str] = []
    seen: set[str] = set()
    for s in coins + stables:
        if s not in seen:
            seen.add(s)
            out.append(s)
    return out


def _riko_resolve_symbol_addresses(symbol: str) -> list[str]:
    """
    Resolve ethereum token addresses for symbol from config/token catalog.
    """
    sym = str(symbol or "").strip().lower()
    if not _is_clean_symbol(sym):
        return []
    # Native ETH has no ERC20 token contract address.
    if sym == "eth":
        return []
    addrs: list[str] = []
    # Ethereum fallbacks for major symbols that may be absent in TOKEN_ADDRESSES/token-catalog.
    # Keep lowercase to match _is_eth_address checks.
    eth_fallback: dict[str, str] = {
        "weth": "0xc02aaa39b223fe8d0a0e5c4f27ead9083c756cc2",
        "link": "0x514910771af9ca656af840dff83e8264ecf986ca",
        "bnb": "0xb8c77482e45f1f44de1745f52c74426c631bdd52",
        "aave": "0x7fc66500c84a76ad7e9c93437bfc5ac33e2ddae9",
        "steth": "0xae7ab96520de3a18e5e111b5eaab095312d7fe84",
        "wsteth": "0x7f39c581f595b53c5cb19bd0b3f8da6c935e2ca0",
        "weeth": "0xcd5fe23c85820f7b72d0926fc9b05b43e359b7ee",
        "arb": "0xb50721bcf8d664c30412cfbc6cf7a15145234ad1",
        "avax": "0x85f138bfee4ef8e540890cfb48f620571d67eda3",
    }
    eth_cfg = TOKEN_ADDRESSES.get("ethereum", {}) if isinstance(TOKEN_ADDRESSES.get("ethereum"), dict) else {}
    direct = str(eth_cfg.get(sym) or "").strip().lower()
    if _is_eth_address(direct):
        addrs.append(direct)
    fb = str(eth_fallback.get(sym) or "").strip().lower()
    if _is_eth_address(fb) and fb not in addrs:
        addrs.append(fb)
    tok_catalog = _load_token_catalog(refresh=False)
    by_chain = tok_catalog.get("by_chain") if isinstance(tok_catalog.get("by_chain"), dict) else {}
    eth_map = by_chain.get("ethereum") if isinstance(by_chain.get("ethereum"), dict) else {}
    for addr, token_sym in (eth_map or {}).items():
        if str(token_sym or "").strip().lower() != sym:
            continue
        a = str(addr or "").strip().lower()
        if _is_eth_address(a) and a not in addrs:
            addrs.append(a)
    return addrs


def _normalize_riko_whitelist_items(items: Any) -> list[dict[str, Any]]:
    out: list[dict[str, Any]] = []
    seen: set[str] = set()
    if not isinstance(items, list):
        return out
    for raw in items:
        if not isinstance(raw, dict):
            continue
        sym = str(raw.get("symbol") or "").strip().lower()
        if not _is_clean_symbol(sym):
            continue
        if sym in seen:
            continue
        seen.add(sym)
        addr = str(raw.get("address") or "").strip().lower()
        keep_on_vault_raw = raw.get("keep_on_vault")
        keep_on_vault = False
        if isinstance(keep_on_vault_raw, bool):
            keep_on_vault = keep_on_vault_raw
        elif isinstance(keep_on_vault_raw, (int, float)):
            keep_on_vault = bool(int(keep_on_vault_raw))
        else:
            keep_on_vault = str(keep_on_vault_raw or "").strip().lower() in {"1", "true", "yes", "on"}
        out.append({"symbol": sym, "address": addr, "keep_on_vault": bool(keep_on_vault)})
    return out


def _riko_default_whitelist_items() -> list[dict[str, Any]]:
    items: list[dict[str, Any]] = []
    for s in _riko_default_whitelist_symbols():
        addrs = _riko_resolve_symbol_addresses(s)
        items.append({"symbol": s, "address": str(addrs[0] if addrs else "").strip().lower(), "keep_on_vault": False})
    return items


def _riko_items_from_symbols(symbols: list[str]) -> list[dict[str, Any]]:
    out: list[dict[str, Any]] = []
    for s in _normalize_symbol_list(symbols or []):
        addrs = _riko_resolve_symbol_addresses(s)
        out.append({"symbol": s, "address": str(addrs[0] if addrs else "").strip().lower(), "keep_on_vault": False})
    return out


def _riko_pending_digest(items: list[dict[str, Any]]) -> str:
    clean = _normalize_riko_whitelist_items(items or [])
    blob = json.dumps(clean, ensure_ascii=True, sort_keys=True, separators=(",", ":"))
    return hashlib.sha256(blob.encode("utf-8")).hexdigest()


def _riko_apply_message(
    *,
    domain: str,
    uri: str,
    address: str,
    nonce: str,
    pending_hash: str,
    issued_at: str,
) -> str:
    return (
        f"{domain} wants you to sign an admin action with your Ethereum account:\n"
        f"{address}\n\n"
        "Confirm apply of RIKO whitelist pending draft.\n\n"
        f"URI: {uri}\n"
        "Version: 1\n"
        f"Nonce: {nonce}\n"
        f"Pending Hash: {pending_hash}\n"
        f"Issued At: {issued_at}"
    )


def _riko_auto_payout_apply_digest(
    *,
    payout_token_address: str,
    holder_scan_start_block: int,
    items: list[dict[str, int]],
    payout_time_utc: str,
    calc_method: str,
) -> str:
    clean_items: list[dict[str, int]] = []
    for raw in (items or []):
        month = int(raw.get("month") or 0)
        day = int(raw.get("day") or 0)
        clean_items.append({"month": month, "day": day})
    clean_items.sort(key=lambda it: (int(it.get("month") or 0), int(it.get("day") or 0)))
    payload = {
        "payout_token_address": str(payout_token_address or "").strip().lower(),
        "holder_scan_start_block": max(0, int(holder_scan_start_block or 0)),
        "items": clean_items,
        "payout_time_utc": str(payout_time_utc or "").strip(),
        "calc_method": _normalize_riko_payout_calc_method(calc_method),
    }
    blob = json.dumps(payload, ensure_ascii=True, sort_keys=True, separators=(",", ":"))
    return hashlib.sha256(blob.encode("utf-8")).hexdigest()


def _normalize_riko_payout_calc_method(raw: Any) -> str:
    txt = str(raw or "").strip().lower()
    if txt in {"treasury", "treasury_10y", "us_treasury_10y"}:
        return "treasury_10y"
    return "treasury_10y"


def _riko_payout_rate_snapshot(calc_method: str) -> dict[str, Any]:
    method = _normalize_riko_payout_calc_method(calc_method)
    if method == "treasury_10y":
        try:
            y = _fetch_us_treasury_daily_10y()
            annual_pct = float(y.get("annual_pct") or 0.0)
            monthly_pct = float(annual_pct) / 12.0
            raw_target_bps = float(monthly_pct) * 100.0
            target_bps = int(round(raw_target_bps))
            next_bps = max(int(RIKO_AUTO_YIELD_MIN_BPS), min(int(RIKO_AUTO_YIELD_MAX_BPS), int(target_bps)))
            return {
                "calc_method": method,
                "calc_method_label": "Treasury 10Y",
                "rate_source": "us_treasury_10y",
                "rate_date": str(y.get("date") or ""),
                "annual_pct": float(round(annual_pct, 6)),
                "monthly_pct": float(round(monthly_pct, 8)),
                "target_bps": int(target_bps),
                "next_bps": int(next_bps),
            }
        except Exception:
            return {
                "calc_method": method,
                "calc_method_label": "Treasury 10Y",
                "rate_source": "us_treasury_10y",
                "rate_date": "",
                "annual_pct": 0.0,
                "monthly_pct": 0.0,
                "target_bps": 0,
                "next_bps": 0,
            }
    return {
        "calc_method": method,
        "calc_method_label": method,
        "rate_source": method,
        "rate_date": "",
        "annual_pct": 0.0,
        "monthly_pct": 0.0,
        "target_bps": 0,
        "next_bps": 0,
    }


def _riko_auto_payout_apply_message(
    *,
    domain: str,
    uri: str,
    address: str,
    nonce: str,
    payload_hash: str,
    issued_at: str,
) -> str:
    return (
        f"{domain} wants you to sign an admin action with your Ethereum account:\n"
        f"{address}\n\n"
        "Confirm apply of RIKO auto-payout configuration and schedule.\n\n"
        f"URI: {uri}\n"
        "Version: 1\n"
        f"Nonce: {nonce}\n"
        f"Payload Hash: {payload_hash}\n"
        f"Issued At: {issued_at}"
    )


def _fetch_us_treasury_daily_10y() -> dict[str, Any]:
    def _from_payload(payload: dict[str, Any], *, mark_stale: bool = False) -> dict[str, Any]:
        annual = float(payload.get("annual_pct") or 0.0)
        daily = float(payload.get("daily_pct") or (annual / 365.0 if annual else 0.0))
        out = {
            "source": str(payload.get("source") or "US Treasury Daily Treasury Par Yield Curve Rates (10Y)"),
            "source_url": str(payload.get("source_url") or "https://home.treasury.gov/treasury-daily-interest-rate-xml-feed"),
            "date": str(payload.get("date") or ""),
            "annual_pct": round(float(annual), 4),
            "daily_pct": round(float(daily), 6),
            "cached_at_ts": float(payload.get("cached_at_ts") or 0.0),
        }
        if mark_stale:
            out["stale_fallback"] = True
        return out

    def _load_persisted_snapshot() -> dict[str, Any] | None:
        raw = _analytics_get_state(TREASURY_YIELD_STATE_KEY)
        if not raw:
            return None
        try:
            parsed = json.loads(raw)
            if not isinstance(parsed, dict):
                return None
            out = _from_payload(parsed, mark_stale=True)
            if not str(out.get("date") or "").strip():
                return None
            if float(out.get("annual_pct") or 0.0) <= 0:
                return None
            return out
        except Exception:
            return None

    def _save_persisted_snapshot(snapshot: dict[str, Any]) -> None:
        try:
            payload = {
                "source": str(snapshot.get("source") or ""),
                "source_url": str(snapshot.get("source_url") or ""),
                "date": str(snapshot.get("date") or ""),
                "annual_pct": float(snapshot.get("annual_pct") or 0.0),
                "daily_pct": float(snapshot.get("daily_pct") or 0.0),
                "cached_at_ts": float(snapshot.get("cached_at_ts") or 0.0),
                "saved_at": _iso_now(),
            }
            _analytics_set_state(TREASURY_YIELD_STATE_KEY, json.dumps(payload, ensure_ascii=False))
        except Exception:
            pass

    now_ts = float(time.time())
    with TREASURY_YIELD_CACHE_LOCK:
        cached = dict(TREASURY_YIELD_CACHE)
    cached_at = float(cached.get("cached_at_ts") or 0)
    if cached and cached_at > 0 and (now_ts - cached_at) < float(TREASURY_YIELD_CACHE_TTL_SEC):
        return cached

    fetch_err: Exception | None = None
    for year in [datetime.now(timezone.utc).year, datetime.now(timezone.utc).year - 1]:
        try:
            url = (
                "https://home.treasury.gov/resource-center/data-chart-center/interest-rates/pages/xml"
                f"?data=daily_treasury_yield_curve&field_tdr_date_value={int(year)}"
            )
            req = UrlRequest(url, method="GET", headers={"User-Agent": "uni_fee/1.0"})
            with urlopen(req, timeout=18) as resp:
                raw = resp.read()
            root = ET.fromstring(raw)
            ns = {
                "atom": "http://www.w3.org/2005/Atom",
                "d": "http://schemas.microsoft.com/ado/2007/08/dataservices",
                "m": "http://schemas.microsoft.com/ado/2007/08/dataservices/metadata",
            }
            rows: list[tuple[str, float]] = []
            for entry in root.findall("atom:entry", ns):
                props = entry.find("atom:content/m:properties", ns)
                if props is None:
                    continue
                date_el = props.find("d:NEW_DATE", ns)
                y10_el = props.find("d:BC_10YEAR", ns)
                if date_el is None or y10_el is None:
                    continue
                date_s = str(date_el.text or "").strip()
                y10_s = str(y10_el.text or "").strip()
                if not date_s or not y10_s:
                    continue
                try:
                    y10 = float(y10_s)
                except Exception:
                    continue
                rows.append((date_s, y10))
            if not rows:
                continue
            rows.sort(key=lambda x: x[0])
            latest_date, annual_pct = rows[-1]
            daily_pct = float(annual_pct) / 365.0
            out = {
                "source": "US Treasury Daily Treasury Par Yield Curve Rates (10Y)",
                "source_url": "https://home.treasury.gov/treasury-daily-interest-rate-xml-feed",
                "date": latest_date.split("T")[0],
                "annual_pct": round(float(annual_pct), 4),
                "daily_pct": round(float(daily_pct), 6),
                "cached_at_ts": now_ts,
            }
            with TREASURY_YIELD_CACHE_LOCK:
                TREASURY_YIELD_CACHE.clear()
                TREASURY_YIELD_CACHE.update(out)
            _save_persisted_snapshot(out)
            return out
        except Exception as e:
            fetch_err = e
            continue

    if cached and float(cached.get("annual_pct") or 0.0) > 0:
        stale_mem = _from_payload(cached, mark_stale=True)
        with TREASURY_YIELD_CACHE_LOCK:
            TREASURY_YIELD_CACHE.clear()
            TREASURY_YIELD_CACHE.update(stale_mem)
        return stale_mem

    persisted = _load_persisted_snapshot()
    if persisted:
        with TREASURY_YIELD_CACHE_LOCK:
            TREASURY_YIELD_CACHE.clear()
            TREASURY_YIELD_CACHE.update(persisted)
        return persisted

    if fetch_err is not None:
        raise fetch_err
    raise RuntimeError("Treasury feed returned no usable 10Y points.")


def _riko_auto_yield_load_state() -> dict[str, Any]:
    raw = _analytics_get_state(RIKO_AUTO_YIELD_STATE_KEY)
    if not raw:
        return {}
    try:
        payload = json.loads(raw)
        if isinstance(payload, dict):
            return dict(payload)
    except Exception:
        return {}
    return {}


def _riko_auto_yield_save_state(state: dict[str, Any]) -> None:
    if not isinstance(state, dict):
        return
    prev = _riko_auto_yield_load_state()
    clean = dict(state)
    for k in ("applied_month", "applied_schedule_date"):
        if k not in clean and prev.get(k):
            clean[k] = prev.get(k)
    clean["updated_at"] = _iso_now()
    _analytics_set_state(RIKO_AUTO_YIELD_STATE_KEY, json.dumps(clean, ensure_ascii=False))


def _riko_auto_yield_load_reminders_state() -> dict[str, Any]:
    raw = _analytics_get_state(RIKO_AUTO_YIELD_REMINDERS_STATE_KEY)
    if not raw:
        return {"sent": {}}
    try:
        payload = json.loads(raw)
        if isinstance(payload, dict):
            sent = payload.get("sent")
            if isinstance(sent, dict):
                return {"sent": dict(sent)}
    except Exception:
        pass
    return {"sent": {}}


def _riko_auto_yield_save_reminders_state(state: dict[str, Any]) -> None:
    payload = state if isinstance(state, dict) else {"sent": {}}
    sent = payload.get("sent")
    if not isinstance(sent, dict):
        sent = {}
    keys = sorted([str(k) for k in sent.keys() if str(k).strip()], reverse=True)[:64]
    trimmed = {k: sent.get(k) for k in keys}
    _analytics_set_state(
        RIKO_AUTO_YIELD_REMINDERS_STATE_KEY,
        json.dumps({"sent": trimmed}, ensure_ascii=False),
    )


def _load_riko_auto_yield_history(limit: int = 500) -> dict[str, Any]:
    lim = max(1, min(2000, int(limit or 500)))
    rows: list[dict[str, Any]] = []
    raw = _analytics_get_state(RIKO_AUTO_YIELD_HISTORY_STATE_KEY)
    if raw:
        try:
            payload = json.loads(raw)
            if isinstance(payload, dict):
                items = payload.get("items") if isinstance(payload.get("items"), list) else []
                for it in items:
                    if not isinstance(it, dict):
                        continue
                    tx_hash = str(it.get("tx_hash") or "").strip().lower()
                    if not (tx_hash.startswith("0x") and len(tx_hash) == 66):
                        continue
                    rows.append(
                        {
                            "run_ts": str(it.get("run_ts") or ""),
                            "status": str(it.get("status") or ""),
                            "reason": str(it.get("reason") or ""),
                            "schedule_date_key": str(it.get("schedule_date_key") or ""),
                            "payout_token": str(it.get("payout_token") or "").strip().lower(),
                            "payout_count": int(it.get("payout_count") or 0),
                            "total_payout_raw": int(it.get("total_payout_raw") or 0),
                            "payout_decimals": int(it.get("payout_decimals") or 18),
                            "chain_id": int(it.get("chain_id") or 0),
                            "tx_hash": tx_hash,
                        }
                    )
        except Exception:
            pass
    rows.sort(key=lambda x: str(x.get("run_ts") or ""), reverse=True)
    return {"items": rows[:lim], "count": len(rows[:lim])}


def _append_riko_auto_yield_history(result: dict[str, Any]) -> None:
    if not isinstance(result, dict):
        return
    tx_hashes: list[str] = []
    tx_many = result.get("tx_hashes")
    if isinstance(tx_many, list):
        for raw in tx_many:
            h = str(raw or "").strip().lower()
            if h.startswith("0x") and len(h) == 66:
                tx_hashes.append(h)
    if not tx_hashes:
        h_one = str(result.get("tx_hash") or "").strip().lower()
        if h_one.startswith("0x") and len(h_one) == 66:
            tx_hashes.append(h_one)
    if not tx_hashes:
        return
    current = _load_riko_auto_yield_history(limit=2000).get("items")
    existing: list[dict[str, Any]] = current if isinstance(current, list) else []
    run_ts = str(result.get("ts") or _iso_now())
    status = str(result.get("status") or "")
    reason = str(result.get("reason") or "")
    schedule_date_key = str(result.get("schedule_date_key") or "")
    payout_token = str(result.get("payout_token") or "").strip().lower()
    payout_count = int(result.get("payout_count") or 0)
    total_payout_raw = int(result.get("total_payout_raw") or 0)
    payout_decimals = int(result.get("payout_decimals") or 18)
    chain_id = int(result.get("chain_id") or 0)
    for txh in tx_hashes:
        existing.append(
            {
                "run_ts": run_ts,
                "status": status,
                "reason": reason,
                "schedule_date_key": schedule_date_key,
                "payout_token": payout_token,
                "payout_count": payout_count,
                "total_payout_raw": total_payout_raw,
                "payout_decimals": payout_decimals,
                "chain_id": chain_id,
                "tx_hash": txh,
            }
        )
    dedup: dict[str, dict[str, Any]] = {}
    for row in existing:
        txh = str(row.get("tx_hash") or "").strip().lower()
        if txh.startswith("0x") and len(txh) == 66:
            dedup[txh] = row
    rows = list(dedup.values())
    rows.sort(key=lambda x: str(x.get("run_ts") or ""), reverse=True)
    rows = rows[:2000]
    _analytics_set_state(RIKO_AUTO_YIELD_HISTORY_STATE_KEY, json.dumps({"items": rows}, ensure_ascii=False))


def _riko_auto_yield_enabled() -> bool:
    raw = _analytics_get_state(RIKO_AUTO_YIELD_CONTROL_STATE_KEY)
    if raw:
        try:
            parsed = json.loads(raw)
            if isinstance(parsed, dict) and "enabled" in parsed:
                return bool(parsed.get("enabled"))
        except Exception:
            pass
    return bool(RIKO_AUTO_YIELD_ENABLED)


def _riko_auto_yield_control_payload() -> dict[str, Any]:
    raw = _analytics_get_state(RIKO_AUTO_YIELD_CONTROL_STATE_KEY)
    source = "env"
    enabled = bool(RIKO_AUTO_YIELD_ENABLED)
    if raw:
        try:
            parsed = json.loads(raw)
            if isinstance(parsed, dict) and "enabled" in parsed:
                enabled = bool(parsed.get("enabled"))
                source = "admin_override"
        except Exception:
            pass
    return {"enabled": bool(enabled), "source": source}


def _set_riko_auto_yield_enabled(enabled: bool) -> dict[str, Any]:
    payload = {"enabled": bool(enabled), "updated_at": _iso_now()}
    _analytics_set_state(RIKO_AUTO_YIELD_CONTROL_STATE_KEY, json.dumps(payload, ensure_ascii=False))
    if bool(enabled):
        _start_riko_auto_yield_job()
    else:
        _stop_riko_auto_yield_job()
    return _riko_auto_yield_control_payload()


def _load_riko_auto_yield_bot_config() -> dict[str, Any]:
    # Payout token is configured only via admin panel.
    # Do not read or fallback to env token.
    payout_token_address = ""
    holder_scan_start_block = 0
    source = "admin_override"
    raw = _analytics_get_state(RIKO_AUTO_YIELD_BOT_CONFIG_STATE_KEY)
    updated_at = ""
    if raw:
        try:
            parsed = json.loads(raw)
            if isinstance(parsed, dict):
                token_raw = str(parsed.get("payout_token_address") or "").strip().lower()
                # Accept only valid admin-selected token value.
                if _is_eth_address(token_raw):
                    payout_token_address = token_raw
                else:
                    payout_token_address = ""
                # RIKO holder scan always starts from block 0 by design.
                holder_scan_start_block = 0
                updated_at = str(parsed.get("updated_at") or "")
                source = "admin_override"
        except Exception:
            pass
    return {
        "payout_token_address": payout_token_address,
        "holder_scan_start_block": int(holder_scan_start_block),
        "source": source,
        "updated_at": updated_at,
    }


def _save_riko_auto_yield_bot_config(payout_token_address: str, holder_scan_start_block: int) -> dict[str, Any]:
    token = str(payout_token_address or "").strip().lower()
    if token and (not _is_eth_address(token)):
        raise ValueError("payout token address must be a valid 0x address")
    if token:
        allowed_erc20 = _riko_active_whitelist_erc20_addresses()
        if token not in allowed_erc20:
            raise ValueError("payout token must be from active RIKO whitelist (ERC-20 only)")
    payload = {
        "payout_token_address": token,
        # Kept in payload for backward compatibility, always pinned to zero.
        "holder_scan_start_block": 0,
        "updated_at": _iso_now(),
    }
    _analytics_set_state(RIKO_AUTO_YIELD_BOT_CONFIG_STATE_KEY, json.dumps(payload, ensure_ascii=False))
    return _load_riko_auto_yield_bot_config()


def _riko_active_whitelist_erc20_addresses() -> set[str]:
    active_items = _load_riko_whitelist_items()
    active_validation = _validate_riko_whitelist_items(active_items)
    out: set[str] = set()
    for it in (active_validation.get("items") if isinstance(active_validation.get("items"), list) else []):
        addr = str(it.get("address") or "").strip().lower()
        if _is_eth_address(addr):
            out.add(addr)
    return out


def _normalize_riko_custody_allowance_text(raw: Any) -> str:
    txt = str(raw or "").strip()
    if not txt:
        return ""
    if txt.lower() in {"max", "unlimited", "infinite"}:
        return "max"
    if not re.fullmatch(r"\d+(?:\.\d{1,36})?", txt):
        raise ValueError("allowance must be a positive decimal number or 'max'")
    try:
        if Decimal(txt) <= 0:
            raise ValueError("allowance must be > 0")
    except Exception as e:
        raise ValueError(f"allowance parse failed: {e}") from e
    return txt


def _load_riko_custody_allowance_presets() -> dict[str, Any]:
    saved_map: dict[str, str] = {}
    updated_at = ""
    raw = _analytics_get_state(RIKO_CUSTODY_ALLOWANCE_PRESETS_STATE_KEY)
    if raw:
        try:
            payload = json.loads(raw)
            if isinstance(payload, dict):
                updated_at = str(payload.get("updated_at") or "")
                saved_items = payload.get("items") if isinstance(payload.get("items"), list) else []
                for it in saved_items:
                    if not isinstance(it, dict):
                        continue
                    addr = str(it.get("address") or "").strip().lower()
                    if not _is_eth_address(addr):
                        continue
                    try:
                        saved_map[addr] = _normalize_riko_custody_allowance_text(it.get("allowance"))
                    except Exception:
                        continue
        except Exception:
            pass
    active_items = _validate_riko_whitelist_items(_load_riko_whitelist_items()).get("items")
    out: list[dict[str, str]] = []
    seen: set[str] = set()
    if isinstance(active_items, list):
        for raw_it in active_items:
            if not isinstance(raw_it, dict):
                continue
            symbol = str(raw_it.get("symbol") or "").strip().lower()
            address = str(raw_it.get("address") or "").strip().lower()
            if not _is_eth_address(address):
                continue
            if address in seen:
                continue
            seen.add(address)
            out.append(
                {
                    "symbol": symbol,
                    "address": address,
                    "allowance": str(saved_map.get(address) or ""),
                }
            )
    out.sort(key=lambda x: (str(x.get("symbol") or ""), str(x.get("address") or "")))
    return {"items": out, "updated_at": updated_at}


def _save_riko_custody_allowance_presets(items: list[dict[str, Any]]) -> dict[str, Any]:
    allowed = _riko_active_whitelist_erc20_addresses()
    by_addr: dict[str, dict[str, str]] = {}
    for raw in (items or []):
        if not isinstance(raw, dict):
            continue
        symbol = str(raw.get("symbol") or "").strip().lower()
        address = str(raw.get("address") or "").strip().lower()
        if not _is_eth_address(address):
            raise ValueError(f"invalid token address: {address or '-'}")
        if address not in allowed:
            raise ValueError(f"token {address} is not in active RIKO whitelist (ERC-20)")
        allowance = _normalize_riko_custody_allowance_text(raw.get("allowance"))
        by_addr[address] = {"symbol": symbol, "address": address, "allowance": allowance}
    persist_rows: list[dict[str, str]] = []
    for row in sorted(by_addr.values(), key=lambda x: (str(x.get("symbol") or ""), str(x.get("address") or ""))):
        if not str(row.get("allowance") or "").strip():
            continue
        persist_rows.append({"address": str(row.get("address") or ""), "allowance": str(row.get("allowance") or "")})
    payload = {"items": persist_rows, "updated_at": _iso_now()}
    _analytics_set_state(RIKO_CUSTODY_ALLOWANCE_PRESETS_STATE_KEY, json.dumps(payload, ensure_ascii=False))
    return _load_riko_custody_allowance_presets()


