def _riko_is_valid_month_day(month: int, day: int) -> bool:
    if month < 1 or month > 12 or day < 1 or day > 31:
        return False
    try:
        date(2025, month, day)
        return True
    except Exception:
        try:
            # Allow Feb 29 in leap years.
            date(2024, month, day)
            return True
        except Exception:
            return False


def _normalize_riko_payout_time_utc(raw_value: Any) -> tuple[int, int, str]:
    raw = str(raw_value or "").strip()
    m = re.fullmatch(r"([01]?\d|2[0-3]):([0-5]\d)", raw)
    if not m:
        return 0, 0, "00:00"
    hour = int(m.group(1))
    minute = int(m.group(2))
    return hour, minute, f"{hour:02d}:{minute:02d}"


def _normalize_riko_payout_schedule_items(items: Any) -> list[dict[str, int]]:
    out: list[dict[str, int]] = []
    seen: set[tuple[int, int]] = set()
    if not isinstance(items, list):
        return out
    for raw in items:
        if not isinstance(raw, dict):
            continue
        try:
            month = int(raw.get("month"))
            day = int(raw.get("day"))
        except Exception:
            continue
        if not _riko_is_valid_month_day(month, day):
            continue
        key = (month, day)
        if key in seen:
            continue
        seen.add(key)
        out.append({"month": int(month), "day": int(day)})
    out.sort(key=lambda x: (int(x.get("month") or 0), int(x.get("day") or 0)))
    return out


def _riko_next_schedule_datetime(
    items: list[dict[str, int]], payout_hour_utc: int, payout_minute_utc: int, now_utc: datetime | None = None
) -> datetime | None:
    clean = _normalize_riko_payout_schedule_items(items)
    now_dt = now_utc if isinstance(now_utc, datetime) else datetime.now(timezone.utc)
    if clean:
        today = now_dt.date()
        for year_offset in range(0, 9):
            y = int(today.year) + int(year_offset)
            for item in clean:
                try:
                    candidate_date = date(y, int(item["month"]), int(item["day"]))
                except Exception:
                    continue
                candidate_dt = datetime(
                    candidate_date.year,
                    candidate_date.month,
                    candidate_date.day,
                    int(payout_hour_utc),
                    int(payout_minute_utc),
                    0,
                    tzinfo=timezone.utc,
                )
                if candidate_dt >= now_dt:
                    return candidate_dt
    else:
        # Fallback mode (no explicit dates): first day of each month at configured UTC time.
        first_this_month = datetime(now_dt.year, now_dt.month, 1, int(payout_hour_utc), int(payout_minute_utc), tzinfo=timezone.utc)
        if first_this_month >= now_dt:
            return first_this_month
        next_month_start = (date(now_dt.year, now_dt.month, 1) + timedelta(days=32)).replace(day=1)
        return datetime(
            next_month_start.year,
            next_month_start.month,
            1,
            int(payout_hour_utc),
            int(payout_minute_utc),
            0,
            tzinfo=timezone.utc,
        )
    return None


def _load_riko_payout_schedule() -> dict[str, Any]:
    raw_text = _analytics_get_state(RIKO_PAYOUT_SCHEDULE_STATE_KEY)
    raw: dict[str, Any] = {}
    if raw_text:
        try:
            parsed = json.loads(raw_text)
            if isinstance(parsed, dict):
                raw = parsed
        except Exception:
            raw = {}
    items = _normalize_riko_payout_schedule_items(raw.get("items"))
    payout_hour_utc, payout_minute_utc, payout_time_utc = _normalize_riko_payout_time_utc(raw.get("payout_time_utc"))
    calc_method = _normalize_riko_payout_calc_method(raw.get("calc_method"))
    rate = _riko_payout_rate_snapshot(calc_method)
    next_due_at = _riko_next_schedule_datetime(items, payout_hour_utc, payout_minute_utc)
    return {
        "items": items,
        "count": int(len(items)),
        "payout_time_utc": payout_time_utc,
        "calc_method": calc_method,
        "payout_hour_utc": int(payout_hour_utc),
        "payout_minute_utc": int(payout_minute_utc),
        "next_due_date": next_due_at.date().isoformat() if isinstance(next_due_at, datetime) else "",
        "next_due_at_utc": next_due_at.strftime("%Y-%m-%d %H:%M UTC") if isinstance(next_due_at, datetime) else "",
        "next_rate_label": str(rate.get("calc_method_label") or ""),
        "next_rate_source": str(rate.get("rate_source") or ""),
        "next_rate_date": str(rate.get("rate_date") or ""),
        "next_rate_annual_pct": float(rate.get("annual_pct") or 0.0),
        "next_rate_monthly_pct": float(rate.get("monthly_pct") or 0.0),
        "next_rate_target_bps": int(rate.get("target_bps") or 0),
        "next_rate_bps": int(rate.get("next_bps") or 0),
        "updated_at": str(raw.get("updated_at") or ""),
    }


def _save_riko_payout_schedule(
    items: list[dict[str, Any]], payout_time_utc: str | None = None, calc_method: str | None = None
) -> dict[str, Any]:
    clean_items = _normalize_riko_payout_schedule_items(items)
    cur = _load_riko_payout_schedule()
    raw_time = str(payout_time_utc or "").strip() or str(cur.get("payout_time_utc") or "00:00")
    _, _, norm_time = _normalize_riko_payout_time_utc(raw_time)
    method = _normalize_riko_payout_calc_method(calc_method or cur.get("calc_method"))
    payload = {
        "items": clean_items,
        "payout_time_utc": norm_time,
        "calc_method": method,
        "updated_at": _iso_now(),
    }
    _analytics_set_state(RIKO_PAYOUT_SCHEDULE_STATE_KEY, json.dumps(payload, ensure_ascii=False))
    return _load_riko_payout_schedule()


def _eth_fn_selector(signature: str) -> str:
    raw = keccak(text=str(signature or ""))[:4]
    return "0x" + raw.hex()


def _eth_encode_call(signature: str, arg_types: list[str] | None = None, args: list[Any] | None = None) -> str:
    selector = _eth_fn_selector(signature)
    if not arg_types:
        return selector
    encoded = abi_encode(arg_types, args or [])
    return selector + encoded.hex()


def _normalize_rpc_url(raw_url: str) -> str:
    raw = str(raw_url or "").strip()
    if (raw.startswith('"') and raw.endswith('"')) or (raw.startswith("'") and raw.endswith("'")):
        raw = raw[1:-1].strip()
    # Extract first URL-like token to guard accidental tails: ".../v2/<key> Ready"
    m = re.search(r"https?://[^\s\"'<>]+", raw, flags=re.IGNORECASE)
    if m:
        raw = str(m.group(0) or "").strip()
    if any(ch.isspace() for ch in raw):
        raw = raw.split()[0].strip()
    # Trim accidental trailing punctuation from copy/paste.
    raw = raw.rstrip(".,;")
    return raw


def _rpc_url_label(raw_url: str) -> str:
    rpc = _normalize_rpc_url(raw_url)
    if not rpc:
        return "missing_rpc_url"
    try:
        p = urlparse(rpc)
    except Exception:
        return "invalid_rpc_url"
    scheme = str(p.scheme or "https")
    host = str(p.netloc or "")
    path = str(p.path or "")
    # Hide API keys in /v2/<key> style paths.
    if path.startswith("/v2/"):
        key = path[4:].strip("/")
        if key:
            if len(key) <= 8:
                key_mask = "***"
            else:
                key_mask = f"{key[:4]}...{key[-4:]}"
            path = f"/v2/{key_mask}"
        else:
            path = "/v2/"
    return f"{scheme}://{host}{path}"


def _riko_auto_yield_rpc_url_runtime() -> str:
    # Prefer live env over module-level constant to avoid stale values after local edits/restarts.
    raw = str(os.environ.get("RIKO_AUTO_YIELD_RPC_URL", "") or RIKO_AUTO_YIELD_RPC_URL or "").strip()
    return _normalize_rpc_url(raw)


def _riko_auto_yield_private_key_runtime() -> str:
    return str(os.environ.get("RIKO_AUTO_YIELD_PRIVATE_KEY", "") or RIKO_AUTO_YIELD_PRIVATE_KEY or "").strip()


def _eth_rpc(rpc_url: str, method: str, params: list[Any]) -> Any:
    rpc = _normalize_rpc_url(rpc_url)
    if not rpc or not rpc.lower().startswith(("http://", "https://")):
        raise RuntimeError("rpc url is invalid or missing")
    is_logs_method = str(method or "").strip().lower() == "eth_getlogs"
    max_attempts = 8 if is_logs_method else 5
    base_backoff_sec = 1.0 if is_logs_method else 0.25
    for attempt in range(max_attempts):
        req_payload = json.dumps(
            {"jsonrpc": "2.0", "id": int(time.time() * 1000) % 1_000_000_000, "method": method, "params": params or []}
        ).encode("utf-8")
        req = UrlRequest(
            rpc,
            data=req_payload,
            method="POST",
            headers={"Content-Type": "application/json", "User-Agent": APP_USER_AGENT},
        )
        try:
            with urlopen(req, timeout=20) as resp:
                body = resp.read().decode("utf-8", errors="ignore")
        except HTTPError as e:
            body = ""
            with contextlib.suppress(Exception):
                body = (e.read() or b"").decode("utf-8", errors="ignore")
            body_one_line = re.sub(r"\s+", " ", str(body or "").strip())
            body_hint = body_one_line[:220] if body_one_line else ""
            hint_l = body_hint.lower()
            http_code = int(getattr(e, "code", 0) or 0)
            is_rate_limited = (
                http_code == 429
                or "rate limit" in hint_l
                or "too many requests" in hint_l
                or "compute units per second" in hint_l
            )
            if is_rate_limited and attempt < (max_attempts - 1):
                retry_after_sec = 0.0
                with contextlib.suppress(Exception):
                    retry_after_sec = float(str(getattr(e, "headers", {}).get("Retry-After", "0")).strip() or 0)
                sleep_sec = retry_after_sec if retry_after_sec > 0 else min(
                    12.0 if is_logs_method else 4.0,
                    float(base_backoff_sec) * (2 ** attempt),
                )
                time.sleep(sleep_sec)
                continue
            suffix = f": {body_hint}" if body_hint else ""
            raise RuntimeError(
                f"rpc {method} http {http_code} at {_rpc_url_label(rpc)}{suffix}"
            ) from e

        payload = json.loads(body) if body else {}
        if not isinstance(payload, dict):
            raise RuntimeError(f"rpc invalid response for {method}")
        if payload.get("error"):
            err = payload.get("error")
            err_code = None
            err_msg = ""
            if isinstance(err, dict):
                err_code = err.get("code")
                err_msg = str(err.get("message") or "")
            err_text_l = str(err_msg or err).lower()
            is_rate_limited = (
                str(err_code) == "429"
                or "rate limit" in err_text_l
                or "too many requests" in err_text_l
                or "compute units per second" in err_text_l
            )
            if is_rate_limited and attempt < (max_attempts - 1):
                sleep_sec = min(
                    12.0 if is_logs_method else 4.0,
                    float(base_backoff_sec) * (2 ** attempt),
                )
                time.sleep(sleep_sec)
                continue
            raise RuntimeError(f"rpc {method} error: {err}")
        return payload.get("result")
    raise RuntimeError(f"rpc {method} failed after retries")


def _eth_hex_to_int(value: Any) -> int:
    s = str(value or "").strip().lower()
    if not s:
        return 0
    if s.startswith("0x"):
        try:
            return int(s, 16)
        except Exception:
            return 0
    try:
        return int(s)
    except Exception:
        return 0


def _eth_decode_uint256(result_hex: Any) -> int:
    return _eth_hex_to_int(result_hex)


def _eth_decode_address(result_hex: Any) -> str:
    raw = str(result_hex or "").strip().lower()
    if raw.startswith("0x"):
        raw = raw[2:]
    if len(raw) < 40:
        return ""
    addr = "0x" + raw[-40:]
    return addr if _is_eth_address(addr) else ""


def _eth_topic_to_address(topic_hex: str) -> str:
    raw = str(topic_hex or "").strip().lower()
    if raw.startswith("0x"):
        raw = raw[2:]
    if len(raw) != 64:
        return ""
    return _eth_decode_address("0x" + raw)


def _eth_to_hex_block(block_number: int) -> str:
    return hex(max(0, int(block_number)))


def _riko_auto_yield_load_holder_cache() -> dict[str, Any]:
    raw = _analytics_get_state(RIKO_AUTO_YIELD_HOLDER_CACHE_STATE_KEY)
    if not raw:
        return {"holders": [], "last_scanned_block": 0, "chain_id": 0, "riko_token": ""}
    try:
        payload = json.loads(raw)
        if not isinstance(payload, dict):
            return {"holders": [], "last_scanned_block": 0, "chain_id": 0, "riko_token": ""}
        holders_raw = payload.get("holders")
        holders: list[str] = []
        if isinstance(holders_raw, list):
            seen: set[str] = set()
            for item in holders_raw:
                a = str(item or "").strip().lower()
                if _is_eth_address(a) and a not in seen:
                    seen.add(a)
                    holders.append(a)
        last_scanned_block = max(0, int(payload.get("last_scanned_block") or 0))
        chain_id = max(0, int(payload.get("chain_id") or 0))
        riko_token = str(payload.get("riko_token") or "").strip().lower()
        if not _is_eth_address(riko_token):
            riko_token = ""
        return {
            "holders": holders,
            "last_scanned_block": last_scanned_block,
            "chain_id": chain_id,
            "riko_token": riko_token,
        }
    except Exception:
        return {"holders": [], "last_scanned_block": 0, "chain_id": 0, "riko_token": ""}


def _riko_auto_yield_save_holder_cache(
    holders: list[str],
    last_scanned_block: int,
    *,
    chain_id: int = 0,
    riko_token: str = "",
) -> None:
    clean_holders: list[str] = []
    seen: set[str] = set()
    for item in holders or []:
        a = str(item or "").strip().lower()
        if not _is_eth_address(a) or a in seen:
            continue
        seen.add(a)
        clean_holders.append(a)
    payload = {
        "holders": clean_holders,
        "last_scanned_block": max(0, int(last_scanned_block or 0)),
        "chain_id": max(0, int(chain_id or 0)),
        "riko_token": str(riko_token or "").strip().lower() if _is_eth_address(str(riko_token or "").strip().lower()) else "",
        "updated_at": _iso_now(),
    }
    _analytics_set_state(RIKO_AUTO_YIELD_HOLDER_CACHE_STATE_KEY, json.dumps(payload, ensure_ascii=False))


def _riko_holder_scan_bg_load_status() -> dict[str, Any]:
    raw = _analytics_get_state(RIKO_HOLDER_SCAN_BG_STATUS_STATE_KEY)
    if not raw:
        return {}
    try:
        payload = json.loads(raw)
        return payload if isinstance(payload, dict) else {}
    except Exception:
        return {}


def _riko_holder_scan_bg_save_status(payload: dict[str, Any]) -> None:
    if not isinstance(payload, dict):
        return
    safe = dict(payload)
    safe["updated_at"] = str(safe.get("updated_at") or _iso_now())
    _analytics_set_state(RIKO_HOLDER_SCAN_BG_STATUS_STATE_KEY, json.dumps(safe, ensure_ascii=False))


def _riko_erc20_decimals(rpc_url: str, token_address: str) -> int:
    data = _eth_encode_call("decimals()")
    out = _eth_rpc(rpc_url, "eth_call", [{"to": token_address, "data": data}, "latest"])
    dec = _eth_decode_uint256(out)
    if dec < 0 or dec > 36:
        raise RuntimeError("invalid token decimals")
    return int(dec)


def _riko_erc20_balance_of(rpc_url: str, token_address: str, holder: str) -> int:
    data = _eth_encode_call("balanceOf(address)", ["address"], [holder])
    out = _eth_rpc(rpc_url, "eth_call", [{"to": token_address, "data": data}, "latest"])
    return int(_eth_decode_uint256(out))


def _riko_collect_holder_candidates_from_transfers(
    rpc_url: str, riko_token: str, from_block: int, to_block: int
) -> tuple[set[str], str]:
    out: set[str] = set()
    if to_block < from_block:
        return out, "none"
    if bool(RIKO_PREVIEW_USE_EXPLORER):
        try:
            chain_id = _eth_hex_to_int(_eth_rpc(rpc_url, "eth_chainId", []))
            activity = _riko_holder_activity_from_explorer_logs(
                int(chain_id),
                str(riko_token or "").strip().lower(),
                from_block=int(from_block),
                to_block=int(to_block),
                max_rows=12_000,
            )
            if activity:
                return set(activity.keys()), "explorer"
        except Exception:
            # Fallback to direct eth_getLogs below.
            pass
    topic_transfer = "0x" + keccak(text="Transfer(address,address,uint256)").hex()
    # Some providers/plans enforce very small
    # eth_getLogs ranges. Start wide, then shrink adaptively down to 10 blocks.
    chunk = 10_000
    min_chunk = 10
    start = max(0, int(from_block))
    end_target = max(0, int(to_block))
    while start <= end_target:
        end = min(end_target, start + chunk - 1)
        params = [
            {
                "address": riko_token,
                "fromBlock": _eth_to_hex_block(start),
                "toBlock": _eth_to_hex_block(end),
                "topics": [topic_transfer],
            }
        ]
        try:
            logs = _eth_rpc(rpc_url, "eth_getLogs", params)
        except Exception:
            if chunk <= min_chunk:
                raise
            chunk = max(min_chunk, chunk // 2)
            continue
        if isinstance(logs, list):
            for lg in logs:
                if not isinstance(lg, dict):
                    continue
                topics = lg.get("topics")
                if not isinstance(topics, list) or len(topics) < 3:
                    continue
                addr_from = _eth_topic_to_address(str(topics[1] or ""))
                addr_to = _eth_topic_to_address(str(topics[2] or ""))
                if _is_eth_address(addr_from) and addr_from != "0x0000000000000000000000000000000000000000":
                    out.add(addr_from.lower())
                if _is_eth_address(addr_to) and addr_to != "0x0000000000000000000000000000000000000000":
                    out.add(addr_to.lower())
        # Keep the discovered working chunk size to avoid oscillation
        # (grow->fail->shrink) on strict provider limits.
        start = end + 1
    return out, "rpc"


def _riko_send_erc20_transfer_tx(
    rpc_url: str, private_key: str, token_address: str, to_address: str, amount_raw: int, nonce: int | None = None
) -> tuple[str, int, int]:
    acct = Account.from_key(private_key)
    from_addr = str(acct.address or "").strip()
    chain_id = _eth_hex_to_int(_eth_rpc(rpc_url, "eth_chainId", []))
    tx_nonce = int(nonce) if nonce is not None else _eth_hex_to_int(_eth_rpc(rpc_url, "eth_getTransactionCount", [from_addr, "pending"]))
    gas_price = _eth_hex_to_int(_eth_rpc(rpc_url, "eth_gasPrice", []))
    data = _eth_encode_call("transfer(address,uint256)", ["address", "uint256"], [to_address, int(amount_raw)])
    estimate_raw = _eth_rpc(
        rpc_url,
        "eth_estimateGas",
        [{"from": from_addr, "to": token_address, "data": data, "value": hex(0)}],
    )
    gas_estimate = max(21_000, _eth_hex_to_int(estimate_raw))
    gas_limit = int(gas_estimate * 1.2) + 7_500
    tx = {
        "chainId": int(chain_id),
        "nonce": int(tx_nonce),
        "to": token_address,
        "value": 0,
        "data": data,
        "gas": int(gas_limit),
        "gasPrice": int(gas_price),
    }
    signed = acct.sign_transaction(tx)
    raw_tx = getattr(signed, "raw_transaction", None)
    if raw_tx is None:
        raw_tx = getattr(signed, "rawTransaction", None)
    if raw_tx is None:
        raise RuntimeError("failed to sign tx")
    tx_hash = _eth_rpc(rpc_url, "eth_sendRawTransaction", ["0x" + bytes(raw_tx).hex()])
    return str(tx_hash or ""), int(chain_id), int(tx_nonce)


def _riko_wait_receipt(rpc_url: str, tx_hash: str, timeout_sec: int = 180) -> dict[str, Any]:
    start = time.time()
    while True:
        raw = _eth_rpc(rpc_url, "eth_getTransactionReceipt", [tx_hash])
        if isinstance(raw, dict) and raw:
            return raw
        if (time.time() - start) >= float(timeout_sec):
            raise TimeoutError("tx receipt timeout")
        time.sleep(3)


def _riko_auto_payout_preview() -> dict[str, Any]:
    result: dict[str, Any] = {"ts": _iso_now(), "status": "unknown"}
    riko_token = _riko_vault_address_value()
    if not _is_eth_address(riko_token):
        result.update({"status": "skip", "reason": "riko_token_not_configured"})
        return result
    bot_cfg = _load_riko_auto_yield_bot_config()
    payout_token = str(bot_cfg.get("payout_token_address") or "").strip()
    if not _is_eth_address(payout_token):
        result.update({"status": "skip", "reason": "payout_token_not_configured"})
        return result
    if payout_token.lower() not in _riko_active_whitelist_erc20_addresses():
        result.update({"status": "skip", "reason": "payout_token_not_in_active_whitelist"})
        return result
    rpc_url = _riko_auto_yield_rpc_url_runtime()
    private_key = _riko_auto_yield_private_key_runtime()
    result["rpc_url_label"] = _rpc_url_label(rpc_url)
    result["rpc_key_present"] = bool(private_key)
    if not rpc_url or not private_key:
        result.update({"status": "skip", "reason": "auto_yield_rpc_or_key_missing"})
        return result
    sender = str(Account.from_key(private_key).address or "").strip().lower()
    y = _fetch_us_treasury_daily_10y()
    annual_pct = float(y.get("annual_pct") or 0.0)
    daily_pct = float(y.get("daily_pct") or 0.0)
    monthly_pct = float(annual_pct) / 12.0
    raw_target_bps = float(monthly_pct) * 100.0
    target_bps = int(round(raw_target_bps))
    next_bps = max(int(RIKO_AUTO_YIELD_MIN_BPS), min(int(RIKO_AUTO_YIELD_MAX_BPS), int(target_bps)))
    schedule = _load_riko_payout_schedule()

    try:
        riko_decimals = _riko_erc20_decimals(rpc_url, riko_token)
        payout_decimals = _riko_erc20_decimals(rpc_url, payout_token)
    except Exception as e:
        result.update({"status": "error", "reason": str(e)[:280]})
        return result

    try:
        chain_id = _eth_hex_to_int(_eth_rpc(rpc_url, "eth_chainId", []))
        latest_block = _eth_hex_to_int(_eth_rpc(rpc_url, "eth_blockNumber", []))
        holder_cache = _riko_auto_yield_load_holder_cache()
        cached_holders = set([str(x).strip().lower() for x in holder_cache.get("holders") or [] if _is_eth_address(str(x).strip().lower())])
        last_scanned_block = max(0, int(holder_cache.get("last_scanned_block") or 0))
        cache_chain = max(0, int(holder_cache.get("chain_id") or 0))
        cache_token = str(holder_cache.get("riko_token") or "").strip().lower()
        if cache_chain != int(chain_id) or cache_token != str(riko_token).lower():
            cached_holders = set()
            last_scanned_block = 0
        if last_scanned_block <= 0:
            last_scanned_block = max(0, int(bot_cfg.get("holder_scan_start_block") or 0) - 1)
        from_block = last_scanned_block + 1
        scan_to_block = latest_block
        holder_scan_source = "none"
        if from_block <= latest_block:
            max_scan_blocks = max(10, int(RIKO_AUTO_YIELD_PREVIEW_SCAN_MAX_BLOCKS))
            scan_to_block = min(latest_block, from_block + max_scan_blocks - 1)
            discovered, holder_scan_source = _riko_collect_holder_candidates_from_transfers(
                rpc_url, riko_token, from_block, scan_to_block
            )
            cached_holders.update(discovered)
            _riko_auto_yield_save_holder_cache(
                sorted(cached_holders),
                scan_to_block,
                chain_id=int(chain_id),
                riko_token=str(riko_token).lower(),
            )
        else:
            _riko_auto_yield_save_holder_cache(
                sorted(cached_holders),
                last_scanned_block,
                chain_id=int(chain_id),
                riko_token=str(riko_token).lower(),
            )
            holder_scan_source = "cache"
        result["holder_scan_from_block"] = int(from_block)
        result["holder_scan_to_block"] = int(scan_to_block)
        result["holder_scan_latest_block"] = int(latest_block)
        result["holder_scan_has_more"] = bool(scan_to_block < latest_block)
        result["holder_scan_source"] = str(holder_scan_source or "none")
    except Exception as e:
        result.update({"status": "error", "reason": f"rpc error: {str(e)[:240]}"})
        return result

    holders_with_balance: list[tuple[str, int]] = []
    for holder in sorted(cached_holders):
        try:
            bal = int(_riko_erc20_balance_of(rpc_url, riko_token, holder))
        except Exception:
            continue
        if bal > 0:
            holders_with_balance.append((holder, bal))

    payout_rows: list[tuple[str, int, int]] = []
    scale_up = max(0, int(payout_decimals) - int(riko_decimals))
    scale_down = max(0, int(riko_decimals) - int(payout_decimals))
    total_payout_raw = 0
    for holder, bal in holders_with_balance:
        base_amount = int(bal)
        if scale_up > 0:
            base_amount *= 10**scale_up
        elif scale_down > 0:
            base_amount //= 10**scale_down
        payout_raw = (base_amount * int(next_bps)) // 10_000
        if payout_raw <= 0:
            continue
        payout_rows.append((holder, int(bal), int(payout_raw)))
        total_payout_raw += int(payout_raw)
    payout_rows.sort(key=lambda x: int(x[2]), reverse=True)

    payout_wallet_balance = int(_riko_erc20_balance_of(rpc_url, payout_token, sender))
    top_recipients: list[dict[str, Any]] = []
    for holder, riko_bal, payout_raw in payout_rows[:10]:
        top_recipients.append(
            {
                "address": holder,
                "riko_balance_raw": int(riko_bal),
                "payout_raw": int(payout_raw),
            }
        )
    result.update(
        {
            "status": "ok",
            "treasury_date": str(y.get("date") or ""),
            "annual_pct": round(annual_pct, 6),
            "daily_pct": round(daily_pct, 8),
            "monthly_pct": round(monthly_pct, 8),
            "target_bps": int(target_bps),
            "bounded_bps": int(next_bps),
            "next_bps": int(next_bps),
            "payout_wallet": sender,
            "riko_token": riko_token.lower(),
            "payout_token": payout_token.lower(),
            "riko_decimals": int(riko_decimals),
            "payout_decimals": int(payout_decimals),
            "holder_scan_start_block": int(bot_cfg.get("holder_scan_start_block") or 0),
            "holders_scanned": int(len(cached_holders)),
            "holders_positive": int(len(holders_with_balance)),
            "payout_count": int(len(payout_rows)),
            "total_payout_raw": int(total_payout_raw),
            "available_raw": int(payout_wallet_balance),
            "can_pay": bool(payout_wallet_balance >= total_payout_raw),
            "top_recipients": top_recipients,
            "schedule_time_utc": str(schedule.get("payout_time_utc") or "00:00"),
            "schedule_next_due_date": str(schedule.get("next_due_date") or ""),
            "schedule_next_due_at_utc": str(schedule.get("next_due_at_utc") or ""),
        }
    )
    return result


def _riko_admin_holders_snapshot(limit: int = 500) -> dict[str, Any]:
    riko_token = _riko_vault_address_value()
    if not _is_eth_address(riko_token):
        raise ValueError("RIKO vault address is not configured.")
    rpc_url = _riko_auto_yield_rpc_url_runtime()
    if not rpc_url:
        raise ValueError("RIKO_AUTO_YIELD_RPC_URL is not configured.")
    chain_id = _eth_hex_to_int(_eth_rpc(rpc_url, "eth_chainId", []))
    latest_block = _eth_hex_to_int(_eth_rpc(rpc_url, "eth_blockNumber", []))
    bot_cfg = _load_riko_auto_yield_bot_config()
    start_block = max(0, int(bot_cfg.get("holder_scan_start_block") or 0))
    if start_block <= 0:
        start_block = max(0, int(RIKO_AUTO_YIELD_HOLDER_SCAN_START_BLOCK))
    from_block = max(0, int(start_block))
    to_block = max(from_block, int(latest_block))
    activity = _riko_holder_activity_from_explorer_logs(
        int(chain_id),
        riko_token,
        from_block=from_block,
        to_block=to_block,
        max_rows=20_000,
    )
    holders = sorted(activity.keys(), key=lambda a: int((activity.get(a) or {}).get("last_change_block") or 0), reverse=True)
    if int(limit) > 0:
        holders = holders[: max(1, min(2000, int(limit)))]
    warnings: list[str] = []
    try:
        riko_decimals = _riko_erc20_decimals(rpc_url, riko_token)
    except Exception as e:
        # Keep snapshot endpoint operational even when provider rejects decimals() call.
        # RIKO uses 6 decimals, so 6 is a safe fallback for admin display math.
        riko_decimals = 6
        warnings.append(f"riko_decimals_fallback_to_6: {str(e)[:140]}")
    payout_token = str(bot_cfg.get("payout_token_address") or "").strip().lower()
    schedule = _load_riko_payout_schedule()
    schedule_next_due_date = str(schedule.get("next_due_date") or "")
    schedule_next_due_at_utc = str(schedule.get("next_due_at_utc") or "")
    annual_pct = 0.0
    monthly_pct = 0.0
    target_bps = 0
    next_bps = 0
    try:
        y = _fetch_us_treasury_daily_10y()
        annual_pct = float(y.get("annual_pct") or 0.0)
        monthly_pct = float(annual_pct) / 12.0
        raw_target_bps = float(monthly_pct) * 100.0
        target_bps = int(round(raw_target_bps))
        next_bps = max(int(RIKO_AUTO_YIELD_MIN_BPS), min(int(RIKO_AUTO_YIELD_MAX_BPS), int(target_bps)))
    except Exception:
        annual_pct = 0.0
        monthly_pct = 0.0
        target_bps = 0
        next_bps = 0
    payout_decimals = 18
    if _is_eth_address(payout_token):
        try:
            payout_decimals = _riko_erc20_decimals(rpc_url, payout_token)
        except Exception:
            payout_decimals = 18
    scale_up = max(0, int(payout_decimals) - int(riko_decimals))
    scale_down = max(0, int(riko_decimals) - int(payout_decimals))
    rows: list[dict[str, Any]] = []
    balance_call_errors = 0
    for holder in holders:
        if str(holder or "").strip().lower() == riko_token:
            continue
        try:
            bal = int(_riko_erc20_balance_of(rpc_url, riko_token, holder))
        except Exception:
            balance_call_errors += 1
            continue
        meta = activity.get(holder) or {}
        tx_hash = str(meta.get("last_change_hash") or "").strip().lower()
        tx_url = _explorer_tx_url_for_chain(int(chain_id), tx_hash) if tx_hash else ""
        ts = int(meta.get("last_change_ts") or 0)
        planned_payout_raw = 0
        planned_reason = ""
        if int(bal) > 0 and int(next_bps) > 0 and _is_eth_address(payout_token):
            base_amount = int(bal)
            if scale_up > 0:
                base_amount *= 10**scale_up
            elif scale_down > 0:
                base_amount //= 10**scale_down
            planned_payout_raw = max(0, (base_amount * int(next_bps)) // 10_000)
            if planned_payout_raw <= 0:
                # Real zero after integer rounding in payout token units.
                planned_reason = "below_token_precision"
        elif int(bal) > 0 and int(next_bps) <= 0:
            planned_reason = "rate_unavailable"
        elif int(bal) > 0 and (not _is_eth_address(payout_token)):
            planned_reason = "payout_token_not_applied"
        rows.append(
            {
                "address": holder,
                "balance_raw": int(bal),
                "last_change_ts": int(ts),
                "last_change_iso": datetime.fromtimestamp(ts, tz=timezone.utc).isoformat() if ts > 0 else "",
                "last_change_hash": tx_hash,
                "last_change_tx_url": tx_url,
                "planned_yield_payout_raw": int(planned_payout_raw),
                "planned_yield_bps": int(next_bps),
                "planned_yield_reason": planned_reason,
                "planned_yield_date": schedule_next_due_date,
                "planned_yield_date_utc": schedule_next_due_at_utc,
            }
        )
    rows.sort(
        key=lambda r: (
            int(r.get("last_change_ts") or 0),
            int(r.get("balance_raw") or 0),
        ),
        reverse=True,
    )
    if balance_call_errors > 0:
        warnings.append(f"balanceOf_failed_for_{int(balance_call_errors)}_holders")
    return {
        "ok": True,
        "chain_id": int(chain_id),
        "riko_token": riko_token,
        "riko_decimals": int(riko_decimals),
        "payout_token": payout_token if _is_eth_address(payout_token) else "",
        "payout_decimals": int(payout_decimals),
        "annual_pct": float(annual_pct),
        "monthly_pct": float(monthly_pct),
        "target_bps": int(target_bps),
        "next_bps": int(next_bps),
        "schedule_next_due_date": schedule_next_due_date,
        "schedule_next_due_at_utc": schedule_next_due_at_utc,
        "holder_scan_start_block": int(from_block),
        "holder_scan_latest_block": int(latest_block),
        "count": int(len(rows)),
        "items": rows,
        "warnings": warnings,
    }


def _riko_auto_yield_try_once() -> dict[str, Any]:
    result: dict[str, Any] = {"ts": _iso_now(), "status": "unknown"}
    riko_token = _riko_vault_address_value()
    if not _is_eth_address(riko_token):
        result.update({"status": "skip", "reason": "riko_token_not_configured"})
        return result
    bot_cfg = _load_riko_auto_yield_bot_config()
    payout_token = str(bot_cfg.get("payout_token_address") or "").strip()
    if not _is_eth_address(payout_token):
        result.update({"status": "skip", "reason": "payout_token_not_configured"})
        return result
    if payout_token.lower() not in _riko_active_whitelist_erc20_addresses():
        result.update({"status": "skip", "reason": "payout_token_not_in_active_whitelist"})
        return result
    if RIKO_PILOT_CONFIG_FROZEN:
        result.update({"status": "skip", "reason": "pilot_config_frozen"})
        return result
    rpc_url = _riko_auto_yield_rpc_url_runtime()
    private_key = _riko_auto_yield_private_key_runtime()
    if not rpc_url or not private_key:
        result.update({"status": "skip", "reason": "auto_yield_rpc_or_key_missing"})
        return result
    sender = str(Account.from_key(private_key).address or "").strip().lower()

    y = _fetch_us_treasury_daily_10y()
    now_utc = datetime.now(timezone.utc)
    month_key = f"{now_utc.year:04d}-{now_utc.month:02d}"
    schedule = _load_riko_payout_schedule()
    schedule_items = _normalize_riko_payout_schedule_items(schedule.get("items"))
    schedule_hour = int(schedule.get("payout_hour_utc") or 0)
    schedule_minute = int(schedule.get("payout_minute_utc") or 0)
    payout_time_utc = str(schedule.get("payout_time_utc") or "00:00")
    now_minutes = (int(now_utc.hour) * 60) + int(now_utc.minute)
    scheduled_minutes = (schedule_hour * 60) + schedule_minute
    schedule_date_key = ""
    if schedule_items:
        today_month = int(now_utc.month)
        today_day = int(now_utc.day)
        matched = any(int(it.get("month") or 0) == today_month and int(it.get("day") or 0) == today_day for it in schedule_items)
        if not matched:
            result.update(
                {
                    "status": "skip",
                    "reason": "not_scheduled_payout_date",
                    "month_key": month_key,
                    "schedule_next_due_date": str(schedule.get("next_due_date") or ""),
                    "schedule_next_due_at_utc": str(schedule.get("next_due_at_utc") or ""),
                    "next_bps": int(schedule.get("next_rate_bps") or 0),
                    "payout_token": payout_token.lower(),
                }
            )
            return result
        if now_minutes < scheduled_minutes:
            result.update(
                {
                    "status": "skip",
                    "reason": "before_scheduled_utc_time",
                    "month_key": month_key,
                    "schedule_time_utc": payout_time_utc,
                    "schedule_next_due_date": str(schedule.get("next_due_date") or ""),
                    "schedule_next_due_at_utc": str(schedule.get("next_due_at_utc") or ""),
                    "next_bps": int(schedule.get("next_rate_bps") or 0),
                    "payout_token": payout_token.lower(),
                }
            )
            return result
        schedule_date_key = f"{now_utc.year:04d}-{today_month:02d}-{today_day:02d}"
    else:
        if now_utc.day != 1:
            result.update(
                {
                    "status": "skip",
                    "reason": "not_first_day_of_month",
                    "month_key": month_key,
                    "schedule_next_due_date": str(schedule.get("next_due_date") or ""),
                    "schedule_next_due_at_utc": str(schedule.get("next_due_at_utc") or ""),
                    "next_bps": int(schedule.get("next_rate_bps") or 0),
                    "payout_token": payout_token.lower(),
                }
            )
            return result
        if now_minutes < scheduled_minutes:
            result.update(
                {
                    "status": "skip",
                    "reason": "before_scheduled_utc_time",
                    "month_key": month_key,
                    "schedule_time_utc": payout_time_utc,
                    "schedule_next_due_date": str(schedule.get("next_due_date") or ""),
                    "schedule_next_due_at_utc": str(schedule.get("next_due_at_utc") or ""),
                    "next_bps": int(schedule.get("next_rate_bps") or 0),
                    "payout_token": payout_token.lower(),
                }
            )
            return result
        schedule_date_key = f"{now_utc.year:04d}-{now_utc.month:02d}-{now_utc.day:02d}"
    last_raw = _analytics_get_state(RIKO_AUTO_YIELD_STATE_KEY)
    if last_raw:
        try:
            last_state = json.loads(last_raw)
            if isinstance(last_state, dict):
                if schedule_date_key and str(last_state.get("applied_schedule_date") or "") == schedule_date_key:
                    result.update(
                        {
                            "status": "skip",
                            "reason": "already_applied_for_scheduled_date",
                            "schedule_date_key": schedule_date_key,
                            "month_key": month_key,
                        }
                    )
                    return result
                if (not schedule_date_key) and str(last_state.get("applied_month") or "") == month_key:
                    result.update({"status": "skip", "reason": "already_applied_this_month", "month_key": month_key})
                    return result
        except Exception:
            pass
    annual_pct = float(y.get("annual_pct") or 0.0)
    daily_pct = float(y.get("daily_pct") or 0.0)
    monthly_pct = float(annual_pct) / 12.0
    treasury_date = str(y.get("date") or "")
    raw_target_bps = float(monthly_pct) * 100.0
    target_bps = int(round(raw_target_bps))
    bounded_bps = max(int(RIKO_AUTO_YIELD_MIN_BPS), min(int(RIKO_AUTO_YIELD_MAX_BPS), int(target_bps)))
    next_bps = int(bounded_bps)

    try:
        riko_decimals = _riko_erc20_decimals(rpc_url, riko_token)
        payout_decimals = _riko_erc20_decimals(rpc_url, payout_token)
    except Exception as e:
        result.update({"status": "error", "reason": str(e)[:280]})
        return result

    chain_id = _eth_hex_to_int(_eth_rpc(rpc_url, "eth_chainId", []))
    latest_block = _eth_hex_to_int(_eth_rpc(rpc_url, "eth_blockNumber", []))
    holder_cache = _riko_auto_yield_load_holder_cache()
    cached_holders = set([str(x).strip().lower() for x in holder_cache.get("holders") or [] if _is_eth_address(str(x).strip().lower())])
    last_scanned_block = max(0, int(holder_cache.get("last_scanned_block") or 0))
    cache_chain = max(0, int(holder_cache.get("chain_id") or 0))
    cache_token = str(holder_cache.get("riko_token") or "").strip().lower()
    if cache_chain != int(chain_id) or cache_token != str(riko_token).lower():
        cached_holders = set()
        last_scanned_block = 0
    if last_scanned_block <= 0:
        last_scanned_block = max(0, int(bot_cfg.get("holder_scan_start_block") or 0) - 1)
    from_block = last_scanned_block + 1
    if from_block <= latest_block:
        discovered, _ = _riko_collect_holder_candidates_from_transfers(rpc_url, riko_token, from_block, latest_block)
        cached_holders.update(discovered)
    _riko_auto_yield_save_holder_cache(
        sorted(cached_holders),
        latest_block,
        chain_id=int(chain_id),
        riko_token=str(riko_token).lower(),
    )

    holders_with_balance: list[tuple[str, int]] = []
    for holder in sorted(cached_holders):
        try:
            bal = int(_riko_erc20_balance_of(rpc_url, riko_token, holder))
        except Exception:
            continue
        if bal > 0:
            holders_with_balance.append((holder, bal))
    if not holders_with_balance:
        result.update(
            {
                "status": "skip",
                "reason": "no_holders_with_balance",
                "holders_scanned": int(len(cached_holders)),
                "holders_positive": 0,
                "month_key": month_key,
                "schedule_date_key": schedule_date_key,
            }
        )
        return result

    payout_rows: list[tuple[str, int]] = []
    scale_up = max(0, int(payout_decimals) - int(riko_decimals))
    scale_down = max(0, int(riko_decimals) - int(payout_decimals))
    total_payout_raw = 0
    for holder, bal in holders_with_balance:
        base_amount = int(bal)
        if scale_up > 0:
            base_amount *= 10**scale_up
        elif scale_down > 0:
            base_amount //= 10**scale_down
        payout_raw = (base_amount * int(next_bps)) // 10_000
        if payout_raw <= 0:
            continue
        payout_rows.append((holder, int(payout_raw)))
        total_payout_raw += int(payout_raw)
    if not payout_rows or total_payout_raw <= 0:
        result.update(
            {
                "status": "skip",
                "reason": "no_positive_payouts",
                "holders_scanned": int(len(cached_holders)),
                "holders_positive": int(len(holders_with_balance)),
                "bps": int(next_bps),
                "month_key": month_key,
                "schedule_date_key": schedule_date_key,
            }
        )
        return result

    payout_wallet_balance = int(_riko_erc20_balance_of(rpc_url, payout_token, sender))
    if payout_wallet_balance < total_payout_raw:
        result.update(
            {
                "status": "skip",
                "reason": "insufficient_payout_balance",
                "payout_wallet": sender,
                "required_raw": int(total_payout_raw),
                "available_raw": int(payout_wallet_balance),
                "payout_token": payout_token.lower(),
                "holders_scanned": int(len(cached_holders)),
                "holders_positive": int(len(holders_with_balance)),
                "payout_count": int(len(payout_rows)),
                "month_key": month_key,
                "schedule_date_key": schedule_date_key,
            }
        )
        return result

    result.update(
        {
            "status": "ok",
            "action": "erc20_payouts_sent",
            "treasury_date": treasury_date,
            "annual_pct": round(annual_pct, 6),
            "daily_pct": round(daily_pct, 8),
            "monthly_pct": round(monthly_pct, 8),
            "raw_target_bps": raw_target_bps,
            "target_bps": int(target_bps),
            "bounded_bps": int(bounded_bps),
            "next_bps": int(next_bps),
            "payout_wallet": sender,
            "payout_token": payout_token.lower(),
            "riko_token": riko_token.lower(),
            "bot_config_source": str(bot_cfg.get("source") or "env"),
            "holder_scan_start_block": int(bot_cfg.get("holder_scan_start_block") or 0),
            "riko_decimals": int(riko_decimals),
            "payout_decimals": int(payout_decimals),
            "holders_scanned": int(len(cached_holders)),
            "holders_positive": int(len(holders_with_balance)),
            "payout_count": int(len(payout_rows)),
            "total_payout_raw": int(total_payout_raw),
            "month_key": month_key,
            "schedule_date_key": schedule_date_key,
            "schedule_time_utc": payout_time_utc,
            "schedule_next_due_date": str(schedule.get("next_due_date") or ""),
            "schedule_next_due_at_utc": str(schedule.get("next_due_at_utc") or ""),
        }
    )

    claimed_schedule_date = False
    if schedule_date_key:
        claimed_schedule_date = _riko_auto_payout_try_claim_schedule_date(schedule_date_key)
        if not claimed_schedule_date:
            result.update(
                {
                    "status": "skip",
                    "reason": "already_applied_for_scheduled_date",
                    "schedule_date_key": schedule_date_key,
                    "month_key": month_key,
                }
            )
            return result

    tx_hashes: list[str] = []
    chain_id = 0
    nonce: int | None = None
    for holder_addr, payout_amount in payout_rows:
        try:
            tx_hash, tx_chain_id, tx_nonce = _riko_send_erc20_transfer_tx(
                rpc_url,
                private_key,
                payout_token,
                holder_addr,
                int(payout_amount),
                nonce=nonce,
            )
            nonce = int(tx_nonce) + 1
            chain_id = int(tx_chain_id)
            tx_hashes.append(str(tx_hash))
            receipt = _riko_wait_receipt(rpc_url, tx_hash, timeout_sec=240)
            status_num = _eth_hex_to_int(receipt.get("status"))
            if status_num != 1:
                result.update(
                    {
                        "status": "error",
                        "reason": "tx_reverted",
                        "tx_hash": tx_hash,
                        "chain_id": int(chain_id),
                        "sent_count": int(len(tx_hashes)),
                    }
                )
                if tx_hashes:
                    # Prevent duplicate payouts on retry after partial success.
                    result["applied_schedule_date"] = schedule_date_key
                    result["partial_payout_incomplete"] = True
                elif claimed_schedule_date:
                    _riko_auto_payout_release_schedule_date_claim(schedule_date_key)
                return result
        except Exception as e:
            result.update(
                {
                    "status": "error",
                    "reason": str(e)[:280],
                    "chain_id": int(chain_id),
                    "sent_count": int(len(tx_hashes)),
                }
            )
            if tx_hashes:
                # Prevent duplicate payouts on retry after partial success.
                result["applied_schedule_date"] = schedule_date_key
                result["partial_payout_incomplete"] = True
                result["tx_hash"] = tx_hashes[-1]
                result["tx_hashes"] = tx_hashes[-20:]
            # Keep schedule-date claim on unknown send outcome to avoid duplicate payouts.
            return result

    result.update(
        {
            "tx_hash": tx_hashes[-1] if tx_hashes else "",
            "tx_hashes": tx_hashes[-20:],
            "chain_id": int(chain_id),
            "sent_count": int(len(tx_hashes)),
            "applied_month": month_key,
            "applied_schedule_date": schedule_date_key,
        }
    )
    return result


def _riko_auto_yield_report(result: dict[str, Any]) -> None:
    def _parse_due_utc(raw: str) -> datetime | None:
        txt = str(raw or "").strip()
        if not txt:
            return None
        for fmt in ("%Y-%m-%d %H:%M UTC", "%Y-%m-%dT%H:%M:%SZ"):
            try:
                dt = datetime.strptime(txt, fmt)
                return dt.replace(tzinfo=timezone.utc)
            except Exception:
                continue
        return None

    def _send_upcoming_payout_reminders(payload: dict[str, Any]) -> None:
        due_txt = str(payload.get("schedule_next_due_at_utc") or "").strip()
        if not due_txt:
            try:
                due_txt = str(_load_riko_payout_schedule().get("next_due_at_utc") or "").strip()
            except Exception:
                due_txt = ""
        due_dt = _parse_due_utc(due_txt)
        if not isinstance(due_dt, datetime):
            return
        now_dt = datetime.now(timezone.utc)
        delta_sec = (due_dt - now_dt).total_seconds()
        if delta_sec <= 0:
            return
        due_key = due_dt.strftime("%Y-%m-%d %H:%M")
        st = _riko_auto_yield_load_reminders_state()
        sent = st.get("sent") if isinstance(st.get("sent"), dict) else {}
        rec = sent.get(due_key) if isinstance(sent.get(due_key), dict) else {}
        reminder_kind = ""
        reminder_label = ""
        if delta_sec <= (24 * 3600):
            if not rec.get("h24"):
                reminder_kind = "h24"
                reminder_label = "24 hours"
        elif delta_sec <= (48 * 3600):
            if not rec.get("h48"):
                reminder_kind = "h48"
                reminder_label = "48 hours"
        if not reminder_kind:
            return
        next_bps = int(payload.get("next_bps") or 0)
        payout_token = str(payload.get("payout_token") or "").strip().lower()
        lines = [
            "[UNI_FEE] RIKO Auto-Payout Bot",
            f"Time (UTC): {_iso_now()}",
            f"Reminder: next payout in {reminder_label}.",
            f"Scheduled payout (UTC): {due_txt}",
        ]
        if next_bps > 0:
            lines.append(f"Planned monthly rate: {next_bps} bps")
        if payout_token:
            lines.append(f"Payout token: {payout_token}")
        ok, info = _send_telegram_message("\n".join(lines))
        if not ok:
            print(f"[riko-auto-payout] telegram reminder send failed: {info}")
            return
        rec = dict(rec)
        rec[reminder_kind] = _iso_now()
        sent = dict(sent)
        sent[due_key] = rec
        _riko_auto_yield_save_reminders_state({"sent": sent})

    _send_upcoming_payout_reminders(result)

    status = str(result.get("status") or "unknown")
    reason_raw = str(result.get("reason") or "").strip()
    planned_skip_reasons = {
        "not_scheduled_payout_date",
        "before_scheduled_utc_time",
        "not_first_day_of_month",
        "already_applied_for_scheduled_date",
        "already_applied_this_month",
    }
    if status == "skip" and reason_raw in planned_skip_reasons:
        return
    status_label = {"ok": "OK", "skip": "SKIPPED", "error": "ERROR"}.get(status, status.upper())
    lines = ["[UNI_FEE] RIKO Auto-Payout Bot", f"Time (UTC): {_iso_now()}", f"Result: {status_label}"]
    if reason_raw:
        reason_human, next_step = _human_riko_auto_yield_reason(reason_raw)
        lines.append(f"Reason: {reason_human}")
        lines.append(f"Action: {next_step}")
    if result.get("treasury_date"):
        lines.append(f"Treasury date: {result.get('treasury_date')}")
    if result.get("annual_pct") is not None:
        lines.append(f"US 10Y annual: {result.get('annual_pct')}%")
    if result.get("daily_pct") is not None:
        lines.append(f"Daily rate: {result.get('daily_pct')}%")
    if result.get("monthly_pct") is not None:
        lines.append(f"Monthly rate: {result.get('monthly_pct')}%")
    if result.get("target_bps") is not None:
        lines.append(f"BPS: raw={result.get('target_bps')}, bounded={result.get('bounded_bps')}, applied={result.get('next_bps')}")
    if result.get("holders_scanned") is not None:
        lines.append(
            f"Holders: scanned={result.get('holders_scanned')}, positive={result.get('holders_positive', 0)}, "
            f"paid={result.get('payout_count', 0)}"
        )
    if result.get("total_payout_raw") is not None:
        lines.append(f"Total payout (raw units): {result.get('total_payout_raw')}")
    if result.get("payout_wallet"):
        lines.append(f"Payout wallet: {result.get('payout_wallet')}")
    if result.get("payout_token"):
        lines.append(f"Payout token: {result.get('payout_token')}")
    if result.get("bot_config_source"):
        lines.append(f"Bot config source: {result.get('bot_config_source')}")
    if result.get("holder_scan_start_block") is not None:
        lines.append(f"Holder scan start block: {result.get('holder_scan_start_block')}")
    if result.get("riko_token"):
        lines.append(f"RIKO token: {result.get('riko_token')}")
    if result.get("month_key"):
        lines.append(f"Month: {result.get('month_key')}")
    if result.get("schedule_date_key"):
        lines.append(f"Schedule date: {result.get('schedule_date_key')}")
    if result.get("schedule_next_due_date"):
        lines.append(f"Next due date: {result.get('schedule_next_due_date')}")
    if result.get("schedule_next_due_at_utc"):
        lines.append(f"Next due at (UTC): {result.get('schedule_next_due_at_utc')}")
    if result.get("schedule_time_utc"):
        lines.append(f"Schedule time (UTC): {result.get('schedule_time_utc')}")
    if result.get("action"):
        lines.append(f"Action done: {result.get('action')}")
    if bool(result.get("partial_payout_incomplete")):
        lines.append("Warning: partial payout completed; retry is blocked for this schedule date.")
    if result.get("tx_hash"):
        lines.append(f"Tx hash: {result.get('tx_hash')}")
    if result.get("chain_id"):
        lines.append(f"Chain ID: {result.get('chain_id')}")
    tx_hashes = result.get("tx_hashes")
    if isinstance(tx_hashes, list) and tx_hashes:
        lines.append(f"Transfers sent: {len(tx_hashes)} (showing last {len(tx_hashes)})")
        for h in tx_hashes:
            lines.append(f" - {h}")
    ok, info = _send_telegram_message("\n".join(lines))
    if not ok:
        print(f"[riko-auto-payout] telegram send failed: {info}")


def _riko_auto_yield_loop(interval_sec: int, run_on_startup: bool) -> None:
    if run_on_startup:
        try:
            out = _riko_auto_yield_try_once()
            _riko_auto_yield_save_state(out)
            _append_riko_auto_yield_history(out)
            _riko_auto_yield_report(out)
        except Exception as e:
            out = {"status": "error", "reason": str(e)[:280], "ts": _iso_now()}
            _riko_auto_yield_save_state(out)
            _append_riko_auto_yield_history(out)
            _riko_auto_yield_report(out)
    while not RIKO_AUTO_YIELD_STOP.wait(interval_sec):
        try:
            out = _riko_auto_yield_try_once()
            _riko_auto_yield_save_state(out)
            _append_riko_auto_yield_history(out)
            _riko_auto_yield_report(out)
        except Exception as e:
            out = {"status": "error", "reason": str(e)[:280], "ts": _iso_now()}
            _riko_auto_yield_save_state(out)
            _append_riko_auto_yield_history(out)
            _riko_auto_yield_report(out)


def _riko_holder_scan_bg_step(max_scan_blocks: int) -> dict[str, Any]:
    def _done(payload: dict[str, Any]) -> dict[str, Any]:
        p = dict(payload or {})
        p["updated_at"] = _iso_now()
        _riko_holder_scan_bg_save_status(p)
        return p

    riko_token = _riko_vault_address_value()
    if not _is_eth_address(riko_token):
        return _done({"status": "skip", "reason": "riko_token_not_configured"})
    rpc_url = _riko_auto_yield_rpc_url_runtime()
    if not rpc_url:
        return _done({"status": "skip", "reason": "rpc_missing"})
    chain_id = _eth_hex_to_int(_eth_rpc(rpc_url, "eth_chainId", []))
    latest_block = _eth_hex_to_int(_eth_rpc(rpc_url, "eth_blockNumber", []))
    holder_cache = _riko_auto_yield_load_holder_cache()
    cached_holders = set(
        [str(x).strip().lower() for x in holder_cache.get("holders") or [] if _is_eth_address(str(x).strip().lower())]
    )
    bot_cfg = _load_riko_auto_yield_bot_config()
    last_scanned_block = max(0, int(holder_cache.get("last_scanned_block") or 0))
    cache_chain = max(0, int(holder_cache.get("chain_id") or 0))
    cache_token = str(holder_cache.get("riko_token") or "").strip().lower()
    if cache_chain != int(chain_id) or cache_token != str(riko_token).lower():
        cached_holders = set()
        last_scanned_block = 0
    if last_scanned_block <= 0:
        last_scanned_block = max(0, int(bot_cfg.get("holder_scan_start_block") or 0) - 1)
    from_block = last_scanned_block + 1
    if from_block > latest_block:
        return _done({
            "status": "ok",
            "source": "cache",
            "chain_id": int(chain_id),
            "riko_token": str(riko_token).lower(),
            "from_block": int(from_block),
            "to_block": int(last_scanned_block),
            "latest_block": int(latest_block),
            "holders": int(len(cached_holders)),
            "has_more": False,
        })
    scan_to_block = min(int(latest_block), int(from_block) + max(10, int(max_scan_blocks)) - 1)
    discovered, source = _riko_collect_holder_candidates_from_transfers(rpc_url, riko_token, from_block, scan_to_block)
    if discovered:
        cached_holders.update(discovered)
    _riko_auto_yield_save_holder_cache(
        sorted(cached_holders),
        scan_to_block,
        chain_id=int(chain_id),
        riko_token=str(riko_token).lower(),
    )
    return _done({
        "status": "ok",
        "source": str(source or "rpc"),
        "chain_id": int(chain_id),
        "riko_token": str(riko_token).lower(),
        "from_block": int(from_block),
        "to_block": int(scan_to_block),
        "latest_block": int(latest_block),
        "holders": int(len(cached_holders)),
        "has_more": bool(scan_to_block < latest_block),
    })


def _riko_holder_scan_bg_loop(interval_sec: int, max_scan_blocks: int) -> None:
    # One immediate step at startup to warm cache.
    try:
        _riko_holder_scan_bg_step(max_scan_blocks=max_scan_blocks)
    except Exception as e:
        print(f"[riko-holder-scan-bg] startup step failed: {str(e)[:220]}")
    while not RIKO_HOLDER_SCAN_BG_STOP.wait(interval_sec):
        try:
            _riko_holder_scan_bg_step(max_scan_blocks=max_scan_blocks)
        except Exception as e:
            print(f"[riko-holder-scan-bg] step failed: {str(e)[:220]}")


def _start_riko_holder_scan_bg_job() -> None:
    global RIKO_HOLDER_SCAN_BG_THREAD
    if not bool(RIKO_HOLDER_SCAN_BG_ENABLED):
        return
    if RIKO_HOLDER_SCAN_BG_THREAD and RIKO_HOLDER_SCAN_BG_THREAD.is_alive():
        return
    RIKO_HOLDER_SCAN_BG_STOP.clear()
    RIKO_HOLDER_SCAN_BG_THREAD = threading.Thread(
        target=_riko_holder_scan_bg_loop,
        args=(RIKO_HOLDER_SCAN_BG_INTERVAL_SEC, RIKO_HOLDER_SCAN_BG_MAX_BLOCKS),
        daemon=True,
        name="riko-holder-scan-bg",
    )
    RIKO_HOLDER_SCAN_BG_THREAD.start()


def _stop_riko_holder_scan_bg_job() -> None:
    RIKO_HOLDER_SCAN_BG_STOP.set()
    t = RIKO_HOLDER_SCAN_BG_THREAD
    if t and t.is_alive():
        try:
            t.join(timeout=2.0)
        except Exception:
            pass


def _start_riko_auto_yield_job() -> None:
    global RIKO_AUTO_YIELD_THREAD
    if not _riko_auto_yield_enabled():
        return
    if RIKO_AUTO_YIELD_THREAD and RIKO_AUTO_YIELD_THREAD.is_alive():
        return
    RIKO_AUTO_YIELD_STOP.clear()
    RIKO_AUTO_YIELD_THREAD = threading.Thread(
        target=_riko_auto_yield_loop,
        args=(RIKO_AUTO_YIELD_INTERVAL_SEC, RIKO_AUTO_YIELD_RUN_ON_STARTUP),
        daemon=True,
        name="riko-auto-payout",
    )
    RIKO_AUTO_YIELD_THREAD.start()


def _stop_riko_auto_yield_job() -> None:
    RIKO_AUTO_YIELD_STOP.set()
    t = RIKO_AUTO_YIELD_THREAD
    if t and t.is_alive():
        try:
            t.join(timeout=2.0)
        except Exception:
            pass


def _riko_backfill_item_addresses(items: list[dict[str, Any]]) -> tuple[list[dict[str, Any]], bool]:
    clean = _normalize_riko_whitelist_items(items or [])
    out: list[dict[str, Any]] = []
    changed = False
    for row in clean:
        sym = str(row.get("symbol") or "").strip().lower()
        addr = str(row.get("address") or "").strip().lower()
        keep_on_vault = bool(row.get("keep_on_vault"))
        if sym == "eth":
            fixed_native = "native"
            if addr != fixed_native:
                addr = fixed_native
                changed = True
            out.append({"symbol": sym, "address": addr, "keep_on_vault": keep_on_vault})
            continue
        if sym and not _is_eth_address(addr):
            addrs = _riko_resolve_symbol_addresses(sym)
            fixed = str(addrs[0] if addrs else "").strip().lower()
            if _is_eth_address(fixed):
                addr = fixed
                changed = True
        out.append({"symbol": sym, "address": addr, "keep_on_vault": keep_on_vault})
    return out, changed


def _load_riko_whitelist_items() -> list[dict[str, Any]]:
    saved = _analytics_get_state(RIKO_WHITELIST_STATE_KEY)
    if saved:
        try:
            payload = json.loads(saved)
            if isinstance(payload, dict):
                items = _normalize_riko_whitelist_items(payload.get("items"))
                if items:
                    backfilled, changed = _riko_backfill_item_addresses(items)
                    if changed:
                        _analytics_set_state(RIKO_WHITELIST_STATE_KEY, json.dumps({"items": backfilled}, ensure_ascii=False))
                    return backfilled
                symbols = _normalize_symbol_list(payload.get("symbols") if isinstance(payload.get("symbols"), list) else [])
                if symbols:
                    return _riko_items_from_symbols(symbols)
            if isinstance(payload, list):
                if payload and isinstance(payload[0], dict):
                    items = _normalize_riko_whitelist_items(payload)
                    if items:
                        return items
                symbols = _normalize_symbol_list(payload)
                if symbols:
                    return _riko_items_from_symbols(symbols)
        except Exception:
            pass
    return _riko_default_whitelist_items()


def _save_riko_whitelist_items(items: list[dict[str, Any]]) -> list[dict[str, Any]]:
    clean = _normalize_riko_whitelist_items(items or [])
    if not clean:
        raise HTTPException(status_code=400, detail="Whitelist cannot be empty.")
    _analytics_set_state(RIKO_WHITELIST_STATE_KEY, json.dumps({"items": clean}, ensure_ascii=False))
    return clean


def _load_riko_pending_whitelist_items() -> list[dict[str, Any]]:
    saved = _analytics_get_state(RIKO_WHITELIST_PENDING_STATE_KEY)
    if not saved:
        return []
    try:
        payload = json.loads(saved)
    except Exception:
        return []
    if isinstance(payload, dict):
        items = _normalize_riko_whitelist_items(payload.get("items"))
        if items:
            backfilled, changed = _riko_backfill_item_addresses(items)
            if changed:
                _analytics_set_state(RIKO_WHITELIST_PENDING_STATE_KEY, json.dumps({"items": backfilled}, ensure_ascii=False))
            return backfilled
        syms = _normalize_symbol_list(payload.get("symbols") if isinstance(payload.get("symbols"), list) else [])
        return _riko_items_from_symbols(syms)
    if isinstance(payload, list):
        if payload and isinstance(payload[0], dict):
            return _normalize_riko_whitelist_items(payload)
        syms = _normalize_symbol_list(payload)
        return _riko_items_from_symbols(syms)
    return []


def _save_riko_pending_whitelist_items(items: list[dict[str, Any]]) -> list[dict[str, Any]]:
    clean = _normalize_riko_whitelist_items(items or [])
    if not clean:
        raise HTTPException(status_code=400, detail="Pending whitelist cannot be empty.")
    _analytics_set_state(RIKO_WHITELIST_PENDING_STATE_KEY, json.dumps({"items": clean}, ensure_ascii=False))
    return clean


def _clear_riko_pending_whitelist_symbols() -> None:
    _analytics_set_state(RIKO_WHITELIST_PENDING_STATE_KEY, "")


def _validate_riko_whitelist_items(items: list[dict[str, Any]]) -> dict[str, Any]:
    clean = _normalize_riko_whitelist_items(items or [])
    errors: list[str] = []
    warnings: list[str] = []
    if not clean:
        errors.append("Whitelist cannot be empty.")
    if len(clean) > 120:
        errors.append("Whitelist is too large (>120 symbols).")
    symbol_addresses: dict[str, list[str]] = {}
    symbols: list[str] = []
    normalized_items: list[dict[str, Any]] = []
    for row in clean:
        s = str(row.get("symbol") or "").strip().lower()
        addr = str(row.get("address") or "").strip().lower()
        keep_on_vault = bool(row.get("keep_on_vault"))
        if s == "eth":
            is_native_marker = addr in {"", "native", "eth"}
            if not is_native_marker:
                errors.append("eth: must use native marker (leave empty or set 'native').")
                symbol_addresses[s] = []
                continue
            symbol_addresses[s] = []
            normalized_items.append({"symbol": s, "address": "native", "keep_on_vault": keep_on_vault})
            symbols.append(s)
            continue
        addrs = _riko_resolve_symbol_addresses(s)
        effective_addr = addr if _is_eth_address(addr) else ""
        if not effective_addr:
            # UX-safe fallback: for known symbols automatically pick the first catalog address.
            if addrs:
                effective_addr = str(addrs[0] or "").strip().lower()
                if _is_eth_address(effective_addr):
                    warnings.append(f"{s}: exact address was empty, auto-filled from catalog.")
                else:
                    effective_addr = ""
            if not effective_addr:
                # If admin entered some address and it is invalid, keep this as an error.
                if addr:
                    errors.append(f"{s}: exact token address is missing or invalid.")
                else:
                    # For symbols with unknown Ethereum address, skip row instead of blocking apply.
                    warnings.append(f"{s}: skipped, no known Ethereum address.")
                symbol_addresses[s] = addrs
                continue
        elif addrs and effective_addr not in addrs:
            warnings.append(f"{s}: address is not in catalog/config known addresses.")
        symbol_addresses[s] = [a for a in [effective_addr] if _is_eth_address(a)] or addrs
        normalized_items.append({"symbol": s, "address": effective_addr, "keep_on_vault": keep_on_vault})
        symbols.append(s)
    if not normalized_items:
        errors.append("No valid whitelist items with Ethereum addresses.")
    return {
        "valid": not errors,
        "items": normalized_items,
        "symbols": symbols,
        "symbol_addresses": symbol_addresses,
        "errors": errors,
        "warnings": warnings,
        "count": len(symbols),
    }


