def _format_position_liquidity_scalar_compact(liq_raw: int) -> str:
    """Человекочитаемый скаляр ликвидности (v4), без USD."""
    x = max(0, int(liq_raw))
    if x <= 0:
        return "-"
    if x < 1000:
        return str(x)
    if x < 1_000_000:
        return f"{x / 1000.0:.1f}K".rstrip("0").rstrip(".")
    if x < 1_000_000_000:
        return f"{x / 1_000_000.0:.1f}M".rstrip("0").rstrip(".")
    return f"{x / 1_000_000_000.0:.1f}B".rstrip("0").rstrip(".")


def _format_position_token_amount_display(v: float | None, *, zero_if_missing: bool = False) -> str:
    """Compact rounded display for In position / Unclaimed fees (e.g. 1K, 2.5M)."""
    if v is None:
        return "0" if zero_if_missing else "-"
    try:
        x = float(v)
    except (TypeError, ValueError, OverflowError):
        return "0" if zero_if_missing else "-"
    if x != x or abs(x) == float("inf"):
        return "0" if zero_if_missing else "-"
    av = abs(x)
    if av >= 1_000_000_000_000:
        s = f"{x / 1_000_000_000_000.0:.1f}T"
    elif av >= 1_000_000_000:
        s = f"{x / 1_000_000_000.0:.1f}B"
    elif av >= 1_000_000:
        s = f"{x / 1_000_000.0:.1f}M"
    elif av >= 1_000:
        s = f"{x / 1_000.0:.1f}K"
    elif av >= 1:
        xr = round(x, 2)
        s = f"{xr:,.2f}"
    elif av >= 0.01:
        xr = round(x, 2)
        s = f"{xr:,.2f}"
    elif av >= 0.0001:
        xr = round(x, 4)
        s = f"{xr:,.4f}"
    else:
        xr = round(x, 6)
        s = f"{xr:.6f}"
    out = s.rstrip("0").rstrip(".")
    return out if out else "0"


def _build_row_updates_from_snapshot(
    row: dict[str, Any],
    snap: dict[str, Any],
    chain_id: int,
    *,
    include_liquidity: bool = True,
) -> dict[str, Any]:
    dec0 = _parse_int_like(snap.get("token0_decimals") or 18)
    dec1 = _parse_int_like(snap.get("token1_decimals") or 18)
    if dec0 <= 0 or dec0 > 36:
        dec0 = 18
    if dec1 <= 0 or dec1 > 36:
        dec1 = 18
    amount0 = snap.get("quote_amount0")
    amount1 = snap.get("quote_amount1")
    fee0 = snap.get("quote_fee0")
    fee1 = snap.get("quote_fee1")
    try:
        if fee0 is None:
            fee0 = float(Decimal(int(snap.get("tokens_owed0_raw") or 0)) / (Decimal(10) ** dec0))
        if fee1 is None:
            fee1 = float(Decimal(int(snap.get("tokens_owed1_raw") or 0)) / (Decimal(10) ** dec1))
    except Exception:
        pass

    liq_raw = max(0, int(snap.get("liquidity") or 0))
    proto_snap = str(snap.get("protocol") or "").strip().lower()
    is_v4_snap = proto_snap == "uniswap_v4"
    a0_now = max(0.0, float(amount0 or 0.0))
    a1_now = max(0.0, float(amount1 or 0.0))
    if is_v4_snap and liq_raw > 0:
        # v4: нет v3-quoter для amount0/1 в снимке — позиция с ненулевой on-chain liquidity всё равно «active».
        status = "active"
    else:
        status = "inactive" if (a0_now <= 0.0 or a1_now <= 0.0) else "active"
    token0_addr = str(snap.get("token0") or row.get("token0_id") or "").strip().lower()
    token1_addr = str(snap.get("token1") or row.get("token1_id") or "").strip().lower()
    fee_raw = str(snap.get("fee") or "").strip()
    fee_disp = fee_raw
    try:
        fee_int = int(fee_raw)
        if fee_int > 0:
            fee_disp = f"{fee_int / 10000.0:.2f}%"
    except Exception:
        fee_disp = fee_raw or "-"
    out = {
        "position_amount0": (float(amount0) if amount0 is not None else 0.0),
        "position_amount1": (float(amount1) if amount1 is not None else 0.0),
        "fees_owed0": (float(fee0) if fee0 is not None else 0.0),
        "fees_owed1": (float(fee1) if fee1 is not None else 0.0),
        "fee_tier_raw": fee_raw,
        "fee_tier": fee_disp,
        "position_amounts_display": f"{_format_position_token_amount_display(amount0)} / {_format_position_token_amount_display(amount1)}",
        "fees_owed_display": f"{_format_position_token_amount_display(fee0, zero_if_missing=True)} / {_format_position_token_amount_display(fee1, zero_if_missing=True)}",
        "position_status": status,
        "pool_token0_price": _safe_float(snap.get("token0Price") or row.get("pool_token0_price")),
        "token0_id": token0_addr,
        "token1_id": token1_addr,
        "position_symbol0": _normalize_display_symbol(str(snap.get("token0_symbol") or row.get("position_symbol0") or "")),
        "position_symbol1": _normalize_display_symbol(str(snap.get("token1_symbol") or row.get("position_symbol1") or "")),
        "pair": (
            f"{_normalize_display_symbol(str(snap.get('token0_symbol') or row.get('position_symbol0') or '?'))}/"
            f"{_normalize_display_symbol(str(snap.get('token1_symbol') or row.get('position_symbol1') or '?'))}"
        ),
        "pair_symbol_source0": "snapshot_symbol",
        "pair_symbol_source1": "snapshot_symbol",
        "pair_symbol_source": "0:snapshot_symbol | 1:snapshot_symbol",
        "suspected_spam": False,
        "spam_skipped": False,
    }
    pool_id_snap = str(snap.get("pool_id") or "").strip().lower()
    if _is_eth_address(pool_id_snap):
        out["pool_id"] = str(pool_id_snap)
    if include_liquidity:
        out["liquidity"] = str(liq_raw)
    return out


INTENT_OPTIONS: list[tuple[str, str]] = [
    ("/", "Find the best fee on Uniswap"),
    ("/pancake", "Find the best pool on PancakeSwap"),
    ("/stables", "Find the best lending positions"),
    ("/positions", "Optimize my pool positions"),
    ("/riko", "Get a stable income like US Treasury bonds"),
    ("/help", "Send wishes or report issues"),
]


def _intent_label_for_path(path: str) -> str:
    for p, label in INTENT_OPTIONS:
        if p == path:
            return label
    return "Find the best fee on Uniswap"


def _intent_options_html(selected_path: str) -> str:
    rows: list[str] = []
    for path, label in INTENT_OPTIONS:
        sel = " selected" if path == selected_path else ""
        rows.append(f'<option value="{path}"{sel}>{label}</option>')
    return "\n".join(rows)


def _render_placeholder_page(
    page_title: str,
    subtitle: str,
    selected_path: str,
    *,
    extra_css: str = "",
    extra_html: str = "",
    extra_script: str = "",
    show_intro: bool = True,
) -> str:
    options_html = _intent_options_html(selected_path)
    selected_label = _intent_label_for_path(selected_path)
    wallet_js = _wallet_ui_bundle_js(
        connect_missing_handler_js='alert("WalletConnect is not configured on server (WALLETCONNECT_PROJECT_ID)."); return;',
        connect_success_handler_js="maybeRedirectAfterAuth();",
        connect_error_handler_js='alert("WalletConnect failed: " + (e?.message || "unknown error") + ". If Reown allowlist is enabled, add origin: " + window.location.origin);',
        auth_unavailable_handler_js="return;",
        auth_success_handler_js="maybeRedirectAfterAuth();",
        auth_error_handler_js='console.warn("wallet auth failed", e);',
    )
    intro_html = (
        f"""
    <section class="card">
      <h2>{page_title}</h2>
      <p class="hint">{subtitle}</p>
    </section>
"""
        if show_intro
        else ""
    )
    return f"""<!doctype html>
<html>
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <title>Uni Fee - {page_title}</title>
  <style>
    * {{ box-sizing: border-box; }}
    html {{
      overflow-y: scroll;
      scrollbar-gutter: stable;
      overflow-x: hidden;
    }}
    body {{
      margin: 0;
      font-family: Inter, Arial, sans-serif;
      background: linear-gradient(180deg, #d9e3f5 0%, #ecf2ff 100%);
      color: #0f172a;
      min-height: 100vh;
      overflow-x: hidden;
    }}
    .container {{
      max-width: 1200px;
      margin: 0 auto;
      padding: 18px;
      min-height: calc(100vh - 36px);
      width: 100%;
      min-width: 0;
      overflow-x: clip;
    }}
    .header {{
      display: flex;
      justify-content: space-between;
      align-items: center;
      gap: 12px;
      margin-bottom: 14px;
      min-width: 0;
    }}
    .title {{
      margin: 0;
      font-size: 30px;
      font-weight: 800;
      letter-spacing: 0.2px;
    }}
    .subtitle {{
      margin: 4px 0 0;
      color: #64748b;
      font-size: 14px;
    }}
    .top-controls {{
      display: flex;
      gap: 10px;
      align-items: center;
      justify-content: flex-end;
      flex-wrap: nowrap;
    }}
    .intent-prefix {{
      font-size: 14px;
      font-weight: 700;
      color: #1d4ed8;
      white-space: nowrap;
    }}
    .intent-select {{
      border: 1px solid #bfdbfe;
      border-radius: 10px;
      padding: 10px 38px 10px 12px;
      font-size: 14px;
      font-weight: 600;
      color: #1f3a8a;
      background: linear-gradient(180deg, #f8fbff 0%, #eff6ff 100%);
      min-width: 320px;
      max-width: 360px;
      appearance: none;
      -webkit-appearance: none;
      background-image:
        linear-gradient(45deg, transparent 50%, #1d4ed8 50%),
        linear-gradient(135deg, #1d4ed8 50%, transparent 50%);
      background-position:
        calc(100% - 18px) calc(50% + 1px),
        calc(100% - 12px) calc(50% + 1px);
      background-size: 6px 6px, 6px 6px;
      background-repeat: no-repeat;
      box-shadow: inset 0 1px 0 rgba(255,255,255,0.7);
    }}
    .intent-select option {{
      background: #eef4ff;
      color: #1f3a8a;
    }}
    .connect-btn {{
      border: 1px solid #bfdbfe;
      border-radius: 10px;
      padding: 10px 16px;
      font-size: 14px;
      font-weight: 700;
      color: #1d4ed8;
      background: #eff6ff;
      cursor: pointer;
      white-space: nowrap;
      width: 190px;
      box-sizing: border-box;
      overflow: hidden;
      text-overflow: ellipsis;
    }}
    .wallet-modal-backdrop {{
      position: fixed;
      inset: 0;
      background: linear-gradient(180deg, rgba(217, 227, 245, 0.82) 0%, rgba(236, 242, 255, 0.82) 100%);
      backdrop-filter: blur(3px);
      display: none;
      align-items: center;
      justify-content: center;
      z-index: 9999;
    }}
    .wallet-modal {{
      width: min(460px, calc(100vw - 24px));
      background: #f8fbff;
      border: 1px solid #cbd5e1;
      border-radius: 14px;
      box-shadow: 0 12px 36px rgba(15, 23, 42, 0.25);
      padding: 14px;
    }}
    .wallet-modal h3 {{
      margin: 0 0 8px;
      font-size: 18px;
    }}
    .wallet-list {{
      display: grid;
      grid-template-columns: 1fr;
      gap: 8px;
      margin-top: 10px;
    }}
    .wallet-item {{
      border: 1px solid #bfdbfe;
      border-radius: 10px;
      padding: 10px 12px;
      background: #eff6ff;
      color: #1d4ed8;
      font-weight: 700;
      text-align: left;
      cursor: pointer;
    }}
    .wallet-item.disabled {{
      opacity: 0.6;
      cursor: not-allowed;
    }}
    .wallet-note {{
      color: #64748b;
      font-size: 12px;
      margin-top: 8px;
    }}
    .card {{
      background: #f3f7ff;
      border: 1px solid #cfdcec;
      border-radius: 14px;
      padding: 18px;
      box-shadow: 0 6px 20px rgba(15, 23, 42, 0.06);
    }}
    .card h2 {{
      margin: 0 0 8px;
      font-size: 22px;
    }}
    .hint {{
      color: #475569;
      margin: 0;
    }}
    .app-footer {{
      margin-top: 20px;
      padding-top: 14px;
      border-top: 1px solid #dbe3ef;
      text-align: center;
      font-size: 12px;
      color: #64748b;
      letter-spacing: 0.02em;
    }}
    .js-runtime-banner {{
      display: none;
      margin: 10px 0 14px;
      padding: 10px 12px;
      border-radius: 10px;
      border: 1px solid #fecaca;
      background: #fef2f2;
      color: #991b1b;
      font-size: 13px;
      white-space: normal;
    }}
    {extra_css}
  </style>
</head>
<body>
  <div class="container">
    <div class="header">
      <div>
        <h1 class="title">DeFi Pools</h1>
        <p class="subtitle">{selected_label}</p>
      </div>
      <div class="top-controls">
        <span class="intent-prefix">I want to</span>
        <select class="intent-select" id="intentSelect" onchange="navigateIntent(this.value)">
          {options_html}
        </select>
        <button class="connect-btn" id="connectWalletBtn" onclick="onConnectWalletClick()">Connect wallet</button>
      </div>
    </div>
    <div id="jsRuntimeBanner" class="js-runtime-banner"></div>
    {intro_html}
    {extra_html}
    <footer class="app-footer">Uni Fee v{APP_VERSION}</footer>
  </div>
  <div id="walletModalBackdrop" class="wallet-modal-backdrop" onclick="closeWalletModal(event)">
    <div class="wallet-modal">
      <h3>Connect wallet</h3>
      <div class="wallet-list" id="walletList"></div>
      <div class="wallet-note">Rabby and Phantom are supported. Sign-in uses a gasless message signature.</div>
    </div>
  </div>
  <script>
    (function () {{
      let shown = false;
      function showJsBanner(msg) {{
        if (shown) return;
        const el = document.getElementById("jsRuntimeBanner");
        if (!el) return;
        const detail = String(msg || "Unknown frontend error");
        el.style.display = "block";
        el.textContent = "Frontend script failed to initialize. Check recent JS changes. Details: " + detail;
        shown = true;
      }}
      window.addEventListener("error", function (ev) {{
        // Ignore generic cross-origin/extension noise like "Script error." with no filename.
        if (ev && ev.target && ev.target !== window) return;
        const m = (ev && (ev.message || (ev.error && ev.error.message))) || "window error";
        const file = String((ev && ev.filename) || "");
        if (m === "Script error." && !file) return;
        showJsBanner(m);
      }});
      window.addEventListener("unhandledrejection", function (ev) {{
        const r = ev ? ev.reason : "";
        const m = (r && (r.message || String(r))) || "unhandled promise rejection";
        if (m === "unhandled promise rejection") return;
        showJsBanner(m);
      }});
    }})();
  </script>
  <script>
    let authState = {{authenticated: false}};
    const WALLETCONNECT_PROJECT_ID = "__WALLETCONNECT_PROJECT_ID__";
    const WALLET_LABELS = {{
      injected: "Browser Wallet",
      walletconnect: "WalletConnect (QR)",
      rabby: "Rabby",
      metamask: "MetaMask",
      phantom: "Phantom",
      coinbase: "Coinbase Wallet",
    }};

    function navigateIntent(path) {{
      if (!path) return;
      window.location.href = path;
    }}
    function refreshIntentMenu() {{
      const sel = document.getElementById("intentSelect");
      if (!sel) return;
      sel.style.position = "absolute";
      sel.style.left = "-9999px";
      sel.style.opacity = "0";
      sel.style.pointerEvents = "none";
      let wrap = document.getElementById("intentMenuWrap");
      if (!wrap) {{
        wrap = document.createElement("div");
        wrap.id = "intentMenuWrap";
        wrap.style.cssText = "position:relative;min-width:320px;max-width:360px;";
        const btn = document.createElement("button");
        btn.type = "button";
        btn.id = "intentMenuBtn";
        btn.style.cssText = "width:100%;border:1px solid #bfdbfe;border-radius:10px;padding:10px 38px 10px 12px;font-size:14px;font-weight:600;color:#1f3a8a;background:linear-gradient(180deg,#f8fbff 0%,#eff6ff 100%);text-align:left;cursor:pointer;box-shadow:inset 0 1px 0 rgba(255,255,255,0.7);";
        const list = document.createElement("div");
        list.id = "intentMenuList";
        list.style.cssText = "display:none;position:absolute;z-index:12000;left:0;right:0;top:calc(100% + 6px);background:#eef4ff;border:1px solid #bfdbfe;border-radius:10px;box-shadow:0 10px 24px rgba(15,23,42,0.15);padding:6px;max-height:320px;overflow:auto;";
        wrap.appendChild(btn);
        wrap.appendChild(list);
        sel.insertAdjacentElement("afterend", wrap);
        btn.onclick = () => {{
          list.style.display = list.style.display === "block" ? "none" : "block";
        }};
        document.addEventListener("click", (e) => {{
          if (!wrap.contains(e.target)) list.style.display = "none";
        }});
      }}
      const btn = document.getElementById("intentMenuBtn");
      const list = document.getElementById("intentMenuList");
      const options = Array.from(sel.options || []);
      const selected = options.find((o) => o.selected) || options[0];
      btn.textContent = selected ? selected.textContent : "Select";
      list.innerHTML = options.map((o) => {{
        const active = o.value === sel.value;
        const style = active
          ? "display:block;width:100%;padding:9px 10px;border:none;background:#dbeafe;color:#1e3a8a;font-weight:700;text-align:left;border-radius:8px;margin-bottom:4px;cursor:pointer;white-space:nowrap;"
          : "display:block;width:100%;padding:9px 10px;border:none;background:#eef4ff;color:#1f3a8a;font-weight:600;text-align:left;border-radius:8px;margin-bottom:4px;cursor:pointer;white-space:nowrap;";
        return `<button type="button" data-v="${{o.value}}" style="${{style}}">${{o.textContent}}</button>`;
      }}).join("");
      Array.from(list.querySelectorAll("button[data-v]")).forEach((b) => {{
        b.onclick = () => {{
          const v = b.getAttribute("data-v") || "";
          sel.value = v;
          list.style.display = "none";
          navigateIntent(v);
        }};
      }});
    }}

    {wallet_js["modal"]}

    async function postJson(url, payload) {{
      const r = await fetch(url, {{
        method: "POST",
        headers: {{"Content-Type": "application/json"}},
        body: JSON.stringify(payload || {{}})
      }});
      const data = await r.json().catch(() => ({{}}));
      if (!r.ok) {{
        throw new Error(data.detail || data.info || "Request failed");
      }}
      return data;
    }}

    function syncAdminIntentOption() {{
      const sel = document.getElementById("intentSelect");
      if (!sel) return;
      const existing = Array.from(sel.options).find((o) => o.value === "/admin");
      const isAdmin = !!authState?.authenticated && !!authState?.is_admin;
      if (isAdmin && !existing) {{
        const opt = document.createElement("option");
        opt.value = "/admin";
        opt.textContent = "Administer project";
        sel.appendChild(opt);
      }} else if (!isAdmin && existing) {{
        existing.remove();
      }}
      refreshIntentMenu();
    }}

    function setAuthUI() {{
      const btn = document.getElementById("connectWalletBtn");
      if (!btn) return;
      if (authState?.authenticated) {{
        btn.textContent = authState.address_short || "Wallet connected";
      }} else {{
        btn.textContent = "Connect Wallet";
      }}
      syncAdminIntentOption();
    }}

    async function loadAuthState() {{
      try {{
        const r = await fetch("/api/auth/me");
        authState = await r.json();
      }} catch (_) {{
        authState = {{authenticated: false}};
      }}
      setAuthUI();
      maybeRedirectAfterAuth();
    }}

    function getPostAuthRedirectPath() {{
      try {{
        const params = new URLSearchParams(window.location.search || "");
        const nextPath = String(params.get("next") || "").trim();
        if (!nextPath || !nextPath.startsWith("/") || nextPath.startsWith("//")) return "";
        return nextPath;
      }} catch (_) {{
        return "";
      }}
    }}

    function maybeRedirectAfterAuth() {{
      if (!authState?.authenticated) return;
      if (window.location.pathname !== "/connect") return;
      const nextPath = getPostAuthRedirectPath();
      if (!nextPath) return;
      window.location.assign(nextPath);
    }}

    async function onConnectWalletClick() {{
      if (authState?.authenticated) {{
        if (!confirm("Disconnect wallet?")) return;
        try {{
          await postJson("/api/auth/logout", {{}});
          authState = {{authenticated: false}};
          setAuthUI();
        }} catch (e) {{
          console.warn("disconnect failed", e);
        }}
        openWalletModal();
        return;
      }}
      openWalletModal();
    }}

    {wallet_js["wallet_auth"]}

    {wallet_js["walletconnect"]}

    {extra_script}
    loadAuthState();
    refreshIntentMenu();
  </script>
</body>
</html>
"""


