        lastFeePricing,
        hasCollectedHistoryTrace,
        hasEstimatedShareTrace,
        hasSnapshotOnlyTrace,
        rowsWithCollected,
        rowsWithEstimated,
        rowsWithSnapshot,
        rowsWithAnySeries,
        collectedPointsTotal,
        estimatedPointsTotal,
        snapshotPointsTotal,
